INSERT INTO `so06_kiet_hung_nam_gio` VALUES (1,'Coi con nít dễ nuôi hay không ?',1,10,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(2,'Coi con nít dễ nuôi hay không ?',11,2,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(3,'Coi con nít dễ nuôi hay không ?',11,3,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(4,'Coi con nít dễ nuôi hay không ?',11,8,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(5,'Coi con nít dễ nuôi hay không ?',11,9,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(6,'Coi con nít dễ nuôi hay không ?',11,6,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(7,'Coi con nít dễ nuôi hay không ?',11,4,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.'),(8,'Coi con nít dễ nuôi hay không ?',12,5,'Nếu sanh nhằm năm này, thì bị quỷ bắt khó nuôi, phải kiếm thầy pháp giải ếm thì mới nuôi được, lớn lên bình thường.');
