LOCK TABLES `so06_moi_sanh_mang_gi` WRITE;
/*!40000 ALTER TABLE `so06_moi_sanh_mang_gi` DISABLE KEYS */;
INSERT INTO `so06_moi_sanh_mang_gi` VALUES (1,1,'Mạng Kim dễ nuôi, nhưng mà nó ít nhống nhẽo, rồi nhàm khi nó khóc thì khó dỗ lắm.'),(2,2,'Mạng Mộc dễ nuôi, lớn có Lộc Trời cho ăn mặc nhiểu, không chết yểu, mạng đặng sống lâu, dễ làm ăn.'),(3,3,'Mạng Thủy sanh ra cái mặt nó buồn lắm, nó hay khác dạ để trong lúc ban đêm, từ 8 ngày sắp lên đến 21 ngày, thì khỏi sự khóc, phải có thẩy yếm mới đặng, rồi phải cho bà con nuôi hay người quen nuôi. Cha mẹ đừng nhìn đến nó, dến 3 tuổi phải chuộc về nuôi mới đặng. Nếu để cha mẹ nuôi thì cái mạng nó 10 kể 2 mà thôi, khi nó lớn có tínhh hay buồn trong lúc êm tịnh lắm.'),(4,4,'Mạng Hỏa hay khóc dạ đêm, sanh ra chừng 8 ngày hoặc 21 ngày thì nó khởi sự khóc nhiểu lắm. Vậy phải kiểm thẩy pháp giỏi ếm nó, rồi phải cho nó làm con nuôi người ta 3 năm mới đặng, sau sẽ chuộc về nuôi mới đặng mạnh giỏi'),(5,5,'Mạng Thổ, hay khóc dạ đêm, sanh ra chừng 8 ngày hoặc 21 ngày thì nó khởi sự khóc nhiều lắm, vậy phải kiếm thẩy pháp giỏi ếm nó mới thôi khóc, rồi mới đễ nuôi.');
/*!40000 ALTER TABLE `so06_moi_sanh_mang_gi` ENABLE KEYS */;
UNLOCK TABLES;

