INSERT INTO `so07_hon_dau_thai` VALUES (1,1,'Nam',1,1,'Số này vợ chồng thay đổi 2, 3 đời. Đứa con đầu khó nuôi. Số có phần tu niệm thì tốt và có số làm giàu'),(2,1,'Nam',2,2,'Số này vợ chồng thay đổi nhiều đời, hào con cũng lôi thôi, số lưu lạc, đến lúc lớn tuổi, bề vợ chồng mới an.'),(3,1,'Nam',3,3,'Số này lớn tuổi hay có tai nạn lắm, lúc tuổi trẻ có gian nan nhiều, đến lớn đặng qua, có tu thì đặng ba đứa con, bằng không có tu có một đứa mà thôi.'),(4,1,'Nam',4,4,'Số này lớn phải cầu khẩn Trời Đất mới có con đặng một đứa và có Thần Phù Hộ, đến già thì đặng thong thả cảnh muộn.'),(5,1,'Nam',5,5,'Số này lớn tuổi làm ăn khá lắm, nhà cửa sự nghiệp kinh vinh, vợ chồng thuở trẻ hay trắc trở, tuổi lớn mới đặng nên đôi.'),(6,1,'Nam',6,6,'Số này gặp quí sứ bắt, cho nên đứa nhỏ nằm ngủ hay giật mình, hay khóc, phải kiếm thầy pháp giỏi ếm nó mới hết, rồi cho người ta làm con nuôi đỡ một thời gian, có như vậy nuôi mới đặng.'),(7,1,'Nam',7,7,'Số này hồn ở cõi trên, Phật cho xuống đầu thai tánh hay cúng kiến. Lớn tuổi làm ăn khá lắm, ý vui vẻ, cha mẹ được sống lâu.'),(8,1,'Nam',8,8,'Số này lớn tuổi tánh hay muốn ở núi non, mạng lý đặng an không có hại, có 3 đứa con, có hưởng phước. Ông bà cha mẹ dễ làm ăn.'),(9,1,'Nam',9,9,'Số này mới sanh hay giật mình, phải cho người ta làm con nuôi mới đặng mạnh giỏi: người mẹ năm sau còn sanh một đứa nữa.'),(10,1,'Nam',10,10,'Số này con trai khó nuôi, con gái dễ nuôi, số này phải chịu làm con nuôi người ta mới đặng mạnh giỏi, khi đến lớn mới dễ làm ăn.'),(11,1,'Nam',11,11,'Số này khi mẹ có thai thì hay đau ốm, và hay có hoạn nạn thường, sanh nó ra dễ nuôi, nếu mẹ mạnh giỏi thì sanh nó ra hay đau ốm và nhõng nhẽo lắm.'),(12,1,'Nam',12,12,'Số này cũng nuôi đặng đến lớn, nhưng mà lúc đang nuôi thuở nhỏ trụ trặc lắm, cha mẹ nên cần mẫn nuôi dưỡng mới đặng.'),(13,2,'Nam',1,7,'Số này hồn ở cõi trên, Phật cho xuống đầu thai tánh hay cúng kiến. Lớn tuổi làm ăn khá lắm, ý vui vẻ, cha mẹ được sống lâu.'),(14,2,'Nam',2,8,'Số này lớn tuổi tánh hay muốn 