LOCK TABLES `so08_36giosanh` WRITE;
/*!40000 ALTER TABLE `so08_36giosanh` DISABLE KEYS */;
INSERT INTO `so08_36giosanh` VALUES (1,'Giữa','Cha mẹ song toàn, làm người vui vẻ, ăn mặc không thiếu, anh em đều có phận, sanh con đặng nhiều, đi khác xứ làm ăn khá, số có quyền chức.'),(1,'Sau','Khăc cha: tính rộng rãi, anh em không khá, sanh con khó dạy, thuở nhỏ cực khổ,làm việc gì có đầu không đuôi. Số theo quê vợ, xa cha mẹ.'),(1,'Đầu','Khắc mẹ: Làm người tính lẹ làng, vợ chổng khắc đời thứ nhất, khắc con đầu lòng, anh em không hòa, tuổi nhỏ làm ăn không khá, tuổi lớn về sau làm ăn khá.'),(2,'Giữa','Khắc cha : Việc ăn mặc trung bình, tính ý công bình, đến 36 tuổi phát tài, anh em không hòa bà con bản lãng, đi xứ khác, hai bàn tay trắng làm đặng nên sự nghiệp.'),(2,'Sau','Khắc mẹ : tuổi nhỏ chịu tàm khổ, làm việc lớn ra nhỏ, không nhờ anh em, hào con phát đạt khá, đến 40 tuổi làm ăn thịnh vượng, lớn tuổi khá thêm, tay có nghề nghiệp làm ăn.'),(2,'Đầu','Cha me song toàn, tuổi nhỏ làm ăn trung bình, 20 tuổi sắp lên làm ăn phát đạt, tính thônng minh, gẫn người sang trọng, có chức phận, anh em khá, hào con tốt'),(3,'Giữa','Cha mẹ đặng song toàn, tính người siêng năng, ăn mặc không thiếu, anh em khá, có con 2,3 đứa tính tốt,văn chương giỏi sự nghiệp nên.'),(3,'Sau','Khắc mẹ: không nhờ anh em, con đầu lòng khó nuôi, tuổi nhỏ phiêu lưu cực khổ. Đến 36 tuổi phát tài, làmăn kha, làm việc gì hay tính tới tính lui, thường có đau ốm, tật bệnh.'),(3,'Đầu','Khắc cha : Số gần người sang trọng, việc hung hóa hiển, tuổi nhỏ cực khổ, 37 tuổi sắp lên làm ăn khá, cốt nhục bảng lãng, có nhờ con nuôi lúc tuổi gìa.'),(4,'Giữa','Cha me song toàn, trai sang gái trọng, quý nhân yêu chuộng, gái ít chồng anh em khá, con nhiều ăn mặc không thiếu, sự nghiệp kinh vinh, cốt nhục hòa, có chức phận.'),(4,'Sau','Khắc cha : thuở nhỏ bôn ba, lao khổ, không nhờ anh em, đến 36 tuổi sắp lên dễ làm ăn, chừng ấy mới ít đi, lập sự nghiệp đặng vững bền.'),(4,'Đầu','Khắc mẹ : Làm việc gì trước có sau không, không nhờ anh em, tuổt nhỏ bôn ba, lặn lội, cực trí, số khắc con, con không chừng, việc ăn mặc tùy thời có, thời không'),(5,'Giữa','Khắc cha: Làm người có tính công bằng, lẹ làng, quý nhân hay giúp đỡ, ở xa xứ lập nên sự nghiệp, tuối trẻ khó nên. 44 tuổi làm ăn phát đạt,anh em không hợp ý'),(5,'Sau','Khắc mẹ: Có tính thông minh, làm ăn thịnh vượng, hào con tốt, anh em làm ăn khá số có chức phận, có phước lộc, hưởng đầy đủ, có danh tiếng, sang trọng, mội đời đặng thẳnh thơi.'),(5,'Đầu','Cha me song toàn, tính ý mau lę, anh em khá, con đầu lòng nuôi không đặng, cốt nhục bất hòa, tính hiển từ, tay có nghể nghiệp làm ăn, thuở nhỏ bình thường, đến 12 tuổi phát tài.'),(6,'Giữa','Cha mẹ song toàn, gần người sang trọng, ăn mặc đầy đủ, anh em làm đặng nên, hào con đặng giàu, có công danh, tính hạnh khẳng khái, làm ăn khá, đi khác xứ lập nên.'),(6,'Sau','Khắc cha: Số gần người sang trọng, làm ăn khi thành khi bại không chừng, tính anh em lạt lẽo, khó nuôi con,vợ chổng lôi thôi, tuổi nhỏ số lưu lạc cực khổ, lớn tuổi làm ăn phát đạt.'),(6,'Đầu','Khắc mẹ: Có lộc ăn mặc, anh em không đặng nhờ,con đầu lòng khó nuôi khắc bào chống vợ,tuổi nhỏ bôn ba đi nhiều xứ, đến lớn làm ăn phát đạt,có chức phận, có sự nghiệp'),(7,'Giữa','Khắc cha: ăn mặc bình thường,tuổi trẻ bôn ba,khổ trái nhiều phen,30 tuổi sắp lên làm ăn khá, không nhờ anh em, làm ăn khi nên, khi hư không chừng,không có tự do.'),(7,'Sau','Khắc mẹ: tính người lẹ làng, không nhờ anh em, con đầu lòng khó nuôi, tính thông minh, lanh lợi, tuổi nhủ cực khổ, đến lớn tuổi làm ăn phát đạt, đến cảnh già cũng trở lại cực khổ'),(7,'Đầu','Cha me song toàn, làm người tính tình lợi hại, gần người sang, anh em hòa, hai ba dòng con, ăn mặc không thiếu, số có chức phận, quyển hành, vận số hưng vượng'),(8,'Giữa','Khắc cha: tính ý rộng rãi, có quý nhân thương, đặng nhờ anh em,thuở nhỏ làm ăn bình thường, lo lường lặn lội cực trí, vợ chồng khắc đời thứ nhất, khắc con, lớn tuổi làm ăn khá.'),(8,'Sau','Khắc mẹ: quý nhân hay yêu chuộng, ăn mặc bình thường, tuổi nhỏ làm ăn khi hư khi nên, tuổi trẻ cực khổ, anh em không hoà, sanh con cứng cỏi lớn tuổi làm ăn khá hơn thời tuổi trẻ.'),(8,'Đầu','Cha mę song toàn, số đặng gần người sang trọng, trọn đời yên vui, anh em hòa hợp ý,số có chức phận gái thì có quyển đặng sang trọng đễ làm ăn, sự nghiệp kinh vinh.'),(9,'Giữa','Khắc cha :bà con không hoà, anh em không nhờ, bôn ba cực khổ, có vợ chồng sớm, ở đời không đặng, có vợ muộn tốt, làm ăn xa xứ khá, lập tại xứ cha mẹ sanh không khá.'),(9,'Sau','Khắc mẹ nhân tình cốt nhục lạt lẽo,thuở nhỏ cực khổ,hình vóc ốm yếu, hào con lôi thôi, đến 30 tuổi vận thời mới bình, đến 40 tuổi làm ăn mới phát đạt.'),(9,'Đầu','Cha mę song toàn, tính thông minh gần người quý thể, nghề văn,nghiệp võ đều thông, bà con có quyển tước, anh em làm ăn khá hào con, dễ làm ăn, số có ruộng đất,dễ lập gia đình'),(10,'Giữa','Khắc cha: tính rộng rãi, anh em bất hoà, con đầu lòng khó nuôi, thuở nhỏ làm ăn không hợp thời, trai khắc vợ, gái khắc chồng, đi khác xứ,không ở chỗ cũ'),(10,'Sau','Khắc mẹ : Việc ăn mặc bình thường, không nhờ anh em, thuở nhỏ khổ tâm, đến 37 tuổi trở lên thì phát tài, vợ chồng khắc nhau, trai thì chậm trễ, gái thì dâm loạn, thất hào con.'),(10,'Đầu','Cha mę song toàn, đời sang trọng, văn võ đều thông, anh em phân cách, hào con ít,tài lợi khá,nhà cửa tốt, có quyển tước, tâm tính tốt.'),(11,'Giữa','Khắc cha : Anh em thân tộc khó nhờ, vợ chồng không hòa, con đầu lòng khó nuôi, tuổi nhỏ không đậu tài, đến 42 tuổi làm ăn phát đạt cảnh muộn khá thêm, ăn nói không chừng'),(11,'Sau','Cha mẹ song toàn, tính mau le,văn võ đều thông, bà con anh em đều khá có nghể học đặng tinh xảo, vợ chồng bền lâu, số ở xa xứ mới đặng.'),(11,'Đầu','Khắc mẹ : tính mau lẹ, lòng hiền lành, không nhờ anh em, làm việc gì đều có quyền, tuổi nhỏ bình thường, cực khổ, đến 37 tuổi sắp lên làm ăn phát đạt, người quý nhân giúp đỡ.'),(12,'Giữa','Cha me song toàn, tính thông minh, mau lẹ thân tộc anh em hòa thuận, sanh con có quyền tước, lớn tuổi sự nghiệp đặng nên, có mưu kể và công bằng'),(12,'Sau','Khắc của : tính nóng mà có ý hiền, bà con anh em không hạp ý, tuổi nhỏ cực khổ, trai thì hai đời vợ gái ba đời chồng lớn tuổi khá hơn nhỏ, việc làm ăn rất nhọc ý'),(12,'Đầu','Khắc mẹ : tính lẹ làng, rộng rãi ,bà con anh em lưu lạc xa nhau,con hai ba đứa, làm ăn thủ thường đến lớn tuổi làm ăn khá, sắp đặt gia đình đặng an');
/*!40000 ALTER TABLE `so08_36giosanh` ENABLE KEYS */;
UNLOCK TABLES;

