INSERT INTO `so09_ngaysanh` VALUES (1,'Thái Dương Nhựt','Sanh nhằm ngày Thái Dương lòng sáng láng, phước lộc nhiều, có nghề nghiệp, bằng không có nghề nghiệp thì cha mẹ chết sớm.'),(2,'Thái Âm Nhựt','Sanh nhằm ngày Thái Âm đi xa xứ, có nhiều người kính trọng quí nhơn thương 36 tuổi sắp lên vận thời làm ăn phát đạt.'),(3,'Thiên Phụ Nhựt','Sanh nhằm ngày Thiên Phụ lớn tuổi của nhiều, cầm đặng, số đặng sống lâu phải tu niệm thì phải buồn rầu.'),(4,'Thiên Mẫu Nhựt','Sanh nhằm ngày Thiên Mẫu, đặng vinh hoa tốt, gặp đặng ngày làm giàu và sang trọng, của vô ra không chừng.'),(5,'Thiên Đế Nhựt','Sanh nhằm ngày Thiên Đế, hay chơi anh em bạn nhiều, tánh hạnh hiền từ và vui vẻ, gái thì khắc chồng.'),(6,'Thiên Hoàng Nhựt','Sanh nhằm ngày Thiên Hoàng, khắc cha mẹ, khắc vợ chồng, không ở chỗ cha mẹ sanh, đi tới xứ khác lập thân nên.'),(7,'Thái Dương Nhựt','Sanh nhằm ngày Thái Dương lòng sáng láng, phước lộc nhiều, có nghề nghiệp, bằng không có nghề nghiệp thì cha mẹ chết sớm.'),(8,'Thái Âm Nhựt','Sanh nhằm ngày Thái Âm đi xa xứ, có nhiều người kính trọng quí nhơn thương 36 tuổi sắp lên vận thời làm ăn phát đạt.'),(9,'Thiên Phụ Nhựt','Sanh nhằm ngày Thiên Phụ lớn tuổi của nhiều, cầm đặng, số đặng sống lâu phải tu niệm thì phải buồn rầu.'),(10,'Thiên Mẫu Nhựt','Sanh nhằm ngày Thiên Mẫu, đặng vinh hoa tốt, gặp đặng ngày làm giàu và sang trọng, của vô ra không chừng.'),(11,'Thiên Đế Nhựt','Sanh nhằm ngày Thiên Đế, hay chơi anh em bạn nhiều, tánh hạnh hiền từ và vui vẻ, gái thì khắc chồng.'),(12,'Thiên Hoàng Nhựt','Sanh nhằm ngày Thiên Hoàng, khắc cha mẹ, khắc vợ chồng, không ở chỗ cha mẹ sanh, đi tới xứ khác lập thân nên.'),(13,'Thái Dương Nhựt','Sanh nhằm ngày Thái Dương lòng sáng láng, phước lộc nhiều, có nghề nghiệp, bằng không có nghề nghiệp thì cha mẹ chết sớm.'),(14,'Thái Âm Nhựt','Sanh nhằm ngày Thái Âm đi xa xứ, có nhiều người kính trọng quí nhơn thương 36 tuổi sắp lên vận thời làm ăn phát đạt.'),(15,'Thiên Phụ Nhựt','Sanh nhằm ngày Thiên Phụ lớn tuổi của nhiều, cầm đặng, số 