INSERT INTO `so10_thothaisanh` VALUES (1,4,1,'Kiếp trước có tu hành và thường cứu giúp người, nên kiếp này được hưởng lộc thật đầy đủ, của cải tiền bạc nhiều, điền sản rộng lớn, có chức phận sang trọng, sống lâu, đi xa lập nghiệp cũng tốt. Trong người có tật kín, vợ chồng buổi đầu khó thành, con đầu lòng khó nuôi dưỡng.'),(2,5,2,'Kiếp trước hay bố thí và in kinh phát cho người tu hành. Kiếp này làm lành nên được sang trọng, có phần đi xa xứ lập nghiệp, sự nghiệp vững vàng. Điền sản tuy có nhưng tánh cứng mạnh, ít nhờ anh em, khó nuôi con, tính hay tiết kiệm và hay dạy bảo người khác.'),(3,6,3,'Kiếp trước có tánh ưa bài bạc, đó là nghiệp chướng chính. Kiếp này hay nói lời phán xét, ban phúc cho người khác một cách bừa bãi. Làm việc gì ban đầu thấy hay sau lại hư hỏng, khó thành con của cha mẹ mình, làm việc trước có sau không. Ăn mặc chật hẹp thiếu thốn, tâm tánh thông minh nhưng phải đến già mới khá lên.'),(4,7,4,'Kiếp trước thông minh khôn khéo lắm. Kiếp này như được sinh ra vào mùa Xuân hoặc mùa Hạ nên dễ phát tài, làm ăn thịnh vượng, sự nghiệp dễ thành. Có điền sản khá, khắc cha mẹ, vợ chồng buổi đầu khó hòa hợp, con đầu lòng khó nuôi dưỡng.'),(5,8,5,'Kiếp trước có tánh kiêu ngạo, khinh thường người khác. Kiếp này hay say rượu, khắc cha mẹ, anh em, vợ con phải xa xứ vất vả. Sau khi lớn tuổi ăn mặc đủ đầy, làm ăn khá hơn. Nếu biết làm lành tích đức thì sẽ có điền sản khá.'),(6,9,6,'Kiếp trước có tánh can trường. Sau đó mới biết làm lành. Kiếp này khắc cha mẹ, anh em, vợ chồng và con cái. Trong người có tiểu tật. Nếu biết làm lành thì sẽ sống lâu, phát tài, có chức phận và minh mẫn.'),(7,10,7,'Kiếp trước hay bàn luận những điều lành, hay bố thí cho người nghèo bằng tiền gạo. Kiếp này đi đến đâu cũng được người ta kính trọng. Thuở trẻ làm ăn bình thường, lớn tuổi làm ăn phát đạt, có chức phận. Vợ chồng buổi đầu khó khăn, con đầu lòng khó nuôi. Có nghề lớn, nhưng hay bị đau lưng hoặc tật ở chân.'),(8,11,8,'Kiếp trước tu niệm lúc thì lành lúc thì ác, thiện nhiều hơn. Kiếp này phải trả quả lúc còn trẻ, thuở nhỏ chịu nhiều khổ cực, khắc ba đời chồng vợ, ít con, đi nhiều nơi, ít được nhờ anh em. Đến khoảng 36 tuổi mới bắt đầu phát đạt, lập nên sự nghiệp, có chức phận. Cha mẹ sống không lâu.'),(9,12,9,'Kiếp trước có tánh vui vẻ, trung tín, rộng rãi. Kiếp này được nhiều người yêu mến, ăn mặc đầy đủ. Anh em có người làm quan nhưng không ở gần nhau. Số đời phải ở nơi khác 3 lần, nếu không làm lành thì phải đến 5 lần mới được bình an. Khắc cha mẹ.'),(10,1,10,'Kiếp trước có tánh can đảm, tự cao, tự đại, không chịu phục người. Kiếp này phải chịu cảnh cô độc một mình, lưu lạc xa phương chịu nhiều khổ cực. Đến khoảng 50 tuổi mới lập nghiệp phát đạt, dung mạo khá tốt.'),(11,2,11,'Kiếp trước có tánh kiêu ngạo, khinh thường người khác. Kiếp này hay đau tim và đau ngũ tạng để trả quả. Khắc cha mẹ, anh em, khó nuôi con. Số này cần phải làm lành nhiều để giải oan. Nếu biết sửa đổi thì đến 44 tuổi làm ăn mới phát tài. Có điền sản và sự nghiệp, có chức phận, nên sớm sửa tánh cho tốt.'),(12,3,12,'Kiếp trước hay nói năng tiên Phật nhưng lòng còn độc ác. Kiếp này phải chịu ăn mặc thiếu thốn, hay đau mắt, nhiều khi phải sống một mình. Phải làm lành nhiều để trả quả xưa, giải oan khiên. Nếu làm lành có dư thì Trời Phật sẽ chuyển hóa, được tự lập sự nghiệp lúc về già. Nếu không ăn năn thì phải chịu khổ đến già.');
/*!40000 ALTER TABLE `so10_thothaisanh` ENABLE KEYS */;
UNLOCK TABLES;

