INSERT INTO `so12_cotcongi` VALUES (1,1,2,'Cốt con Trâu','Sinh năm cốt Trâu làm người tánh khéo trí sáng, thấy việc chi cũng mau hiểu, tánh ngay thẳng với người, số đi xa xứ có anh em bạn tử tế, nhưng việc làm có ích cho đời không đến ơn mà vẫn làm hoài.'),(2,1,3,'Cốt con Cọp','Sinh năm cốt Cọp không có phát đạt ở xứ cha mẹ sanh, đi xa xứ làm ăn khá, số đặng sang trọng, ăn mặc đầy đủ, luận mưu chi thì có đặng nấy, có quyền hành oai võ, ăn uống dễ, bất luận ngon dở.'),(3,1,4,'Cốt con Thỏ','Sinh năm cốt Thỏ, làm việc gì ban đầu khởi lớn, lúc sau như không có, như học nhiều biết ít, có số ở chỗ cha mẹ sanh đặng nên, lần lần đến khi lớn tuổi cũng đặng khá, ý vui vẻ mà có tánh nhát.'),(4,1,5,'Cốt con Rồng','Sinh năm cốt Rồng, người đặng sang trọng lại có oai quyền, tài lộc phát đạt, lại có danh tiếng, ở đặng yên, tánh hạnh vui vẻ, hình trạng tốt, hay giúp đời, có tánh công bình.'),(5,1,6,'Cốt con Rắn','Sinh năm cốt Rắn, tánh ưa chỗ yên tịnh, tay chân mau lẹ, tánh nóng nảy hung tợn, ít có bệnh hoạn, ít tai nạn, tánh vui vẻ, không muốn đi xa xứ.'),(6,1,7,'Cốt con Ngựa','Sinh năm cốt Ngựa, số người đặng sang trọng, ăn mặc đầy đủ, tánh hay đi xứ này sang xứ kia, tướng mạo tốt, mưu mô giỏi, tay chân mau lẹ.'),(7,1,8,'Cốt con Dê','Sinh năm cốt Dê, số người lớn tuổi đặng thong thả, ở chỗ cha mẹ sanh không đặng, số hai bàn tay trắng, mới lập nghiệp đặng thành, dầu ở tử tế bao nhiêu, lối xóm cũng hay nghét, ưa ăn trái cây nhiều hơn.'),(8,1,9,'Cốt con Khỉ','Sinh năm cốt Khỉ, người khó cầm của, ưa đi chơi, tay chân bộ tướng lẹ làng, có tánh thông minh ứng biến, nhưng không có tánh dè dặt, không chú ý.'),(9,1,10,'Cốt con Gà','Sinh năm cốt Gà, số người đặng sang trọng, đặng gần người quới nhân đi đâu thì có nha trạo bộ hạ nhiều theo hộ vệ, có danh tiếng nhiều, của có công mới hưởng không có công không an, tánh siêng năng mau lẹ.'),(10,1,11,'Cốt con Chó','Sinh năm cốt Chó, người có tánh khẩn khải lắm, ít sợ ai hay giúp đỡ với đời, ở đời hay có lòng bênh vực anh em và trung tín, không chịu người nói nặng lời, ít có hoạn nạn, tuổi lớn trở nên sự nghiệp.'),(11,1,12,'Cốt con Heo','Sinh năm cốt Heo, người có tánh ngay thẳng, đặng sang trọng, nhưng không có ở xứ cha mẹ sanh, bề ăn uống dễ hay mạnh khỏe, người tử tế hay yêu chuộng quí thể.'),(12,1,1,'Cốt con Chuột','Sinh năm cốt Chuột, tâm tánh không can đảm, hay thù nhỏ mọn, hay có tật bệnh lặt vặt trong mình thường lắm, hay buồn rầu, ít vui, hay tranh luận, ăn mặc như thường.'),(13,2,3,'Cốt con Trâu','Sinh năm cốt Trâu làm người tánh khéo trí sáng, thấy việc chi cũng mau hiểu, tánh ngay thẳng với người, số đi xa xứ có anh em bạn tử tế, nhưng việc làm có ích cho đời không đến ơn mà vẫn làm hoài.'),(14,2,4,'Cốt con Cọp','Sinh năm cốt Cọp không có phát đạt ở xứ cha mẹ sanh, đi xa xứ làm ăn khá, số đặng sang trọng, ăn mặc đầy đủ, luận mưu chi thì có đặng nấy, có quyền hành oai võ, ăn uống dễ, bất luận ngon dở.'),(15,2,5,'Cốt con Thỏ','Sinh năm cốt Thỏ, làm việc gì ban đầu khởi lớn, lúc sau như không có, như học nhiều biết ít, có số ở chỗ cha mẹ sanh đặng nên, lần lần đến khi lớn tuổi cũng đặng khá, ý vui vẻ mà có tánh nhát.'),(16,2,6,'Cốt con Rồng','Sinh năm cốt Rồng, người đặng sang trọng lại có oai quyền, tài lộc phát đạt, lại có danh tiếng, ở đặng yên, tánh hạnh vui vẻ, hình trạng tốt, hay giúp đời, có tánh công bình.'),(17,2,7,'Cốt con Rắn','Sinh năm cốt Rắn, tánh ưa chỗ yên tịnh, tay chân mau lẹ, tánh nóng nảy hung tợn, ít có bệnh hoạn, ít tai nạn, tánh vui vẻ, không muốn đi xa xứ.'),(18,2,8,'Cốt con Ngựa','Sinh năm cốt Ngựa, số người đặng sang trọng, ăn mặc đầy đủ, tánh hay đi xứ này sang xứ kia, tướng mạo tốt, mưu mô giỏi, tay chân mau lẹ.'),(19,2,9,'Cốt con Dê','Sinh năm cốt Dê, số người lớn tuổi đặng thong thả, ở chỗ cha mẹ sanh không đặng, số hai bàn tay trắng, mới lập nghiệp đặng thành, dầu ở tử tế bao nhiêu, lối xóm cũng hay nghét, ưa ăn trái cây nhiều hơn.'),(20,2,10,'Cốt con Khỉ','Sinh năm cốt Khỉ, người khó cầm của, ưa đi chơi, tay chân bộ tướng lẹ làng, có tánh thông minh ứng biến, nhưng không có tánh dè dặt, không chú ý.'),(21,2,11,'Cốt con Gà','Sinh năm cốt Gà, số người đặng sang trọng, đặng gần người quới nhân đi đâu thì có nha trạo bộ hạ nhiều theo hộ vệ, có danh tiếng nhiều, của có công mới hưởng không có công không an, tánh siêng năng mau lẹ.'),(22,2,12,'Cốt con Chó','Sinh năm cốt Chó, người có tánh khẩn khải lắm, ít sợ ai hay giúp đỡ với đời, ở đời hay có lòng bênh vực anh em và trung tín, không chịu người nói nặng lời, ít có hoạn nạn, tuổi lớn trở nên sự nghiệp.'),(23,2,1,'Cốt con Heo','Sinh năm cốt Heo, người có tánh ngay thẳng, đặng sang trọng, nhưng không có ở xứ cha mẹ sanh, bề ăn uống dễ hay mạnh khỏe, người tử tế hay yêu chuộng quí thể.'),(24,2,2,'Cốt con Chuột','Sinh năm cốt Chuột, tâm tánh không can đảm, hay thù nhỏ mọn, hay có tật bệnh lặt vặt trong mình thường lắm, hay buồn rầu, ít vui, hay tranh luận, ăn mặc như thường.'),(25,3,4,'Cốt con Trâu','Sinh năm cốt Trâu làm người tánh khéo trí sáng, thấy việc chi cũng mau hiểu, tánh ngay thẳng với người, số đi xa xứ có anh em bạn tử tế, nhưng việc làm có ích cho đời không đến ơn mà vẫn làm hoài.'),(26,3,5,'Cốt con Cọp','Sinh năm cốt Cọp không có phát đạt ở xứ cha mẹ sanh, đi xa xứ làm ăn khá, số đặng sang trọng, ăn mặc đầy đủ, luận mưu chi thì có đặng nấy, có quyền hành oai võ, ăn uống dễ, bất luận ngon dở.'),(27,3,6,'Cốt con Thỏ','Sinh năm cốt Thỏ, làm việc gì ban đầu khởi lớn, lúc sau như không có, như học nhiều biết ít, có số ở chỗ cha mẹ sanh đặng nên, lần lần đến khi lớn tuổi cũng đặng khá, ý vui vẻ mà có tánh nhát.'),(28,3,7,'Cốt con Rồng','Sinh năm cốt Rồng, người đặng sang trọng lại có oai quyền, tài lộc phát đạt, lại có danh tiếng, ở đặng yên, tánh hạnh vui vẻ, hình trạng tốt, hay giúp đời, có tánh công bình.'),(29,3,8,'Cốt con Rắn','Sinh năm cốt Rắn, tánh ưa chỗ yên tịnh, tay chân mau lẹ, tánh nóng nảy hung tợn, ít có bệnh hoạn, ít tai nạn, tánh vui vẻ, không muốn đi xa xứ.'),(30,3,9,'Cốt con Ngựa','Sinh năm cốt Ngựa, số người đặng sang trọng, ăn mặc đầy đủ, tánh hay đi xứ này 