INSERT INTO `so13_can_loc` VALUES (1,1,1,'Hưởng Lộc','Số này có tài lộc thạnh vượng, có ruộng vườn, có tánh tốt, việc ăn mặc đủ, gặp hung hóa hiền, cầu quan có quý nhân kính trọng.'),(2,1,11,'Khổn Lộc','Số này phạm Khổn Lộc, anh em bà con không đặng gần, ăn mặc thiếu hạp, tánh can cường, nhiều người ghét, tuổi nhỏ nghèo, tuổi lớn làm khá.'),(3,1,9,'Bất Lộc','Số này phạm Bối Lộc, anh em ở xa cách, đi biệt xứ không trở về, đi có nhiều xứ, đồ lao cực khổ, mà không khá.'),(4,1,7,'Chánh Lộc','Số này đặng Chánh Lộc, tánh cần kiệm, đi lưu lạc xứ khác khi tuổi lớn làm ăn trở nên sự nghiệp, vợ chồng con cháu vui vẻ.'),(5,1,5,'Ám Lộc','Số này phạm Ám Lộc, ăn mặc có ít, không nhờ anh em, gần người sang trọng, sự nghiệp không ở xứ cũ, tuổi lớn ăn ở đặng yên, làm ăn mới khá.'),(6,1,3,'Tài Lộc','Số này đặng Tài Lộc, làm ăn khá, sự nghiệp lập nên, có trâu ruộng, tôi tớ đủ dùng, trở nên danh tiếng phú gia.'),(7,1,1,'Sát Lộc','Số này phạm Sát Lộc, số bôn ba lội lạc, mưu sanh kế mị thường, để sanh nhai, đến tuổi gần già làm ăn mới khá.'),(8,1,11,'Thiên Lộc','Số này đặng Thiên Lộc, có số làm quan, lại có số làm giàu tôi tớ nhiều, vợ chồng hòa thuận, hưởng phước lộc nhiều.'),(9,1,9,'Hao Lộc','Số này phạm Hao Lộc, tánh hay ăn diện tiệc, hay kết nhân tình, chơi gần người sang trọng, sự nghiệp phá tan, đến xứ khác mới lập an.'),(10,1,7,'Toại Lộc','Số này phạm Toại Lộc, tánh hạnh nhiều mưu kế, có tánh tham, xảo trá, anh em, chồng vợ, con cháu có nhưng không hòa hiệp.'),(11,1,5,'Bịnh Lộc','Số này phạm Bịnh Lộc hay có bịnh hoạn lắm, không ở xứ cũ tu hành không đặng, giữ tiết kiệm đời cực khổ mà cũng nghèo.'),(12,1,3,'Vượng Lộc','Số này đặng Vượng Lộc, tiền tài hưng vượng, sản nghiệp lập thành, tánh hay chơi anh em bạn, trai có vợ, gái có chồng gặp đặng chỗ sang trọng.'),(13,2,2,'Hưởng Lộc','Số này có tài lộc thạnh vượng, có ruộng vườn, có tánh tốt, việc ăn mặc đủ, gặp hung hóa hiền, cầu quan có quý nhân kính trọng.'),(14,2,12,'Khổn Lộc','Số này phạm Khổn Lộc, anh em bà con không đặng gần, ăn mặc thiếu hạp, tánh can cường, nhiều người ghét, tuổi nhỏ nghèo, tuổi lớn làm khá.'),(15,2,10,'Bất Lộc','Số này phạm Bối Lộc, anh em ở xa cách, đi biệt xứ không trở về, đi có nhiều xứ, đồ lao cực khổ, mà không khá.'),(16,2,8,'Chánh Lộc','Số này đặng Chánh Lộc, tánh cần kiệm, đi lưu lạc xứ khác khi tuổi lớn làm ăn trở nên sự nghiệp, vợ chồng con cháu vui vẻ.'),(17,2,6,'Ám Lộc','Số này phạm Ám Lộc, ăn mặc có ít, không nhờ anh em, gần người sang trọng, sự nghiệp không ở xứ cũ, tuổi lớn ăn ở đặng yên, làm ăn mới khá.'),(18,2,4,'Tài Lộc','Số này đặng Tài Lộc, làm ăn khá, sự nghiệp lập nên, có trâu ruộng, tôi tớ đủ dùng, trở nên danh tiếng phú gia.'),(19,2,2,'Sát Lộc','Số này phạm Sát Lộc, số bôn ba lội lạc, mưu sanh kế mị thường, để sanh nhai, đến tuổi gần già làm ăn mới khá.'),(20,2,12,'Thiên Lộc','Số này đặng Thiên Lộc, có số làm quan, lại có số làm giàu tôi tớ nhiều, vợ chồng hòa thuận, hưởng phước lộc nhiều.'),(21,2,10,'Hao Lộc','Số này phạm Hao Lộc, tánh hay ăn diện tiệc, hay kết nhân tình, chơi gần người sang trọng, sự nghiệp phá tan, đến xứ khác mới lập an.'),(22,2,8,'Toại Lộc','Số này phạm Toại Lộc, tánh hạnh nhiều mưu kế, có tánh tham, xảo trá, anh em, chồng vợ, con cháu có nhưng không hòa hiệp.'),(23,2,6,'Bịnh Lộc','Số này phạm Bịnh Lộc hay có bịnh hoạn lắm, không ở xứ cũ tu hành không đặng, giữ tiết kiệm đời cực khổ mà cũng nghèo.'),(24,2,4,'Vượng Lộc','Số này đặng Vượng Lộc, tiền tài hưng vượng, sản nghiệp lập thành, tánh hay chơi anh em bạn, trai có vợ, gái có chồng gặp đặng chỗ sang trọng.'),(25,3,3,'Hưởng Lộc','Số này có tài lộc thạnh vượng, có ruộng vườn, có tánh tốt, việc ăn mặc đủ, gặp hung hóa hiền, cầu quan có quý nhân kính trọng.'),(26,3,1,'Khổn Lộc','Số này phạm Khổn Lộc, anh em bà con không đặng gần, ăn mặc thiếu hạp, tánh can cường, nhiều người ghét, tuổi nhỏ nghèo, tuổi lớn làm khá.'),(27,3,11,'Bất Lộc','Số này phạm Bối Lộc, anh em ở xa cách, đi biệt xứ không trở về, đi có nhiều xứ, đồ lao cực khổ, mà không khá.'),(28,3,9,'Chánh Lộc','Số này đặn