INSERT INTO `so13_can_sanghen` VALUES (1,1,6,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang trọng, và đặng rảnh rang, làm ruộng, nuôi thú vật đều thạnh vượng.'),(2,1,10,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang trọng, và đặng rảnh rang, làm ruộng, nuôi thú vật đều thạnh vượng.'),(3,1,1,'Phước Tinh','Số này đặng Phước Tinh; số đặng sang trọng, số sống lâu có học thì dễ lấy khoa, còn làm ăn thì đặng sản nghiệp lớn.'),(4,1,8,'Thiên Quan','Số này đặng Thiên Quan thì có chức phận, chốn triều đình đặng sống lâu thêm sang trọng.'),(5,1,1,'Hiệp Lộc','Số này đặng Hiệp Lộc, thì đặng giàu sang kinh dinh có tánh thông minh, thân mạng không tai họa, hưởng vinh hoa.'),(6,1,2,'Dương Vận','Số này Dương Vận thì anh em cốt nhục không hòa, có số làm thợ khéo, anh em ở xa cách không nhờ.'),(7,1,3,'Kim Ô','Số này đặng Kim Ô, tánh thông minh hiểu việc, đi xứ nào cũng có tài lợi thạnh vượng, sự nghiệp đặng an cư.'),(8,1,8,'Văn Tinh','Số này đặng Văn Tinh có số văn chương tấn phát, làm ăn thạnh vượng, phòng còn ngày sau đi ăn xin.'),(9,2,10,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang trọng, và đặng rảnh rang, làm ruộng, nuôi thú vật đều thạnh vượng.'),(10,2,8,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang trọng, và đặng rảnh rang, làm ruộng, nuôi thú vật đều thạnh vượng.'),(11,2,12,'Phước Tinh','Số này đặng Phước Tinh; số đặng sang trọng, số sống lâu có học thì dễ lấy khoa, còn làm ăn thì đặng sản nghiệp lớn.'),(12,2,2,'Hiệp Lộc','Số này đặng Hiệp Lộc, thì đặng giàu sang kinh dinh có tánh thông minh, thân mạng không tai họa, hưởng vinh hoa.'),(13,2,3,'Dương Vận','Số này Dương Vận thì anh em cốt nhục không hòa, có số làm thợ khéo, anh em ở xa cách không nhờ.'),(14,2,4,'Kim Ô','Số này đặng Kim Ô, tánh thông minh hiểu việc, đi xứ nào cũng có tài lợi thạnh vượng, sự nghiệp đặng an cư.'),(15,2,11,'Văn Tinh','Số này đặng Văn Tinh có số văn chương tấn phát, làm ăn thạnh vượng, phòng còn ngày sau đi ăn xin.'),(16,3,10,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang 