INSERT INTO `so13_can_thang_sanh` VALUES (1,'Giáp',1,'Cô thần','Số phạm Cô Thẩn, số khắc vợ chồng, khắc con, lại thêm phận bạc, lại có anh em không hòa, mỗi việc gì tự liệu.'),(2,'Giáp',9,'Quả tú','Số phạm Quả Tú, số khắc vợ chổng, khắc con, số phận bạc, gái gặp số này không có chổng con chi cả.'),(3,'Giáp',4,'Đại bại','Số phạm Đại Bại, thì lập gia đình không thành như có chỗ khác tốt thì dỡ nhẹ bớt, bằng không sự nghiệp phiêu lưu.'),(4,'Giáp',10,'Đại bại','Số phạm Đại Bại, thì lập gia đình không thành như có chỗ khác tốt thì dỡ nhẹ bớt, bằng không sự nghiệp phiêu lưu.'),(5,'Giáp',5,'Long phạm','Số này có lập sự nghiệp ở xứ khác thì tốt, và có ruộng đất bằng như ở xứ cha mẹ sanh thì thất bại'),(6,'Giáp',8,'Long phạm','Số này có lập sự nghiệp ở xứ khác thì tốt, và có ruộng đất bằng như ở xứ cha mẹ sanh thì thất bại'),(7,'Giáp',6,'Bát bại','Số phạm Bát Bại thì gia đình sự nghiệp lập không thành, trai đi đông tây, gái đi Nam Bắc, số lưu lạc phong trần.'),(8,'Giáp',9,'Bát bại','Số phạm Bát Bại thì gia đình sự nghiệp lập không thành, trai đi đông tây, gái đi Nam Bắc, số lưu lạc phong trần.'),(9,'Giáp',9,'Tiểu long phạm','Số phạm Tiểu Lang Phạm, trai thì làm con nuôi người ta, bằng không thì cũng làm bộ hạ, gái kỵ cha me, anh em, bà con.'),(10,'Giáp',12,'Tiểu long phạm','Số phạm Tiểu Lang Phạm, trai thì làm con nuôi người ta, bằng không thì cũng làm bộ hạ, gái kỵ cha me, anh em, bà con.'),(11,'Giáp',1,'Phi thiên long','Số đặng Phi Thiên Long, đặng hiển đạt, công danh sự nghiệp, phát đạt vinh hiển.'),(12,'Giáp',2,'Phi thiên long','Số đặng Phi Thiên Long, đặng hiển đạt, công danh sự nghiệp, phát đạt vinh hiển.'),(13,'Giáp',1,'Phá gia sát','Số phạm Phá Gia Sát, phá tán tổ nghiệp, khó giữ tiền của.'),(14,'Giáp',5,'Phá gia sát','Số phạm Phá Gia Sát, phá tán tổ nghiệp, khó giữ tiền của.'),(15,'Giáp',2,'Thiên hình sát','Số phạm Thiên Hình Sát thì trong đời ngừa kẻo bị bắt giam cẩm, như có phước thì qua đặng bằng không, thì có bị phạm án.'),(16,'Giáp',9,'Thiên hình sát','Số phạm Thiên Hình Sát thì trong đời ngừa kẻo bị bắt giam cẩm, như có phước thì qua đặng bằng không, thì có bị phạm án.'),(17,'Giáp',5,'Đại hao','Số phạm Đại Hao trong đời phải ngừa sự làm ăn thất bại, và tiền tài cẩn thận kẻo hao bớt thình lình, rán nên dè dặt.'),(18,'Giáp',6,'Đại hao','Số phạm Đại Hao trong đời phải ngừa sự làm ăn thất bại, và tiền tài cẩn thận kẻo hao bớt thình lình, rán nên dè dặt.'),(19,'Giáp',11,'Lục hạp','Số này đặng Lục Hạp thì cha mẹ, anh em, gia đinh, bà con, làm ăn cũng đều thuận hạp tất cả, việc ăn mặc rộng rãi.'),(20,'Giáp',12,'Lục hạp','Số này đặng Lục Hạp thì cha mẹ, anh em, gia đinh, bà con, làm ăn cũng đều thuận hạp tất cả, việc ăn mặc rộng rãi.'),(21,'Giáp',4,'Quan sát','Số này đặng Quan Sát, thuở nhỏ khó nuôi, lớn lên hay có tai nạn, và hay có bệnh, bằng không thì phải chịu tật.'),(22,'Giáp',12,'Quan sát','Số này đặng Quan Sát, thuở nhỏ khó nuôi, lớn lên hay có tai nạn, và hay có bệnh, bằng không thì phải chịu tật.'),(23,'Giáp',1,'Đản mạng sát','Số phạm Đản Mạng Sát, lúc cha mẹ mới sanh khó nuôi, hạng 3 năm và hạng 6 tuổi và hạng 12 tuổi, như qua đặng thì đến 21 và 31 tuổi nên ngừa số phận ai bi.'),(24,'Giáp',4,'Đản mạng sát','Số phạm Đản Mạng Sát, lúc cha mẹ mới sanh khó nuôi, hạng 3 năm và hạng 6 tuổi và hạng 12 tuổi, như qua đặng thì đến 21 và 31 tuổi nên ngừa số phận ai bi.'),(25,'Giáp',2,'Đản mạng sát','Số phạm Đản Mạng Sát, lúc cha mẹ mới sanh khó nuôi, hạng 3 năm và hạng 6 tuổi và hạng 12 tuổi, như qua đặng thì đến 21 và 31 tuổi nên ngừa số phận ai bi.'),(26,'Giáp',3,'Đản mạng sát','Số phạm Đản Mạng Sát, lúc cha mẹ mới sanh khó nuôi, hạng 3 năm và hạng 6 tuổi và hạng 12 tuổi, như qua đặng thì đến 21 và 31 tuổi nên ngừa số phận ai bi.'),(27,'Ất',4,'Cô thần','Số phạm Cô Thẩn, số khắc vợ chồng, khắc con, lại thêm phận bạc, lại có anh em không hòa, mỗi việc gì tự liệu.'),(28,'Ất',11,'Quả tú','Số phạm Quả Tú, số khắc vợ chổng, khắc con, số phận bạc, gái gặp số này không có chổng con chi cả.'),(29,'Ất',10,'Đại bại','Số phạm Đại Bại, thì 