INSERT INTO `so13_chi_sat` VALUES (1,1,1,'Nhựt Mã','Số này đặng Nhựt Mã, tánh hay đi nhiều, làm ăn khá, có điền địa, thâu tài lợi nhiều, gia trụ ít lo, ra đường nhiều trọng hậu.'),(2,1,2,'Lục Hại','Số này phạm Lục Hại, khắc cha mẹ, anh em, thân tộc, bề vợ chồng con cái cũng xung khắc, có số đi tu thì đắc quả.'),(3,1,3,'Hao Cái','Số này đặng Hao Cái, thì đặng có duyên nhiều người thương có phát 3 tài giỏi, có lộc thực nhiều, người ta hay kính trọng.'),(4,1,4,'Kiếp Sát','Số này phạm Kiếp Sát, khắc cha mẹ, khắc vợ con, có phước thì qua, bằng không thì đi ăn xin, số gái thay đổi ba đời chồng.'),(5,1,5,'Tai Sát','Số này phạm Tai Sát nhơn thân hay có tật bịnh, không lìa và hay có tai nạn thường, hay khắc vợ chồng và con.'),(6,1,6,'Thiên Sát','Số này phạm Thiên Sát, số trai khắc cha mẹ vợ, số gái khắc cha mẹ chồng, vợ chồng khắc, ít con, hay có bịnh ngặt, bằng không thì lưu lạc, một mình tìm cách sanh nhai.'),(7,1,7,'Địa Sát','Số này phạm Địa Sát, thường gặp tai nạn, kỵ con, khắc vợ chồng, nhưng có nghề giỏi, làm ăn no đủ.'),(8,1,8,'Niên Sát','Số này phạm Niên Sát, không ở chỗ cha mẹ lập, đi chỗ khác làm ăn khá, tự lập nên sự nghiệp, không nhờ anh em.'),(9,1,9,'Ngoại Sát','Số này phạm Ngoại Sát, số không ở xứ cha mẹ, đi nơi khác xứ làm ăn khá, khắc vợ chồng, khắc con, tay trắng lập nên sự nghiệp.'),(10,1,10,'Vong Thần','Số này phạm Vong Thần, số khắc anh em, bà con, đổi chỗ ở ba lần, kỳ ba lập nên sự nghiệp, điền viên tốt.'),(11,1,11,'Tướng Tinh','Số này đặng Tướng Tinh, số có quyền hành, bỉnh cán, tuổi trẻ phát tài, lộc sớm, bề vợ chồng con cháu sung túc, rất vinh hoa.'),(12,1,12,'Thiên An','Số này đặng Thiên An, tánh can cường, tâm thông minh, có số tu niệm đắc quả, có học thì dễ lấy khoa.'),(13,2,2,'Nhựt Mã','Số này đặng Nhựt Mã, tánh hay đi nhiều, làm ăn khá, có điền địa, thâu tài lợi nhiều, gia trụ ít lo, ra đường nhiều trọng hậu.'),(14,2,3,'Lục Hại','Số này phạm Lục Hại, khắc cha mẹ, anh em, thân tộc, bề vợ chồng con cái cũng xung khắc, có số đi tu thì đắc quả.'),(15,2,4,'Hao Cái','Số này đặng Hao Cái, thì đặng có duyên nhiều người thương có phát 3 tài giỏi, có lộc thực nhiều, người ta hay kính trọng.'),(16,2,5,'Kiếp Sát','Số này phạm Kiếp Sát, khắc cha mẹ, khắc vợ con, có phước thì qua, bằng không thì đi ăn xin, số gái thay đổi ba đời chồng.'),(17,2,6,'Tai Sát','Số này phạm Tai Sát nhơn thân hay có tật bịnh, không lìa và hay có tai nạn thường, hay khắc vợ chồng và con.'),(18,2,7,'Thiên Sát','Số này phạm Thiên Sát, số trai khắc cha mẹ vợ, số gái khắc cha mẹ chồng, vợ chồng khắc, ít con, hay có bịnh ngặt, bằng không thì lưu lạc, một mình tìm cách sanh nhai.'),(19,2,8,'Địa Sát','Số này phạm Địa Sát, thường gặp tai nạn, kỵ con, khắc vợ chồng, nhưng có nghề giỏi, làm ăn no đủ.'),(20,2,9,'Niên Sát','Số này phạm Niên Sát, không ở chỗ cha mẹ lập, đi chỗ khác làm ăn khá, tự lập nên sự nghiệp, không nhờ anh em.'),(21,2,10,'Ngoại Sát','Số này phạm Ngoại Sát, số không ở xứ cha mẹ, đi nơi khác xứ làm ăn khá, khắc vợ chồng, khắc con, tay trắng lập nên sự nghiệp.'),(22,2,11,'Vong Thần','Số này phạm Vong Thần, số khắc anh em, bà con, đổi chỗ ở ba lần, kỳ ba lập nên sự nghiệp, điền viên tốt.'),(23,2,12,'Tướng Tinh','Số này đặng Tướng Tinh, số có quyền hành, bỉnh cán, tuổi trẻ phát tài, lộc sớm, bề vợ chồng con cháu sung túc, rất vinh hoa.'),(24,2,1,'Thiên An','Số này đặng Thiên An, tánh can cường, tâm thông minh, có số tu niệm đắc quả, có học thì dễ lấy khoa.'),(25,3,3,'Nhựt Mã','Số này đặng Nhựt Mã, tánh hay đi nhiều, làm ăn khá, có điền địa, thâu tài lợi nhiều, gia trụ ít lo, ra đường nhiều trọng hậu.'),(26,3,4,'Lục Hại','Số này phạm Lục Hại, khắc cha mẹ, anh em, thân tộc, bề vợ chồng con cái cũng xung khắc, có số đi tu thì đắc quả.'),(27,3,5,'Hao Cái','Số này đặng Hao Cái, thì đặng có duyên nhiều người thương có phát 3 tài giỏi, có lộc thực nhiều, người ta hay kính trọng.'),(28,3,6,'Kiếp Sát','Số này phạm Kiếp Sát, khắc cha mẹ, khắc vợ con, có phước thì qua, bằng không thì đi ăn xin, số gái thay đổi ba đời chồng.'),(29,3,7,'Tai Sát','Số này