INSERT INTO `so13_chi_thu` VALUES (1,1,1,'Phụng Hoàng','Số này đặng Phụng Hoàng, tánh hiền lành, có chức phận lớn, bằng không thì cũng phát tài thịnh vượng rất vinh hoa.'),(2,1,2,'Sư Tử','Số này đặng Sư Tử thì mạng đặng chức phận lớn, có tánh ôn hòa với đời, có nghề nghiệp lớn, làm ăn thịnh vượng.'),(3,1,3,'Kim Kê','Số này đặng Kim Kê, tánh hạnh can đảm, văn chương giỏi, có nghề khéo, có danh tiếng lộc thực nhiều.'),(4,1,4,'Hề Sắt','Số này đặng Hề Sắt, có tài bằng người, nghề nghiệp rất tinh thông làm quan cũng tốt, làm dân cũng có tài.'),(5,1,5,'Yến Tử','Số này đặng Yến Tử tâm tánh khéo, thân hình đi đứng nhẹ nhàng, siêng năng nói chuyện, ít buồn rầu, đặng mạnh khỏe trong mình.'),(6,1,6,'Hồng Cao','Số này đặng Hồng Cao, số này hay lui tới chốn quan trường, cái mạng đặng hưng vượng, lộc thực tự nhiên có, một đời đặng vui vẻ.'),(7,1,7,'Sơn Lộc','Số này đặng Sơn Lộc, thuở nhỏ cách xa cha mẹ lo làm ăn, mỗi việc chi cũng chẳng đủ, tuổi lớn đặng thịnh vượng, vàng bạc đầy rương.'),(8,1,8,'Khổng Tước','Số này đặng Khổng Tước, thì có danh tiếng, gần người sang trọng, làm ăn có chi lo liệu, biết tự lập lấy thân.'),(9,1,9,'Bật Cửu','Số này đặng Bật Cửu. Ở đời hay có tánh làm lành, y lộc không thiếu, tuổi nhỏ chưa khá, đến lớn đặng vui vẻ, thịnh vượng.'),(10,1,10,'Châu Tước','Số này đặng Châu Tước tánh hạnh đặng cao cường, ăn mặc không thiếu, tiền tài thịnh vượng, ra đường nhiều người kính trọng.'),(11,1,11,'Giác Ưng','Số này đặng Giác Ưng, tâm tánh cao thượng có quyền hành tuổi lớn có tài lộc nhiều, tánh ưa diện tiệc, vui vẻ đời.'),(12,1,12,'Bạch Hạt','Số này đặng Bạch Hạt, số này đi mua bán tứ phương, có tiền lúa nhiều, tuổi lớn làm ăn thịnh vượng, đặng thong thả.'),(13,2,2,'Phụng Hoàng','Số này đặng Phụng Hoàng, tánh hiền lành, có chức phận lớn, bằng không thì cũng phát tài thịnh vượng rất vinh hoa.'),(14,2,3,'Sư Tử','Số này đặng Sư Tử thì mạng đặng chức phận lớn, có tánh ôn hòa với đời, có nghề nghiệp lớn, làm ăn thịnh vượng.'),(15,2,4,'Kim Kê','Số này đặng Kim Kê, tánh hạnh can đảm, văn chương giỏi, có nghề khéo, có danh tiếng lộc thực nhiều.'),(16,2,5,'Hề Sắt','Số này đặng Hề Sắt, có tài bằng người, nghề nghiệp rất tinh thông làm quan cũng tốt, làm dân cũng có tài.'),(17,2,6,'Yến Tử','Số này đặng Yến Tử tâm tánh khéo, thân hình đi đứng nhẹ nhàng, siêng năng nói chuyện, ít buồn rầu, đặng mạnh khỏe trong mình.'),(18,2,7,'Hồng Cao','Số này đặng Hồng Cao, số này hay lui tới chốn quan trường, cái mạng đặng hưng vượng, lộc thực tự nhiên có, một đời đặng vui vẻ.'),(19,2,8,'Sơn Lộc','Số này đặng Sơn Lộc, thuở nhỏ cách xa cha mẹ lo làm ăn, mỗi việc chi cũng chẳng đủ, tuổi lớn đặng thịnh vượng, vàng bạc đầy rương.'),(20,2,9,'Khổng Tước','Số này đặng Khổng Tước, thì có danh tiếng, gần người sang trọng, làm ăn có chi lo liệu, biết tự lập lấy thân.'),(21,2,10,'Bật Cửu','Số này đặng Bật Cửu. Ở đời hay có tánh làm lành, y lộc không thiếu, tuổi nhỏ chưa khá, đến lớn đặng vui vẻ, thịnh vượng.'),(22,2,11,'Châu Tước','Số này đặng Châu Tước tánh hạnh đặng cao cường, ăn mặc không thiếu, tiền tài thịnh vượng, ra đường nhiều người kính trọng.'),(23,2,12,'Giác Ưng','Số này đặng Giác Ưng, tâm tánh cao thượng có quyền hành tuổi lớn có tài lộc nhiều, tánh ưa diện tiệc, vui vẻ đời.'),(24,2,1,'Bạch Hạt','Số này đặng Bạch Hạt, số này đi mua bán tứ phương, có tiền lúa nhiều, tuổi lớn làm ăn thịnh vượng, đặng thong thả.'),(25,3,3,'Phụng Hoàng','Số này đặng Phụng Hoàng, tánh hiền lành, có chức phận lớn, bằng không thì cũng phát tài thịnh vượng rất vinh hoa.'),(26,3,4,'Sư Tử','Số này đặng Sư Tử thì mạng đặng chức phận lớn, có tánh ôn hòa với đời, có nghề nghiệp lớn, làm ăn thịnh vượng.'),(27,3,5,'Kim Kê','Số này đặng Kim Kê, tánh hạnh can đảm, văn chương giỏi, có nghề khéo, có danh tiếng lộc thực nhiều.'),(28,3,6,'Hề Sắt','Số này đặng Hề Sắt, có tài bằng người, nghề nghiệp rất tinh thông làm quan cũng tốt, làm dân cũng có tài.'),(29,3,7,'Yến Tử','Số này đặng Yến Tử tâm tánh khéo, thân hình đi đứng nhẹ nhàng, siêng năng nói chuyện, ít buồn rầu, đặng mạnh khỏe trong 