INSERT INTO `so13_nghenghiep` VALUES (1,1,1,'Quan nhơn','Số này: số có mạng làm giàu, hay ăn của bốn phương, học tập văn chương đễ lấy khoa, số có tiển và lúa gạo.'),(2,1,2,'Trùng Tế','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(3,1,3,'Tú Tài','Số này: Có số về văn chương, đặng cậy nhờ về sau, công đường rất thạnh vượng, nam nữ cũng vậy.'),(4,1,4,'Đả Thiết','Số này: Có số làm thợ rèn, hoặc làm thợ thiết, bằng không thì cũng có nghề cẩm gươm giáo, nếu không thì anh em ở cách xứ.'),(5,1,5,'Sư Thuật','Số này : Có số làm thẩy, như có phước nhiều đặng làm quan, trong đời ăn mặc đầy đủ, người có tài và gần người sang trọng.'),(6,1,6,'Sanh Quan','Số này: Tánh hạnh có mưu kế nhiều, và có số làm thợ mộc, số có ăn mặc đầy đủ, khéo ý, khéo tay làm.'),(7,1,7,'Âm Nhạc','Số này : Có tánh thông minh, có nghể đờn tinh thông, có danh tiếng và vui vẻ, đến xứ nào cũng được người trọng hậu, quí thể.'),(8,1,8,'Tiệm Dược','Số này: có số làm thầy thuốc và lập tiệm thuốc và làm thẩy bói, có cái phần làm thầy, thuận số thì khá.'),(9,1,9,'Tăng Đạo','Số này: Có tu niệm đặng đắc quả, nếu lập gia đình sau rồi cũng bỏ, dù làm nghể gì thì cũng đủ sanh nhai đó thôi.'),(10,1,10,'Tài Phùng','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(11,1,11,'Hoàng Quí','Số này: Không có số ở theo làng xóm làm ăn, chỉ có cái số ở theo chốn công môn, làm nghề văn chương thì tốt.'),(12,1,12,'Thủ Tác','Số này: Có cái số trồng răng, nhổ răng giỏi lắm, làm nghề răng đặng khá lại có người sang trọng yêu chuộng.'),(13,2,1,'Thủ Tác','Số này: Có cái số trồng răng, nhổ răng giỏi lắm, làm nghề răng đặng khá lại có người sang trọng yêu chuộng.'),(14,2,2,'Quan nhơn','Số này: số có mạng làm giàu, hay ăn của bốn phương, học tập văn chương đễ lấy khoa, số có tiển và lúa gạo.'),(15,2,3,'Trùng Tế','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(16,2,4,'Tú Tài','Số này: Có số về văn chương, đặng cậy nhờ về sau, công đường rất thạnh vượng, nam nữ cũng vậy.'),(17,2,5,'Đả Thiết','Số này: Có số làm thợ rèn, hoặc làm thợ thiết, bằng không thì cũng có nghề cẩm gươm giáo, nếu không thì anh em ở cách xứ.'),(18,2,6,'Sư Thuật','Số này : Có số làm thẩy, như có phước nhiều đặng làm quan, trong đời ăn mặc đầy đủ, người có tài và gần người sang trọng.'),(19,2,7,'Sanh Quan','Số này: Tánh hạnh có mưu kế nhiều, và có số làm thợ mộc, số có ăn mặc đầy đủ, khéo ý, khéo tay làm.'),(20,2,8,'Âm Nhạc','Số này : Có tánh thông minh, có nghể đờn tinh thông, có danh tiếng và vui vẻ, đến xứ nào cũng được người trọng hậu, quí thể.'),(21,2,9,'Tiệm Dược','Số này: có số làm thầy thuốc và lập tiệm thuốc và làm thẩy bói, có cái phần làm thầy, thuận số thì khá.'),(22,2,10,'Tăng Đạo','Số này: Có tu niệm đặng đắc quả, nếu lập gia đình sau rồi cũng bỏ, dù làm nghể gì thì cũng đủ sanh nhai đó thôi.'),(23,2,11,'Tài Phùng','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(24,2,12,'Hoàng Quí','Số này: Không có số ở theo làng xóm làm ăn, chỉ có cái số ở theo chốn công môn, làm nghề văn chương thì tốt.'),(25,3,1,'Hoàng Quí','Số này: Không có số ở theo làng xóm làm ăn, chỉ có cái số ở theo chốn công môn, làm nghề văn chương thì tốt.'),(26,3,2,'Thủ Tác','Số này: Có cái số trồng răng, nhổ răng giỏi lắm, làm nghề răng đặng khá lại có người sang trọng yêu chuộng.'),(27,3,3,'Quan nhơn','Số này: số có mạng làm giàu, hay ăn của bốn phương, học tập văn chương đễ lấy khoa, số có tiển và lúa gạo.'),(28,3,4,'Trùng Tế','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(29,3,5,'Tú Tài','Số này: Có số về văn chương, đặng cậy nhờ về sau, công đường rất thạnh vượng, nam nữ cũng vậy.'),(30,3,6,'Đả Thiết','Số này: Có số làm thợ rèn, hoặc làm thợ thiết, bằng không thì cũng có nghề cẩm gươm giáo, nếu không thì