INSERT INTO `so14_nuoithuvat` VALUES (1,1,'Kiên','Số này có số nuôi trâu heo và các loài thú nó sanh đẻ nhiều, nuôi mau lớn, đặng thạnh vượng, cái huê lợi lớn ấy, còn lập nên sự nghiệp vững bền đặng.'),(1,2,'Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi hay chết lắm, nếu không chết thì không sanh đẻ và nuôi không lớn nên rất bất lợi.'),(1,3,'Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi hay chết lắm, nếu không chết thì không sanh đẻ và nuôi không lớn nên rất bất lợi.'),(1,4,'Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi hay chết lắm, nếu không chết thì không sanh đẻ và nuôi không lớn nên rất bất lợi.'),(1,5,'Không','Số này không có nuôi trâu heo và các loài thú, nếu nuôi thì hay sanh ra nhiều điều trắc trở lắm, lại thêm không lớn không sanh đẻ, bất lợi.'),(1,6,'Không','Số này không có nuôi trâu heo và các loài thú, nếu nuôi thì hay sanh ra nhiều điều trắc trở lắm, lại thêm không lớn không sanh đẻ, bất lợi.'),(1,7,'Phá','Số này có số nuôi trâu, nuôi heo và các loài thú, nhưng mà khi nuôi 2, 3 lứa đầu, có hao tổn lôi thôi, rồi sau nuôi đặng trở nên thạnh vượng lắm.'),(1,8,'Hiệp','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn, lại thêm sanh đẻ nhiều, cái huê lợi ấy sanh lợi thêm và thêm thu trữ đặng nhiều.'),(1,9,'Hiệp','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn, lại thêm sanh đẻ nhiều, cái huê lợi ấy sanh lợi thêm và thêm thu trữ đặng nhiều.'),(1,10,'Hiệp','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn, lại thêm sanh đẻ nhiều, cái huê lợi ấy sanh lợi thêm và thêm thu trữ đặng nhiều.'),(1,11,'Hướng','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn lại thêm sanh đẻ đặng nhiều, có huê lợi, cái huê lợi ấy nó sanh thêm thạnh vượng.'),(1,12,'Hướng','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn lại thêm sanh đẻ đặng nhiều, có huê lợi, cái huê lợi ấy nó sanh thêm thạnh vượng.'),(2,1,'Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi h