INSERT INTO `so15_ruongdat` VALUES (1,1,'Phá','Số này nhằm chữ Phá, dù cha cho ruộng đất cũng hết, rồi sau khi đến xứ khác lập lại cũng không thành, tại số khắc điền địa, số không có ruộng.'),(1,2,'Giai','Số này nhằm chữ Giai, cha mẹ cho ruộng đất giữ không được lâu dài, tự nhiên tay trắng tạo thành ruộng đất điền viên, rất nên thạnh vượng về lúc tuổi già.'),(1,3,'Hướng','Số này nhằm chữ Hướng, dầu ruộng đất cha mẹ cho cũng không cần gìn giữ, đi đến đâu thấy ruộng đất cũng không ham bởi thế cho nên, không giữ và không tạo đặng, lo ăn mặc chơi bời đó thôi.'),(1,4,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(1,5,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(1,6,'Giai','Số này nhằm chữ Giai, cha mẹ cho ruộng đất giữ không được lâu dài, tự nhiên tay trắng tạo thành ruộng đất điền viên, rất nên thạnh vượng về lúc tuổi già.'),(1,7,'Kiên','Số này nhằm chữ Kiên, cha mẹ cho ruộng đất giữ đặng hay là tự tay tạo cũng đặng thành, và đặng thạnh vượng. Làm ăn nghề ruộng thường gặp đặng mùa, bền vững.'),(1,9,'Kiên','Số này nhằm chữ Kiên, cha mẹ cho ruộng đất giữ đặng hay là tự tay tạo cũng đặng thành, và đặng thạnh vượng. Làm ăn nghề ruộng thường gặp đặng mùa, bền vững.'),(1,10,'Bại','Số này nhằm chữ Bại, ruộng đất cha mẹ cho hay là mình tạo, ở tại chốn quan sanh thì bị thất bại, nếu có ý chí lớn, đi xứ khác lập điền viên, thì có đặng chút ít.'),(1,11,'Hướng','Số này nhằm chữ Hướng, dầu ruộng đất cha mẹ cho cũng không cần gìn giữ, đi đến đâu thấy ruộng đất cũng không ham bởi thế cho nên, không giữ và không tạo đặng, lo ăn mặc chơi bời đó thôi.'),(1,12,'Bại','Số này nhằm chữ Bại, ruộng đất cha mẹ cho hay là mình tạo, ở tại chốn quan sanh thì bị thất bại, nếu có ý chí lớn, đi xứ khác lập điền viên, thì có đặng chút ít.'),(2,1,'Kiên','Số này nhằm chữ Kiên, cha mẹ cho ruộng đất giữ đặng hay là tự tay tạo cũng đặng thành, và đặng thạnh vượng. Làm ăn nghề ruộng thường gặp đặng mùa, bền vững.'),(2,4,'Hướng','Số này nhằm chữ Hướng, dầu ruộng đất cha mẹ cho cũng không cần gìn giữ, đi đến đâu thấy ruộng đất cũng không ham bởi thế cho nên, không giữ và không tạo đặng, lo ăn mặc chơi bời đó thôi.'),(2,7,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(2,9,'Bại','Số này nhằm chữ Bại, ruộng đất cha mẹ cho hay là mình tạo, ở tại chốn quan sanh thì bị thất bại, nếu có ý chí lớn, đi xứ khác lập điền viên, thì có đặng chút ít.'),(2,10,'Giai','Số này nhằm chữ Giai, cha mẹ cho ruộng đất giữ không được lâu dài, tự nhiên tay trắng tạo thành ruộng đất điền viên, rất nên thạnh vượng về lúc tuổi già.'),(2,11,'Hiệp','Số này nhằm chữ Hiệp, cha mẹ cho ruộng đất gìn giữ đặng, lại còn mua tạo thêm, cũng đều đặng tốt, số này điền địa rất thạnh vượng đặng vững bền.'),(3,1,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(3,2,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(3,3,'Hướng','Số này nhằm chữ Hướng, dầu ruộng đất cha mẹ cho cũng không cần gìn giữ, đi đến đâu thấy ruộng đất cũng không ham bởi thế cho nên, không giữ và không tạo đặng, lo ăn mặc chơi bời đó thôi.'),(3,4,'Phá','Số này nhằm chữ Phá, dù cha cho ruộng đất cũng hết, rồi sau khi đến xứ khác lập lại cũng không thành, tại số khắc điền địa, số không có ruộng.'),(3,5,'Phá','Số này nhằm chữ Phá, dù cha cho ruộng đất cũng hết, rồi sau khi đến xứ khác lập lại cũng không thành, tại số khắc điền địa, số không có ruộng.'),(3,6,'Bại','Số này nhằm chữ Bại, ruộng đất cha