INSERT INTO `so16_hocgioido` VALUES (1,3,1,'Trực Kiên','Sanh nhằm Trực Kiên thì học rất thông minh, học ít biết nhiều, sự học rất phát đạt, dầu học văn hay học võ, cũng đều lấy khoa đặng dễ dàng, khi lấy khoa thì đặng khoa cao không có khoa nhỏ.'),(2,3,2,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(3,3,3,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(4,3,4,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(5,3,5,'Trực Không','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(6,3,6,'Trực Không','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(7,3,7,'Trực Phá','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(8,3,8,'Trực Hướng','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì.Vị Quan,dầu có thôi cũng Vi Sư, nghĩa là:tới thì làm quan, còn lui thì làm thầy.'),(9,3,9,'Trực Hướng','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì.Vị Quan,dầu có thôi cũng Vi Sư, nghĩa là:tới thì làm quan, còn lui thì làm thầy.'),(10,3,10,'Trực Hướng','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì.Vị Quan,dầu có thôi cũng Vi Sư, nghĩa là:tới thì làm quan, còn lui thì làm thầy.'),(11,3,11,'Trực Hiệp','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì.Vị Quan,dầu có thôi cũng Vi Sư, nghĩa là:tới thì làm quan, còn lui thì làm thầy.'),(12,3,12,'Trực Hiệp','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì.Vị Quan,dầu có thôi cũng Vi Sư, nghĩa là:tới thì làm quan, còn lui thì làm thầy.'),(13,7,1,'Trực Kiên','Sanh nhằm Trực Kiên thì học rất thông minh, học ít biết nhiều, sự học rất phát đạt, dầu học văn hay học võ, cũng đều lấy khoa đặng dễ dàng, khi lấy khoa thì đặng khoa cao không có khoa nhỏ.'),(14,7,2,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(15,7,3,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(16,7,4,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(17,7,5,'Trực Không','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít,cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đ