INSERT INTO `so17_thicu_kynhat` VALUES (1,1,7,'Hư Tú','Số này hội thi gặp nhằm năm Tý,thi lấy đặng khoa là phần kể chắc,còn nhằm năm thìn thì cũng lấy đặng khoa kể chắc, còn nhằm năm khác thì phước đức đặng chăng?'),(2,1,1,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(3,1,4,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(4,1,7,'Tinh Tú','Số này hội thi gặp nhằm năm Ngọ, thì lấy đặng khoa kể chắc , còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(5,1,10,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(6,1,7,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(7,1,1,'Can Tú','Số này hội thi gặp nhằm tháng bảy, tháng tám thì lấy đặng khoa kể chắc còn thi nhằm năm khác thì nhờ phước đức đặng chăng?'),(8,1,4,'Quỷ Tú','Số này thi không kỵ năm, tháng chỉ cả, như học giỏi siêng năng, đến khi thi dễ lấy khoa,đặng hai chữ công danh và hiển đạt.'),(9,1,10,'Lưu Tú','Số này học siêng năng, đến khi thi dễ lấy khoa, tuy học cực khổ quá mặc dầu,nên cần năng thì bảng đề chói rạng danh thơm.'),(10,1,7,'Ngưu Tú','Số này tuy học dở mặc đầu nhưng mà phải ráng cần học đến sau cũng lấy khoa ngày sau cũng công danh đặng.'),(11,2,11,'Hư Tú','Số này hội thi gặp nhằm năm Tý,thi lấy đặng khoa là phần kể chắc,còn nhằm năm thìn thì cũng lấy đặng khoa kể chắc, còn nhằm năm khác thì phước đức đặng chăng?'),(12,2,5,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(13,2,8,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(14,2,11,'Tinh Tú','Số này hội thi gặp nhằm năm Ngọ, thì lấy đặng khoa kể chắc , còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(15,2,2,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(16,2,11,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(17,2,5,'Can Tú','Số này hội thi gặp nhằm tháng bảy, tháng tám thì lấy đặng khoa kể chắc còn thi nhằm năm khác thì nhờ phước đức đặng chăng?'),(18,2,8,'Quỷ Tú','Số này thi không kỵ năm, tháng chỉ cả, như học giỏi siêng năng, đến khi thi dễ lấy khoa,đặng hai chữ công danh và hiển đạt.'),(19,2,2,'Lưu Tú','Số này học siêng năng, đến khi thi dễ lấy khoa, tuy học cực khổ quá mặc dầu,nên cần năng thì bảng đề chói rạng danh thơm.'),(20,2,11,'Ngưu Tú','Số này tuy học dở mặc đầu nhưng mà phải ráng cần học đến sau cũng lấy khoa ngày sau cũng công danh đặng.'),(21,3,3,'Hư Tú','Số này hội thi gặp nhằm năm Tý,thi lấy đặng khoa là phần kể chắc,còn nhằm năm thìn thì cũng lấy đặng khoa kể chắc, còn nhằm năm khác thì phước đức đặng chăng?'),(22,3,9,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(23,3,12,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(24,3,3,'Tinh Tú','Số này hội thi gặp nhằm năm Ngọ, thì lấy đặng khoa kể chắc , còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(25,3,6,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mão thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(26,3,3,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(27,3,9,'Can Tú','Số này hội thi gặp nhằm tháng bảy, tháng tám thì lấy đặng khoa kể chắc còn thi nhằm năm khác thì nhờ phước đức đặng chăng?'),(28,3,12,'Quỷ Tú','Số này thi không kỵ năm, tháng chỉ cả, như học giỏi siêng năng, đến khi thi dễ lấy khoa,đặng hai chữ công danh và hiển đạt.'),(29,3,6,'Lưu Tú','Số này học siêng năng, đến khi thi dễ lấy khoa, tuy học cực khổ quá mặc dầu