INSERT INTO `so20_loi_giai_duyen_no` VALUES ('Bảo Thủ','Số này nguyệt lão khéo se, Trăm năm tơ tóc chớ e chi phiền. Lương duyên chung thủy đặng yên, Của tiền giữ gìn phỉ nguyền ước mơ. Xóm giềng ai nấy cũng nhờ, Vợ chồng vinh hiển phụng thờ tổ tiên. Gần nhau bán chuyện ít nhiều, Của tiền thâu nhập luân phiên để dành.'),('Bịnh','Thảm buồn cho cảnh nợ duyên, Sanh nhằm chữ Bịnh lụy liên gia đình. Thở than phiền trách phận mình, Rồi đây thọ lãnh giữ gìn lư hương. Sanh ly tử biệt hai đường, Dẫu mà không thác tang thương chia lìa. Tán tụ nhơn đức trau tria, Thứ nhì mới đặng đó đây sum vầy.'),('Cách Sơn','Số ta cách trở vợ chồng, Nếu mà thuở trẻ tơ hồng se lơi. Trải qua một độ đổi dời, Thứ nhì mới đặng ở đời trăm năm. Cách sông cách núi xa xăm, Số trời chuyển định phước lâm phỉ nguyền. Khuyên chàng giảm bớt ưu phiền, Căn duyên hảo hiệp bạn hiền trời cho.'),('Cầu Tử','Số này chồng vợ quạnh hiu, Đôi đằng thơ thẩn mấy chiều trông con. Đêm nằm lo liệu hao mòn, Sớm trưa cầu khẩn thon von tháng ngày. Lạy trời lạy phật cầu con, May sao trời phật cho con nối dòng. Ý tình ở cũng xong xong, Vợ chồng hoà hợp tấc lòng mến thương.'),('Dưỡng','Số này Trời Đất cho ta, Vợ chồng phối ngẫu giao hoà bình an. Phụng loan kết cánh vầy đoàn, Một năm sanh dưỡng phòng loan kịp kỳ. Ăn mặc đầy đủ số ni, Vợ chồng một tuổi vậy thời giàu sang. Chớ lo duyên nợ lỡ làng, Vợ chồng hoà hiệp luận bàn thất gia.'),('Hòa Hiệp','Số này duyên phận trời cho, Làm chi đặng nấy chớ lo ưu phiền. Chung tình vĩnh viễn đặng yên, Sớm trưa chung hưởng phỉ nguyền Trần Châu. Trong ngoài trai gái tớ hầu, Gia đình sắp đặt nơi đâu chỉnh tề. Phu thê loan lạc một bề, Trường sanh thọ hưởng chớ bề lo chi.'),('Khắc Tử','Can trường gặp gỡ cùng nhau, Ý tình hòa hiệp làm giàu không con. Vợ chồng lo liệu mỏi mòn, Của tiền có sẵn không con nối dòng. Điền viên có sản nghiệp lo xong, Số không sanh dưỡng lòng trông đợi hoài. Ta nên tích đức hậu lai, Xin con nuôi đỡ mong ngày trời cho.'),('Lâm Quan','Hỡi thân phận bạc sau này, Lâm Quan rủi gặp nỗi này đớn đau. Vợ chồng ai cũng ước ao, Tại sao có bạn khác nào như không. Các sông các núi vợ chồng, Ý tình không hạp loan phòng quạnh hiu. Nhớ trông buồn tủi bao nhiêu, Đến khi gặp mặt khó yêu tình chàng.'),('Ly Thê','Số ta bạc phận quá chừng, Vợ chồng gặp mặt lẫy lừng muốn gây. Làm cho én nhạn lạc bầy, Kẻ nam người bắc ngồi đây đợi chàng. Thảm thay trách phận lỡ làng, Vợ chồng cách trở gia đàng quạnh hiu. Nhớ trông hình dạng mấy chiều, Khổ mà vui trọn về điều nợ duyên.'),('Mộ','Vợ chồng nghĩa trọng tình thâm, Sanh nhằm chữ Mộ vương lâm cho chàng. Căn duyên mù tịt lỡ làng, Khi tan khi hiệp đôi đàng mới xong. Trước đời xóm kiến chòm ong, Đời sau qui hiệp bưởi bồng đa đoan. Vợ chồng mới đặng bình an, Đến sau rồi cũng bình an một mình.'),('Mộc Dục','Chẳng may số hệ ở trời, Sanh nhằm Mộc Dục đổi dời căn duyên. Hôn nhân trắc trở chớ phiền, Một đời thứ nhất không yên gia đình. Đời sau vương vấn linh đinh, Thứ ba hòa hiệp chung tình trăm năm. Lo cho huynh đệ nhứt tâm, Việc rồi kết oán thù thâm nỡ đành.'),('Ngỗ Nghịch','Tơ hồng nguyệt lão hỡi ông, Cớ sao duyên nợ bông lông thế này. Đèn ngày nói chuyện sanh rầy, Hai đời cách trở đổi xoay vợ chồng.'),('Nhập Xá','Lương duyên cưới gả tốt thay, Mai nhơn nói giúp hai bên vừa lòng. Trước thời ăn nói đặng xong, Sau thời ăn nói bướm ong rộn ràng. Hai đàng lỡ vỡ rã tan, Thứ nhì hoà hiệp bà con gia đình. Tánh tình tin cậy giữ gìn, Cùng nhau trọn đạo chung tình phu thê.'),('Quan Đái','Than ôi! Trong cảnh phòng loan, Sanh nhằm Quan Đài đeo mang nợ tình. Hai đời phải chịu linh đinh, Thình lình gặp mối chung tình thứ ba. Ngày sau nên cửa nên nhà, Đến già trọn đạo gọi là phu thê. Trong bề gia đạo đặng an, Tề gia nội trợ mọi bề đặng an.'),('Suy','Thảm thay căn số vô phần, Gặp duyên bạc phận sanh nhằm chữ Suy. Mạng ai nấy tính không tùy, Gặp nhau hiểm tỵ khác gì tù nhơn. Đôi co nhiều tiếng thiệt hơn, Sâm thương hai ngả như đờn thiếu dây. Hai đời phải chịu đổi xây, Thứ ba mới đặng sum vầy nợ duyên.'),('Thai','Hồng nhan cốt cách xanh tươi, Xuê xoa ăn mặc tiếng cười có duyên. Dè đâu tình nghĩa ưu phiền, Lương duyên thứ nhứt vẹn tuyền đặng đâu. Của tiền hao tốn ngõ hầu, Thứ nhì mới đặng giao đầu phụng loan. Phỉ nguyền tình thiếp nghĩa chàng, Gia đình phát đạt đặng an một nhà.'),('Thương Lượng','Cám ơn nguyệt lão tơ hồng, Khéo se duyên mỗi chỉ vợ chồng thương nhau. Ngày đêm lo liệu làm giàu, Cùng nhau bàn bạc thanh tao càng tràng. Gia đình hưng vượng bình an, Trong ngoài tài vật nghinh ngang bốn bề. Trong thân phiền trách cười chê, Số này bạc phận những bề anh em.'),('Trùng Phu','Phu thê giữ gìn chữ tùng, Can thường đạo trọng giày dùn nương nhau. Nếu mà căng thẳng khác nào, Mối tơ yếu ớt làm sao cho bền. Kiếp trước thất hứa hai bên, Kiếp này trả quả hiệp nên vợ chồng. Rầy rà xung khắc chẳng đồng, Thứ nhì mới đặng tơ hồng se săn.'),('Trùng Thê','Số này chồng vợ nương nhau, Xem trong căn nợ xôn xao bộn bề. Số này ai nỡ cười chê, Lương duyên thứ nhứt khuê phòng đợi trông. Tơ hồng nguyệt lão hỡi ông, Giúp cho đôi trẻ loan phòng có đôi. Đời sao đặng hiệp giao bôi, Vững bền tơ tóc an ngôi gia đình.'),('Trường Sanh','Mẹ cha tích đức dày công, Nên nay con hưởng phước hồng Trường Sanh. Vợ chồng duyên nợ đặng thành, Trăm năm tơ tóc yến anh giao hòa. Sống lâu an hưởng một nhà, Trọn đời có một đầu là có hai. Tôi trai tớ gái hàng ngày, Số này có đức hậu lại đặng nhờ.'),('Tử','Câu rằng: phu phụ tình thâm, Phạm nay chữ Tử vương nhằm cho ta. Vợ chồng không đặng hiệp hòa, Không trùng duyên nợ dẫu mà bình an. Một đời thứ nhứt lo toan, Không lìa thì thác hai đàng biệt ly. Đời sau trọn nghĩa trọn nghì, Kết nguyền tơ tóc phải thì bền lâu.'),('Tương Hiểm','Vợ chồng gặp mặt chẳng ưa, Gặp nhau kiếm chuyện nói thừa thêm gây. Buổi đầu gặp gỡ vừa khuây, Đến sau rầy lộn tạo mày sẽ xa. Thiên thai số định đó là, Hai đằng kiếp trước chẳng qua lỡ nguyền. Kiếp này không đặng phi duyên, Khá tu nhơn đức mới nên cửa nhà.'),('Tuyệt','Vợ chồng duyên nợ chẳng lành, Sanh nhằm chữ Tuyệt bao đành sầu đau. Thêm sầu số phận quân bao, Xem trong duyên nợ khắc hào phu thê. Măng lo tranh đấu bộn bề, Trải qua bao độ gia tề mới an. Bởi do số hệ chớ than, Kỳ ba trời định mới an gia đình.'),('Đế Vượng','Khá nên tích đức thi công, Sanh nhằm Đế Vượng phước hồng tương giao. Hôn nhân gặp chỗ sang giàu, Một đời thong thả cùng nhau phỉ nguyền. Thiên nhiên sở định lương duyên, Thượng hoà hạ lục miệng miệng đời đời. Số này duyên nợ chẳng dời, Thảnh thơi lo liệu an nơi gia đình.');
/*!40000 ALTER TABLE `so20_loi_giai_duyen_no` ENABLE KEYS */;
UNLOCK TABLES;

