INSERT INTO `so22_nuoicon` VALUES (1,'Trường Sanh','Sanh con nuôi đặng phân nửa','Lời giải luận :\n\nĐây là luận hào con trai, nếu phước đức của Tổ Tiên nhiều thì y đứa con trai. Còn phước đức ít thì đổi sang con gái. Còn số này của người chồng thì coi như vậy, còn số con của vợ nữa, hay đặng hiệp lại cuộc sanh dưỡng con của chồng, phần con của vợ, cộng chung lại là khắc hơn số định trước đây.\n\nCó ý như vầy: nếu con đứa nào nó ưa cha hơn, thì là con của cha nó. Còn đứa nào ưa mẹ hơn, thì là con của mẹ nó, đó là cái quả tiền khiên như vậy, mới kết tình Phụ Tử, Mẫu Tử tình thâm.\n\nĐây là lời giải luận phụ thêm cho dễ hiểu, nhờ kinh nghiệm nhiều năm mới rõ đặng, qua chắc như vậy không sai.\n\nCòn vợ chồng sanh con dư số định thì đó là quả báo tiền kiếp, bởi thế cho nên trong số định thì nó có hiếu, con sanh dư số định thì nó bất hiếu, đã bất hiếu mà lại hại cha mẹ, để sự buồn rầu là khác nữa.\n\nTrong tay Mẫu Tâm Tử có 6 đứa con con người và con ta đó là con của mình, còn con trời, con đất, con phật, con ma, đó là con đi báo quả, đã không có hiếu, lại còn hại cha mẹ quả thật như vậy chẳng sai.'),(2,'Mộc Dục','Sanh con nuôi đặng 2 đứa','Lời giải luận :\n\nĐây là luận hào con trai, nếu phước đức của Tổ Tiên nhiều thì y đứa con trai. Còn phước đức ít thì đổi sang con gái. Còn số này của người chồng thì coi như vậy, còn số con của vợ nữa, hay đặng hiệp lại cuộc sanh dưỡng con của chồng, phần con của vợ, cộng chung lại là khắc hơn số định trước đây.\n\nCó ý như vầy: nếu con đứa nào nó ưa cha hơn, thì là con của cha nó. Còn đứa nào ưa mẹ hơn, thì là con của mẹ nó, đó là cái quả tiền khiên như vậy, mới kết tình Phụ Tử, Mẫu Tử tình thâm.\n\nĐây là lời giải luận phụ thêm cho dễ hiểu, nhờ kinh nghiệm nhiều năm mới rõ đặng, qua chắc như vậy không sai.\n\nCòn vợ chồng sanh con dư số định thì đó là quả báo tiền kiếp, bởi thế cho nên trong số định thì nó có hiếu, con sanh dư số định thì nó bất hiếu, đã bất hiếu mà lại hại cha mẹ, để sự buồn rầu là khác nữa.\n\nTrong tay Mẫu Tâm Tử có 6 đứa con con người và con ta đó là con của mình, còn con trời, con đất, con phật, con ma, đó là con đi báo quả, đã không có hiếu, lại còn hại cha mẹ quả thật như vậy chẳng sai.'),(3,'Quan Đái','Sanh con nuôi đặng 3 đứa','Lời giải luận :\n\nĐây là luận hào con trai, nếu phước đức của Tổ Tiên nhiều thì y đứa con trai. Còn phước đức ít thì đổi sang con gái. Còn số này của người chồng thì coi như vậy, còn số con của vợ nữa, hay đặng hiệp lại cuộc sanh dưỡng con của chồng, phần con của vợ, cộng chung lại là khắc hơn số định trước đây.\n\nCó ý như vầy: nếu con đứa nào nó ưa cha hơn, thì là con của cha nó. Còn đứa nào ưa mẹ hơn, thì là con của mẹ nó, đó là cái quả tiền khiên như vậy, mới kết tình Phụ Tử, Mẫu Tử tình thâm.\n\nĐây là lời giải luận phụ thêm cho dễ hiểu, nhờ kinh nghiệm nhiều năm mới rõ đặng, qua chắc như vậy không sai.\n\nCòn vợ chồng sanh con dư số định thì đó là quả báo tiền kiếp, bởi thế cho nên trong số định thì nó có hiếu, con sanh dư số định thì nó bất hiếu, đã bất hiếu mà lại hại cha mẹ, để sự buồn rầu là khác nữa.\n\nTrong tay Mẫu Tâm Tử có 6 đứa con con người và con ta đó là con của mình, còn con trời, con đất, con phật, con ma, đó là con đi báo quả, đã không có hiếu, lại còn hại cha mẹ quả thật như vậy chẳng sai.'),(4,'Lâm Quan','Sanh con nuôi đặng 3 đứa','Lời giải luận :\n\nĐây là luận hào con trai, nếu phước đức của Tổ Tiên nhiều thì y đứa con trai. Còn phước đức ít thì đổi sang con gái. Còn số này của người chồng thì coi như vậy, còn số con của vợ nữa, hay đặng hiệp lại cuộc sanh dưỡng con của chồng, phần con của vợ, cộng chung lại là khắc hơn số định trước đây.\n\nCó ý như vầy: nếu con đứa nào nó ưa cha hơn, thì là con của cha nó. Còn đứa nào ưa mẹ hơn, thì là con của mẹ nó, đó là cái quả tiền khiên như vậy, mới kết tình Phụ Tử, Mẫu Tử tình thâm.\n\nĐây là lời giải luận phụ thêm cho dễ hiểu, nhờ kinh nghiệm nhiều năm mới rõ đặng, qua chắc như vậy không sai.\n\nCòn vợ chồng sanh con dư số định thì đó là quả báo tiền kiếp, bởi thế cho nên tr