/*!40000 ALTER TABLE `so24_huynhde_loigiai` DISABLE KEYS */;
INSERT INTO `so24_huynhde_loigiai` VALUES ('Bàn tay','Bài thơ ở bàn tay ông Huỳnh Đế:\nỞ tay Huỳnh Đế tốt thay,\nPhước mà ta đặng tiền tài thiếu chi.\nRa đi nhiều kẻ yêu vì,\nTrong nhà trăm việc thiếu cho vật dùng.\nLao tâm tuổi nhỏ chẳng cùng,\nĐến khi lớn tuổi thong dung vẹn toàn.\nBốn phương lui tới luận bàn,\nCủa tiền tài vật muôn vàn thiếu chi.\n(Số này tuổi nhỏ trung bình đến 35 tuổi sắp lên phát đạt lắm)'),('Bụng','May sanh nhằm bụng ông Vua,\nCủa tiền ăn mặc thua ai đâu là.\nChẳng văn thì võ số ta,\nHai bên chầu trực xướng ca vui mừng.\nNửa đời sung sướng quá chừng,\nTrong ngoài của cải lẫy lừng thiếu chi.\nSố này chung thủy khả vi,\nDầu không chức phận hưởng thì giàu sang.\n(Số này dễ làm ăn lắm, có quyền chức, gửi có chồng)'),('Chân','Số này sanh ở tại chơn,\nTu hành đắc quả có hơn người thường.\nBiết đời nên giúp nghĩa phương,\nKhá tu nhơn đức lo lường ngày sau.\nChỗ cha mẹ ở đặng nào,\nVợ chồng thứ nhứt khắc hào.\nĐời sau mới đặng vẹn bề,\nGia đình khác xứ mới hề lập nên.\n(Số này tu đắc quả, vợ chồng thay đổi một lần mới nên)'),('Hông','Sanh nhằm Huỳnh Đế ở hông,\nPhước hồng thì đặng chờ trông lâu dài.\nThi thơ kinh sách thông thạo,\nSố có khoa mục đặng hào Công Danh.\nLương duyên tơ tóc đặng lành,\nTrăm năm chung hưởng phước sanh an hòa.\nLàm ăn gặp vận số ta,\nVợ chồng lo tính vậy mà đặng nên.\n(Số này làm ăn khá, đặng khá công danh)'),('Vai','Sanh nhiều chỗ ở trên vai,\nTuổi xuân cực khổ nào hay vận thời.\nBa mươi gặp vận thời lại,\nSắp lên lớn tuổi tiền tài thiếu chi.\nChừng ấy trâu ruộng thiếu gì,\nSố trời đã định phải thì thua ai.\nAnh em số phận tiền tài,\nChuyện mình mình liệu khó bề cậy nương.\n(Số này nhỏ cực lớn khá, không nhờ anh em)'),('Đầu','Sanh tại trên đầu ông Huỳnh Đế,\nTrong đời vui vẻ khỏi bề nhọc lo.\nRảnh rang phú quý trời cho,\nCao lương mỹ vị ăn no thiếu gì.\nCông danh phú quý lo chi,\nTự nhiên danh giá một khi đặng nhờ.\nSố này dầu giả đảo thờ,\nGặp cảnh duyên nợ đặng nhờ nào phu.\nSánh duyên cùng với danh phu,\nDầu cho nam nữ cũng đều tốt cả.\n(Số này nam nữ cũng tốt cả)'),('Đầu gối','Ở nơi đầu gối khổ ôi,\nThuở trẻ cực khổ lôi thôi trăm bề.\nĐi nhiều chưn chẳng muốn về,\nXiết bao lao khổ chớ hề ngồi không.\nGia đàng trễ nải không xong,\nĐến bốn mươi tuổi mới hòng ngồi an.\nChừng ấy lo liệu gia đàng,\nTrong ngoài đến đó vững vàng lập nên.\n(Số này tuổi trẻ đi đứng nhiều, đến 48 tuổi mới nên)');
/*!40000 ALTER TABLE `so24_huynhde_loigiai` ENABLE KEYS */;
UNLOCK TABLES;

