INSERT INTO `so25_con_vua` VALUES (1,'Con Vua Hắc Đế','Tánh thông minh, có tài lộc, công bình, ưa trồng tỉa, không khiếp sợ, hay đi lưu thông nhiều. Nên thờ ông Vua Hắc Đế, nên làm lành ăn chay, thờ phật mới nên.'),(2,'Con Vua Huỳnh Đế','Tánh cứng mạnh, hay có của hoạch tài, ưa trồng tỉa hay bao gồm cơ mật. Nên thờ Thổ Địa, Long Thần, phải tu tâm thờ phật mới nên.'),(3,'Con Vua Thanh Đế','Tánh ưa chơi hậu bạn, hậu bạn hay phản, có trí độ, có bà con đông, con cháu nhiều, nên đề phòng hỏa hoạn. Nên thờ vua Thanh Đế, ở đời nên nhẫn nại mới an.'),(4,'Con Vua Thanh Đế','Tánh ưa chơi hậu bạn, hậu bạn hay phản, có trí độ, có bà con đông, con cháu nhiều, nên đề phòng hỏa hoạn. Nên thờ vua Thanh Đế, ở đời nên nhẫn nại mới an.'),(5,'Con Vua Huỳnh Đế','Tánh cứng mạnh, hay có của hoạch tài, ưa trồng tỉa hay bao gồm cơ mật. Nên thờ Thổ Địa, Long Thần, phải tu tâm thờ phật mới nên.'),(6,'Con Vua Xích Đế','Tánh nóng nảy lẹ làng, gần người sang trọng, con cháu ít, có tài lộc và có tiểu tật. Nên thờ vua Xích Đế tánh đừng nóng nảy nhẫn nại mới yên.'),(7,'Con Vua Xích Đế','Tánh nóng nảy lẹ làng, gần người sang trọng, con cháu ít, có tài lộc và có tiểu tật. Nên thờ vua Xích Đế tánh đừng nóng nại nhẫn nại mới yên.'),(8,'Con Vua Huỳnh Đế','Tánh cứng mạnh, hay có của hoạch tài, ưa trồng tỉa hay bao gồm cơ mật. Nên thờ Thổ Địa, Long Thần, phải tu tâm thờ phật mới nên.'),(9,'Con Vua Bạch Đế','Tánh hạnh can cường, có tật hoặc có thẹo, hay ưa dao búa, ưa chiến trận, có tài lộc, hay hoạn nạn. Nên thờ vua Bạch Đế.'),(11,'Con Vua Huỳnh Đế','Tánh cứng mạnh, hay có của hoạch tài, ưa trồng tỉa hay bao gồm cơ mật. Nên thờ Thổ Địa, Long Thần, phải tu tâm thờ phật mới nên.'),(12,'Con Vua Bạch Đế','Tánh hạnh can cường, có tật hoặc có thẹo, hay ưa dao búa, ưa chiến trận, có tài lộc, hay hoạn nạn. Nên thờ vua Bạch Đế.'),(12,'Con Vua Hắc Đế','Tánh thông minh, có tài lộc, công bình, ưa trồng tỉa, không khiếp sợ, hay đi lưu thông nhiều. Nên thờ ông Vua Hắc Đế, nên làm lành ăn chay, thờ phật mới nên.');
