INSERT INTO `so26_conha` VALUES (1,1,'Kiên Gia','Gặp nhằm số Kiên Gia: số này lập gia nghiệp mau thì làm ăn khá lắm, còn ở nhà cũ cha mẹ, hay mua nhà cũ sửa lại thì phải chịu đau ốm hoài.'),(1,2,'Kiên Địa','Gặp nhằm số Kiên Gia: số này lập gia nghiệp mau thì làm ăn khá lắm, còn ở nhà cũ cha mẹ, hay mua nhà cũ sửa lại thì phải chịu đau ốm hoài.'),(1,3,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(1,4,'Đại Gia','Phạm nhằm số Đại Gia: số ở nhà của cha mẹ không đặng hay sanh đều hao tốn, tai nạn, có số đi ở làng khác, tạo gia nghiệp đặng tốt, dễ làm ăn hơn chỗ cũ. Phạm số người ở chỗ quê hương lập đặng, nếu đi xứ khác tạo không thành, còn số người có lưu lạc xứ khác lập nên gia nghiệp; nếu ở lại quê hương thì lập không thành.'),(1,5,'Phá Gia','Phạm nhằm số Phá Gia và Bại Gia không ở nhà của cha mẹ đặng, phải đổi dời chỗ khác, mới lập đặng thành nghiệp, nếu ở nhà của cha mẹ thì bôn ba cực khổ lắm.'),(1,6,'Không Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(1,7,'Không Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(1,8,'Vong Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(1,9,'Bại Gia','Phạm nhằm số Phá Gia và Bại Gia không ở nhà của cha mẹ đặng, phải đổi dời chỗ khác, mới lập đặng thành nghiệp, nếu ở nhà của cha mẹ thì bôn ba cực khổ lắm.'),(1,10,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(1,11,'Hiệp Gia','Số này đặng số Hiệp Gia: nhà cửa lập đặng nguy nga tốt đẹp, người ăn nói đặng thông minh, mở mang, tuổi lớn 50 sắp lên thì thấy gia nghiệp tốt, của tiền lúa gạo nhiều.'),(1,12,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(2,1,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(2,2,'Hiệp Gia','Số này đặng số Hiệp Gia: nhà cửa lập đặng nguy nga tốt đẹp, người ăn nói đặng thông minh, mở mang, tuổi lớn 50 sắp lên thì thấy gia nghiệp tốt, của tiền lúa gạo nhiều.'),(2,3,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(2,4,'Kiên Gia','Gặp nhằm số Kiên Gia: số này lập gia nghiệp mau thì làm ăn khá lắm, còn ở nhà cũ cha mẹ, hay mua nhà cũ sửa lại thì phải chịu đau ốm hoài.'),(2,5,'Kiên Địa','Gặp nhằm số Kiên Gia: số này lập gia nghiệp mau thì làm ăn khá lắm, còn ở nhà cũ cha mẹ, hay mua nhà cũ sửa lại thì phải chịu đau ốm hoài.'),(2,6,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(2,7,'Đại Gia','Phạm nhằm số Đại Gia: số ở nhà của cha mẹ không đặng hay sanh đều hao tốn, tai nạn, có số đi ở làng khác, tạo gia nghiệp đặng tốt, dễ làm ăn hơn chỗ cũ. Phạm số người ở chỗ quê hương lập đặng, nếu đi xứ khác tạo không thành, còn số người có lưu lạc xứ khác lập nên gia nghiệp; nếu ở lại quê hương thì lập không thành.'),(2,8,'Phá Gia','Phạm nhằm số Phá Gia và Bại Gia không ở nhà của cha mẹ đặng, phải đổi dời chỗ khác, mới lập đặng thành nghiệp, nếu ở nhà của cha mẹ thì bôn ba cực khổ lắm.'),(2,9,'Không Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(2,10,'Không Gia','Phạm nhằm số Không Gia 