INSERT INTO `so27_ngaykyhap` VALUES (1,1,1,'NGÀY TÝ - Hạp: quới nhơn, văn thơ, đơn từ, nhập học (Kỵ: nghe lời can thiệp, hùn hạp, người quen phản)'),(1,1,2,'NGÀY SỬU - Hạp: cầu tài cầu phước, đào đất dời chỗ ở (Kỵ: rầy rà, gái hờn chồng, nhức mỏi, lo chi phòng thất vọng)'),(1,1,3,'NGÀY DẦN - Hạp: văn thơ, đơn từ, nhập học, đi đường (Kỵ: trai hờn vợ, người quen phản, đào đất)'),(1,1,4,'NGÀY MẸO - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: pháp luật, rầy rà, bệnh hoạn, gái hờn chồng)'),(1,1,5,'NGÀY THÌN - Hạp: có thần độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, cầu tài, quan sự, đi sông, bị té, chó dữ)'),(1,1,6,'NGÀY TỴ - Hạp: mỗi việc có hạp ý, có tiên bà độ mạng (Kỵ: bịnh hoạn, trộm cắp, gian tham, hung dữ, phá hoại)'),(1,1,7,'NGÀY NGỌ - Hạp: quới nhơn hộ trợ (Kỵ: nghe lời hùn hạp, chồng hờn vợ, xung buồn đi nhiều)'),(1,1,8,'NGÀY MÙI - Hạp: cầu tài, dời chỗ ở, đào đất (Kỵ: phép luật, tranh rầy, lo chi phòng thất vọng, nhức mỏi)'),(1,1,9,'NGÀY THÂN - Hạp: văn thơ, đơn từ, nhập học, đi đường (Kỵ: rầy rà, đào đất, trao tiền cho vợ)'),(1,1,10,'NGÀY DẬU - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: gian tham, pháp luật, rầy rà, gái hờn chồng)'),(1,1,11,'NGÀY TUẤT - Hạp: có thần linh độ mạng (Kỵ: đưa tiền ra, cầu tài, quan sự, nghe lời can thiệp, xung buồn)'),(1,1,12,'NGÀY HỢI - Hạp: lo liệu hạp ý, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, cướp trộm, phá hư hao)'),(1,3,1,'NGÀY TÝ - Hạp: thần linh độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, cầu tài, quan sự, đi nhiều, kỵ té, đi sông).'),(1,3,2,'NGÀY SỬU - Hạp: cầu tài, kết hôn, đào đất, cầu tiền bà cứu bịnh (Kỵ: bịnh hoạn, gian tham, phá hại rầy rà).'),(1,3,3,'NGÀY DẦN - Hạp: văn thơ, đơn tờ, nhập học, có thần độ mạng (Kỵ: đưa tiền ra, cầu tài, nghe lời, đi sông).'),(1,3,4,'NGÀY MẸO - Hạp: cầu tài, kết hôn, đào đất, gặp hung hóa hiền (Kỵ: nhức mỏi, lo chi phòng thất vọng, gái hờn chồng).'),(1,3,5,'NGÀY THÌN - Hạp: (không có) (Kỵ: buồn rầu, người quen phản, kỵ té, chó dữ).'),(1,3,6,'NGÀY TỴ - Hạp: cầu tài, cầu phước, gặp hung hóa hiền (Kỵ: pháp luật rầy rà, lo nhiều, trai hờn vợ, gái hờn chồng).'),(1,3,7,'NGÀY NGỌ - Hạp: văn thơ, đơn tờ, nhập học, quới nhơn hỗ trợ (Kỵ: quan sự, đi té, rầy rà, đào đất).'),(1,3,8,'NGÀY MÙI - Hạp: kết hôn, vui vẻ hạp ý, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, rầy rà, lo chi phòng thất vọng).'),(1,3,9,'NGÀY THÂN - Hạp: văn thơ, đơn tờ, nhập học, có thần độ mạng (Kỵ: đưa tiền ra, cầu tài, hùn hạp, nghe lời).'),(1,3,10,'NGÀY DẬU - Hạp: cầu tài, đào đất (Kỵ: cướp trộm, luật pháp, lo nhiều người nói láo).'),(1,3,11,'NGÀY TUẤT - Hạp: quới nhơn hỗ trợ (Kỵ: người thân phản, quan sự buồn phiền).'),(1,3,12,'NGÀY HỢI - Hạp: cầu tài, cầu phước, gặp hung hóa hiền (Kỵ: pháp luật, lo nhiều, trai hờn vợ).'),(1,5,1,'NGÀY TÝ - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: pháp luật rầy rà, bịnh hoạn, gái hờn chồng).'),(1,5,2,'NGÀY SỬU - Hạp: có thần linh độ mạng (Kỵ: đi tế, quan sự, đi sông, nghe lời hùn hạp).'),(1,5,3,'NGÀY DẦN - Hạp: mỗi việc hạp ý (Kỵ: bịnh hoạn, trộm cắp, gian tham, phá hoại).'),(1,5,4,'NGÀY MẸO - Hạp: văn thơ, đơn tờ, nhập học (Kỵ: quới nhơn hộ trợ, nghe lời bàn hùn hạp).'),(1,5,5,'NGÀY THÌN - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: nhức mỏi, lo chi phòng thất vọng).'),(1,5,6,'NGÀY TỴ - Hạp: thơ từ, đơn tờ, nhập học, đi đường, quới nhơn hỗ trợ (Kỵ: gian tham, trai hờn vợ, người phản).'),(1,5,7,'NGÀY NGỌ - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: bệnh hoạn, thị phi).'),(1,5,8,'NGÀY MÙI - Hạp: có thần linh độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, cầu tài, quan sự, té, than buồn).'),(1,5,9,'NGÀY THÂN - Hạp: mỗi việc an vui, cầu tiền bà cứu bịnh (Kỵ: bệnh hoạn).'),(1,5,10,'NGÀY DẬU - Hạp: quới nhơn hộ trợ (Kỵ: nghe lời, kẻ gian tham, đi nhiều, trai hờn vợ).'),(1,5,11,'NGÀY TUẤT - Hạp: cầu tài, đào đất, yên vui (Kỵ: phép luật, rầy rà, lo nhiều, nhức mỏi).'),(1,5,12,'NGÀY HỢI - Hạp: văn thơ, đơn tờ, nhập học, đi đường (Kỵ: trai hờn vợ, đào đất, người phản).'),(1,7,1,'NGÀY TÝ - Hạp: quới nhơn hộ trợ, văn thơ, đơn tờ, nhập học (Kỵ: nghe lời hùn hạp, vợ chồng buồn giận).'),(1,7,2,'NGÀY SỬU - Hạp: cầu tài, cầu phước, kết hôn, đào đất (Kỵ: pháp luật, quan sự, té, nhức mỏi).'),(1,7,3,'NGÀY DẦN - Hạp: văn thơ, đơn tờ, đi đường, có thần hộ mạng (Kỵ: người thân phản, đào đất, trai hờn vợ).'),(1,7,4,'NGÀY MẸO - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: pháp luật, rầy rà, gái hờn chồng).'),(1,7,5,'NGÀY THÌN - Hạp: có thần độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, quan sự, đi sông, bị té).'),(1,7,6,'NGÀY TỴ - Hạp: cầu tiên bà cứu bịnh, hạp ý (Kỵ: bịnh hoạn, kẻ gian tham, trộm cắp, lo nhiều).'),(1,7,7,'NGÀY NGỌ - Hạp: văn thơ, đơn tờ, thần độ mạng, quới nhơn trợ giúp (Kỵ: nghe lời hùn hạp, xung buồn).'),(1,7,8,'NGÀY MÙI - Hạp: cầu tài, cầu phước, làm ăn trung bình (Kỵ: bịnh hoạn, rầy rà, tranh phản).'),(1,7,9,'NGÀY THÂN - Hạp: văn thơ, đơn tờ, nhập học, đi đường (Kỵ: trai hờn vợ, đi đường, đào đất).'),(1,7,10,'NGÀY DẬU - Hạp: cầu tài, cầu phước, kết hôn, hạp ý (Kỵ: gái hờn chồng, pháp luật).'),(1,7,11,'NGÀY TUẤT - Hạp: thần linh độ mạng, quới nhơn trợ giúp (Kỵ: đưa tiền ra, đi nhiều, bị té, xung buồn).'),(1,7,12,'NGÀY HỢI - Hạp: cầu tài, cầu phước, hạp ý, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, lo nhiều).'),(1,9,1,'NGÀY TÝ - Hạp: văn thơ, đơn tờ, nhập học, quới nhơn hộ trợ (Kỵ: đưa tiền ra, quan sự, đi sông, than buồn).'),(1,9,2,'NGÀY SỬU - Hạp: kết hôn, cầu tiền bà cứu bịnh, kỵ bịnh hoạn (Kỵ: rầy rà, gian tham, lo chi phòng thất vọng).'),(1,9,3,'NGÀY DẦN - Hạp: văn thơ, đơn tờ, nhập học, đi đường, có thần độ mạng (Kỵ: đưa tiền ra, nghe lời, đi sông, đi nhiều).'),(1,9,4,'NGÀY MẸO - Hạp: cầu tài, cầu phước, tạo chỗ ở, kết hôn (Kỵ: pháp luật, gian tham, nhức mỏi, lo chi phòng thất vọng).'),(1,9,5,'NGÀY THÌN - Hạp: có quới nhơn hộ trợ, hạp ý (Kỵ: quan sự, người thân phản, té, chó dữ).'),(1,9,6,'NGÀY TỴ - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: đưa tiền ra, lo nhiều, trai hờn vợ).'),(1,9,7,'NGÀY NGỌ - Hạp: có thần độ mạng, quới nhơn hộ trợ (Kỵ: nghe lời, quan sự, đi sông, đi nhiều).'),(1,9,8,'NGÀY MÙI - Hạp: cầu tài, tạo chỗ ở, kết hôn, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, rầy rà).'),(1,9,9,'NGÀY THÂN - Hạp: văn thơ, đơn tờ, nhập học, có thần độ mạng (Kỵ: đưa tiền ra, cầu tài, đi sông, đào đất).'),(1,9,10,'NGÀY DẬU - Hạp: cầu tài, kết hôn, gặp hung hóa hiền (Kỵ: nhức mỏi, lo chi phòng thất vọng, trai hờn vợ).'),(1,9,11,'NGÀY TUẤT - Hạp: (không có) (Kỵ: đi té, người quen phản, quan sự, buồn phiền).'),(1,9,12,'NGÀY HỢI - Hạp: cầu tài, cầu phước, hạp ý, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, pháp luật, lo nhiều).'),(1,11,1,'NGÀY TÝ - Hạp: có thần hộ mạng, quới nhơn hộ trợ, đi đường (Kỵ: đưa tiền ra, cầu tài, người phản, đi sông).'),(1,11,2,'NGÀY SỬU - Hạp: cầu tài, cầu phước, tạo chỗ ở, hạp ý (Kỵ: pháp luật, gian tham, rầy rà, gái hờn chồng).'),(1,11,3,'NGÀY DẦN - Hạp: văn thơ, đơn tờ, nhập học, quới nhơn hộ trợ (Kỵ: nghe lời hùn hạp, nhức mỏi, lo buồn).'),(1,11,4,'NGÀY MẸO - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: đưa tiền ra, cầu tài, đi nhiều, bị té).'),(1,11,5,'NGÀY THÌN - Hạp: có thần độ mạng, quới nhơn hộ trợ (Kỵ: cầu tài, nghe lời, đi sông, đi nhiều, đào đất).'),(1,11,6,'NGÀY TỴ - Hạp: cầu tài, kết hôn, hạp ý, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, lo nhiều).'),(1,11,7,'NGÀY NGỌ - Hạp: văn thơ, đơn tờ, nhập học, thần độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, tiền bạc, đi sông, té).'),(1,11,8,'NGÀY MÙI - Hạp: cầu tài, kết hôn, hạp ý, cầu tiên bà cứu bịnh (Kỵ: pháp luật, rầy rà, gái hờn chồng).'),(1,11,9,'NGÀY THÂN - Hạp: văn thơ, đơn tờ, nhập học, đi đường (Kỵ: đi nhiều, người phản, đào đất, hùn hạp).'),(1,11,10,'NGÀY DẬU - Hạp: kết hôn, kết hôn, đào đất, cầu tiên bà cứu bịnh (Kỵ: bịnh hoạn, lo chi lo nhiều).'),(1,11,11,'NGÀY TUẤT - Hạp: có người quới nhơn hộ trợ (Kỵ: nghe lời hùn hạp, nghe lời hùn hạp, người quen phản, hay xung buồn).'),(1,11,12,'NGÀY HỢI - Hạp: cầu tài, kết hôn, tạo chỗ ở, đào đất (Kỵ: nhức mỏi, lo chi phòng thất vọng, bị té).'),(2,2,1,'NGÀY TÝ - Hạp: cầu tài, cầu tiền hà độ mạng, đào đất, dời chỗ ở (Kỵ: hay lo nhiều, phòng bịnh hoạn).'),(2,2,2,'NGÀY SỬU - Hạp: có thần linh độ mạng, có người quới nhơn trợ (Kỵ: nghe lời hùn hạp, cầu tài, quan sự, đi sông, té).'),(2,2,3,'NGÀY DẦN - Hạp: cầu tài, dời chỗ ở, kết hôn, đào đất (Kỵ: lo chi phòng thất vọng, nhức mỏi, trai hờn vợ).'),(2,2,4,'NGÀY MẸO - Hạp: có thần linh độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, cầu tài, người quen phản, đi nhiều kỵ té).'),(2,2,5,'NGÀY THÌN - Hạp: cầu tài, cầu phước, gặp hung hóa hiền (Kỵ: phép luật, bịnh hoạn, rầy rà, gái hờn chồng).'),(2,2,6,'NGÀY TỴ - Hạp: văn thơ, đơn từ, nhập học đi đường (Kỵ: đào đất buồn ý, quan sự kỵ té).'),(2,2,7,'NGÀY NGỌ - Hạp: kết hôn, nhiều việc hạp, cầu tiên bà độ (Kỵ: lo nhiều, làm chi phòng thất vọng, bịnh hoạn, thị phi).'),(2,2,8,'NGÀY MÙI - Hạp: (không có) (Kỵ: nghe lời, cướp trộm, can thiệp, hùn hạp, than buồn).'),(2,2,9,'NGÀY THÂN - Hạp: cầu tài, kết hôn, đào đất (Kỵ: nhức mỏi, lo chi phòng thất vọng, trai hờn vợ).'),(2,2,10,'NGÀY DẬU - Hạp: thần linh độ mạng, quới nhơn hộ trợ (Kỵ: đưa tiền ra, cầu tài, người thân phản, buồn phiền, quan sự).'),(2,2,11,'NGÀY TUẤT - Hạp: cầu tài, cầu phước, gặp hung hoá hiền (Kỵ: rầy rà phép luật, khổ tâm lo nhiều, gái hờn chồng).'),(2,2,12,'NGÀY HỢI - Hạp: văn thơ, đơn từ, nhập học, đi đường (Kỵ: đào đất dời dời, kỵ té, quan sự buồn phiền).'),(2,4,1,'NGÀY TÝ - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: pháp luật rầy rà, bịnh hoạn, gái hờn chồng).'),(2,4,2,'NGÀY SỬU - Hạp: có thần linh độ mạng (Kỵ: đi tế, quan sự, đi sông, nghe lời hùn hạp).'),(2,4,3,'NGÀY DẦN - Hạp: mỗi việc hạp ý (Kỵ: bịnh hoạn, trộm cắp, gian tham, phá hoại).'),(2,4,4,'NGÀY MẸO - Hạp: văn thơ, đơn tờ, nhập học (Kỵ: quới nhơn hộ trợ, nghe lời bàn hùn hạp).'),(2,4,5,'NGÀY THÌN - Hạp: cầu tài, cầu phước, kết hôn, gặp hung hóa hiền (Kỵ: nhức mỏi, lo chi phòng thất vọng).'),(2,4,6,'NGÀY TỴ - Hạp: thơ từ, đơn tờ, nhập học, đi đường, quới nhơn hỗ trợ (Kỵ: gian tham, trai hờn vợ, người phản).'),(2,4,7,'NG