INSERT INTO `so27_thangkyhap` VALUES (1,1,'Nam',1,'3, 15, 27, 39, 51, 63, 75, 87','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, cần việc quan có người quới nhơn giúp đỡ.','Có việc đi đường nhiều, hoặc đổi dời chỗ ở, phòng có việc bi ai, hoặc tai nạn, chớ nên đi xa đường; ngừa kẻ tiểu nhơn phản, vợ chồng có việc buồn giận với nhau.'),(1,1,'Nam',2,'4, 16, 28, 40, 52, 64, 76, 88','Làm ăn thạnh vượng, tiền tài 10 phần đặng 8 phần, và có cảnh duyên nợ vấn vương lo tính việc chi cũng đặng sáng suốt, gia đạo đặng sự an vui.','Phòng có động việc quan làng hình phạt, và có tiếng thị phi rầy rà, vợ chồng có việc buồn giận chút ít.'),(1,1,'Nam',3,'5, 17, 29, 41, 53, 65, 77, 89','Làm ăn tiến tài 10 phần đặng 5 phần, lo tính việc chi giữ bực trung là tốt, có việc kỵ đề phòng cũng đặng nhẹ.','Phòng có động việc quan làng, có tiền có hao tốn, kỵ đi sông sâu sóng lớn, giữ mình kẻo bị té.'),(1,1,'Nam',4,'6, 18, 30, 42, 54, 66, 78, 90','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, lo tính việc chi nên đề ý đề phòng, dầu có việc kỵ cũng đặng nhẹ.','Có bệnh đau trong mình không đặng an, phòng trộm cấp hao tài, nên cầu nguyện trời phật.'),(1,1,'Nam',5,'7, 19, 31, 43, 55, 67, 79, 91','Người quyền tước có gặp việc may về chức phận, cầu việc quan có người quới nhơn giúp đỡ.','Chớ nên can thiệp tin cậy người, có việc đi đường, hoặc đổi dời vợ chồng có việc buồn giận hoặc có bệnh đau.'),(1,1,'Nam',6,'8, 20, 32, 44, 56, 68, 80, 92','Làm ăn có gặp dịp may thạnh vượng, tiền tài 10 phần đặng 10 phần.','Có kẻ tranh phản rầy rà, và trong mình nhức mỏi chút ít, trong lòng lo tính nhiều việc.'),(1,1,'Nam',7,'9, 21, 33, 45, 57, 69, 81, 93','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, cần việc quan có người quới nhơn giúp đỡ.','Có việc đi đường nhiều, hoặc đổi dời chỗ ở, phòng có việc bi ai, hoặc tai nạn, vợ chồng có việc buồn giận.'),(1,1,'Nam',8,'10, 22, 34, 46, 58, 70, 82, 94','Làm ăn thạnh vượng, tiền tài 10 phần đặng 7 phần, lo tính việc chi cũng đặng sáng suốt.','Phòng có động việc quan làng, và có tiếng thị phi rầy rà, hoặc trộm cấp mất đồ.'),(1,1,'Nam',9,'11, 23, 35, 47, 59, 71, 83, 95','Làm ăn cẩn thận tiền tài 10 phần đặng 5 phần, có việc kỵ đề phòng cũng đặng nhẹ.','Kỵ đi sông sâu sóng lớn, giữ mình kẻo bị té, của tiền có hao tốn.'),(1,1,'Nam',10,'12, 24, 36, 48, 60, 72, 84, 96','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, lo tính việc chi nên đề ý.','Có bệnh đau trong mình không đặng an, phòng trộm cấp hao tài.'),(1,1,'Nam',11,'1, 13, 25, 37, 49, 61, 73, 85','Làm ăn tự ý cẩn thận tiền tài 10 phần đặng 4 phần, quới nhơn giúp đỡ.','Chớ nên can thiệp tin cậy người, có việc đi đường hoặc đổi dời.'),(1,1,'Nam',12,'2, 14, 26, 38, 50, 62, 74, 86','Làm ăn thạnh vượng tiền tài 10 phần đặng 7 phần, gia đạo đặng sự an vui.','Có việc tranh phản rầy rà, trong lòng lo tính nhiều việc.'),(1,1,'Nu',1,'11, 23, 35, 47, 59, 71, 83, 95','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, cần việc quan có người quới nhơn giúp đỡ.','Có việc đi đường nhiều, hoặc đổi dời chỗ ở, phòng có việc bi ai, hoặc tai nạn, chớ nên đi xa đường; ngừa kẻ tiểu nhơn phản, vợ chồng có việc buồn giận với nhau.'),(1,1,'Nu',2,'10, 22, 34, 46, 58, 70, 82, 94','Làm ăn thạnh vượng, tiền tài 10 phần đặng 8 phần, và có cảnh duyên nợ vấn vương lo tính việc chi cũng đặng sáng suốt, gia đạo đặng sự an vui.','Phòng có động việc quan làng hình phạt, và có tiếng thị phi rầy rà, vợ chồng có việc buồn giận chút ít.'),(1,1,'Nu',3,'9, 21, 33, 45, 57, 69, 81, 93','Làm ăn tiến tài 10 phần đặng 5 phần, lo tính việc chi giữ bực trung là tốt, có việc kỵ đề phòng cũng đặng nhẹ.','Phòng có động việc quan làng, có tiền có hao tốn, kỵ đi sông sâu sóng lớn, giữ mình kẻo bị té.'),(1,1,'Nu',4,'8, 20, 32, 44, 56, 68, 80, 92','Làm ăn cẩn thận tiền tài 10 phần đặng 3 phần, lo tính việc chi nên đề ý đề phòng, dầu có việc kỵ cũng đặng nhẹ.','Có bệnh đau trong mình không đặng an, phòng trộm cấp hao tài, nên cầu nguyện trời phật.'),(1,1,'Nu',5,'7, 19, 31, 43, 55, 67, 79, 91','Người quyền tước có gặp việc may về chức phận, cầu