INSERT INTO `so27_tongquan` VALUES (1,1,'Nam','Hải Trung Kim','Đoán xem số mạng như là,\nGiáp Tý kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nTrung niên phát đạt tiền tài,\nGia đình no đủ thong ngoài đặng an.\nSố ta không đặng vẹn toàn,\nTin người giúp đỡ là đàng vô ân.\nTánh hay lo tính cân phân,\nTánh cao lo thấp ân cần siêng năng.\nBái buôn lỗ miệng khoan hoằn,\nGiận hay nói cộc tánh hằng thông minh.\nSố này đặng chữ hiển vinh,\nCó mạng Quyền tước thân tình người sang.\nLàm ăn lớn việc không toàn,\nBất câu việc nhỏ bình an đắc thành.\nSố này tuổi trẻ xuân xanh,\nĐắng cay một lúc phải đành gian truân.\nCách xa xứ sở trông chừng,\nKhắc hào phu phụ đã từng số ni.\nLương duyên dời đổi vậy thì,\nKhó tròn đôi bạn sầu bi số phần.\nSanh nhằm Thiên Quí giải nhân,\nTánh sáng thanh khiết tự tân nghiệp nghề.\nLo cho huynh đệ nhiều bề,\nAnh em thiếu sức chở hề bỏ qua.\nHay lo hay tính ý ta,\nHọc nhiều biết ít khá mà tài hay.\nTa nên chưởng đức nhiều ngày,\nMai sau ăn hưởng hậu lai an lành.','Tuổi này đặng chữ hiển vinh. Có mạng Quyền tước thân tình người sang. Làm ăn lớn việc không toàn, bất câu việc nhỏ bình an đắc thành. Số này tuổi trẻ xuân xanh, đắng cay một lúc phải đành gian truân. Cách xa xứ sở trông chừng, khắc hào phu phụ đã từng số ni. Lương duyên dời đổi vậy thì, khó tròn đôi bạn sầu bi số phần.'),(1,1,'Nu','Hải Trung Kim','Đoán xem số mạng như là,\nGiáp Tý kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nTrung niên phát đạt tiền tài,\nGia đình no đủ thong ngoài đặng an.\nSố ta không đặng vẹn toàn,\nTin người giúp đỡ là đàng vô ân.\nTánh hay lo tính cân phân,\nTánh cao lo thấp ân cần siêng năng.\nBái buôn lỗ miệng khoan hoằn,\nGiận hay nói cộc tánh hằng thông minh.\nSố này đặng chữ hiển vinh,\nCó mạng Quyền tước thân tình người sang.\nLàm ăn lớn việc không toàn,\nBất câu việc nhỏ bình an đắc thành.\nSố này tuổi trẻ xuân xanh,\nĐắng cay một lúc phải đành gian truân.\nCách xa xứ sở trông chừng,\nKhắc hào phu phụ đã từng số ni.\nLương duyên dời đổi vậy thì,\nKhó tròn đôi bạn sầu bi số phần.\nSanh nhằm Thiên Quí giải nhân,\nTánh sáng thanh khiết tự tân nghiệp nghề.\nLo cho huynh đệ nhiều bề,\nAnh em thiếu sức chở hề bỏ qua.\nHay lo hay tính ý ta,\nHọc nhiều biết ít khá mà tài hay.\nTa nên chưởng đức nhiều ngày,\nMai sau ăn hưởng hậu lai an lành.','Nữ mạng Giáp Tý, thờ bà Cửu Thiên Huyền Nữ độ mạng. Tánh sáng thanh khiết, siêng năng. Số này tuổi trẻ đắng cay, hậu vận phát đạt tiền tài, gia đình no đủ.'),(1,3,'Nam','Đại Khuê Thủy','Đoán xem số mạng như là,\nGiáp Dần mạng Thủy số ta như vầy.\nTuổi Mộc mạng Thủy số nầy hạp rày.\nSớm sanh nạn hạn chẳng may,\nỐm đau kể thác nhọc nhằn khó nuôi.\nNgười lớn con mắt, vẻ vui bề ngoài.\nKhông phần chơi bạn hôm nay,\nNgười quen phận phận, dưới tay phân tình.\nSố ta có nước Triều Đình,\nHoặc là oai võ có danh trong đời.\nLuận xem tiền của đến nay,\nTa làm ra của vậy thời thấy dày.\nLại lòng có tánh bao hao,\nLàm nguyệt phụ mẫu đến sau an phận.\nMẹ cha cách trở nhiều lần,\nKhắc hào cô quả lo toan.\nSố ta trung vận mọi an,\nCửa nhà yên ổn gia đàng ấm no.\nSố trai tài nghệ nhiều pho,\nSố gái duyên nợ âu lo lâu dài.\nHào sanh thình vượng vậy thời,\nSanh đặng nuôi dễ nỗi dời hiển vang.\nĐệ huynh khắc ý hại phần,\nKhông đặng hòa thuận gia đàng lo ên.\nSố ta có nghề nghiệp mới nên,\nGia đình tạo lập vững bền về sau.\nKhá nên tích thiện tâm bảo,\nĐến ngày hậu nhựt đặng hào an khương.','Tuổi này mạng Đại Khuê Thủy. Người có tánh tình bao dung, nhân hậu, vẻ ngoài vui vẻ. Số thông minh, có tài năng nghệ thuật hoặc tay nghề cao, đặng quyền chức trong triều đình. Thuở nhỏ khó nuôi, khắc cha mẹ, cô quả. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Tuy nhiên, duyên nợ trắc trở, vợ chồng hay xung khắc, anh em không hòa thuận. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm tích đức.'),(1,3,'Nu','Đại Khuê Thủy','Đoán xem số mạng như là,\nGiáp Dần mạng Thủy số ta như vầy.\nTuổi Mộc mạng Thủy số nầy hạp rày.\nSớm sanh nạn hạn chẳng may,\nỐm đau kể thác nhọc nhằn khó nuôi.\nNgười lớn con mắt, vẻ vui bề ngoài.\nKhông phần chơi bạn hôm nay,\nNgười quen phận phận, dưới tay phân tình.\nSố ta có nước Triều Đình,\nHoặc là oai võ có danh trong đời.\nLuận xem tiền của đến nay,\nTa làm ra của vậy thời thấy dày.\nLại lòng có tánh bao hao,\nLàm nguyệt phụ mẫu đến sau an phận.\nMẹ cha cách trở nhiều lần,\nKhắc hào cô quả lo toan.\nSố ta trung vận mọi an,\nCửa nhà yên ổn gia đàng ấm no.\nSố trai tài nghệ nhiều pho,\nSố gái duyên nợ âu lo lâu dài.\nHào sanh thình vượng vậy thời,\nSanh đặng nuôi dễ nỗi dời hiển vang.\nĐệ huynh khắc ý hại phần,\nKhông đặng hòa thuận gia đàng lo ên.\nSố ta có nghề nghiệp mới nên,\nGia đình tạo lập vững bền về sau.\nKhá nên tích thiện tâm bảo,\nĐến ngày hậu nhựt đặng hào an khương.','Nữ mạng Giáp Dần, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(1,5,'Nam','Phúc Đăng Hỏa','Đoán xem số mạng như là,\nGiáp Thìn mạng Hỏa số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ bịnh chẳng lành,\nPhải mang trưởng bịnh chịu đành trong thân.\nKhổ khán ý tứ mười phân,\nKhó ngừa tánh nết kẻ cần lòng người.\nGiận ở trong dạ ngoài cười,\nĐến ơn trả oán vẹn mười kế mưu.\nTrong đời xung với sầu ưu,\nThường hay lo tính ít vui trong lòng.\nHào tài ta khó giữ xong,\nTay làm ra của khó gởi xong.\nKhông phần chơi bạn về sau,\nTin hùn giúp đỡ đến sanh phản lòng.\nSố ta nhờ chút phước hồng,\nTay có nghề nghiệp mới mong vững bền.\nHoặc là công chức cũng nên,\nTiểu phuờng ta có đặng dạng ấm thân.\nRảnh rang số đặng hưởng phần,\nÍt ra cực khổ tầm đó là.\nĐệ huynh cốt nhục của ta,\nCũng là no ấm mà khó gần.\nVợ chồng hòa hiệp ai ân,\nTrăm năm tơ tóc trọn bề bền lâu.\nHào con sung túc ngõ hầu,\nCũng là đặng đặng đầu con vinh.\nTa nên tích đức xem kinh,\nHưởng nơi vãng cảnh gia đình an khương.','Tuổi này mạng Phúc Đăng Hỏa. Người có tánh tình thông minh, mưu lược, có tài năng và nghề nghiệp vững vàng. Tuy nhiên, thuở nhỏ hay đau ốm, bị bệnh triền miên. Số tự lập, tay trắng tạo nên cơ nghiệp, không nhờ đặng bạn bè. Vợ chồng hòa thuận, con cái sung túc, gia đạo an vui. Hậu vận đặng giàu sang, hưởng phước an nhàn. Cần tu tâm dưỡng tánh để giữ gìn phước lộc.'),(1,5,'Nu','Phúc Đăng Hỏa','Đoán xem số mạng như là,\nGiáp Thìn mạng Hỏa số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ bịnh chẳng lành,\nPhải mang trưởng bịnh chịu đành trong thân.\nKhổ khán ý tứ mười phân,\nKhó ngừa tánh nết kẻ cần lòng người.\nGiận ở trong dạ ngoài cười,\nĐến ơn trả oán vẹn mười kế mưu.\nTrong đời xung với sầu ưu,\nThường hay lo tính ít vui trong lòng.\nHào tài ta khó giữ xong,\nTay làm ra của khó gởi xong.\nKhông phần chơi bạn về sau,\nTin hùn giúp đỡ đến sanh phản lòng.\nSố ta nhờ chút phước hồng,\nTay có nghề nghiệp mới mong vững bền.\nHoặc là công chức cũng nên,\nTiểu phuờng ta có đặng dạng ấm thân.\nRảnh rang số đặng hưởng phần,\nÍt ra cực khổ tầm đó là.\nĐệ huynh cốt nhục của ta,\nCũng là no ấm mà khó gần.\nVợ chồng hòa hiệp ai ân,\nTrăm năm tơ tóc trọn bề bền lâu.\nHào con sung túc ngõ hầu,\nCũng là đặng đặng đầu con vinh.\nTa nên tích đức xem kinh,\nHưởng nơi vãng cảnh gia đình an khương.','Nữ mạng Giáp Thìn, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi, hậu vận nhờ đức dày mà đặng hưởng phước an nhàn vinh hoa.'),(1,7,'Nam','Sa Trung Kim','Đoán xem số mạng như là,\nGiáp Ngọ Kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nSớm sanh bổn mạng chẳng may,\nTrong mình có bịnh thường hay đau rầy.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt rầy mong sang giàu.\nTa làm ra của biết bao,\nGia đình tạo lập đặng vinh quang.\nSố ta chồng vợ chẳng toàn,\nDời đổi nhà cửa nhiều khi rã phân.\nĐời sau sum hiệp ân cần,\nCũng là khắc ý là phần số ta.\nCơ mưu léo lắt vậy mà,\nChí khí cứng cỏi dám qua mặt người.\nCó duyên đi đứng tốt tươi,\nQuới nhơn trợ giúp cũng xong xong.\nTánh người sau trước chẳng đông,\nVui lòng thương vội buồn lòng ghét mau.\nLòng lo nhiều việc lao xao,\nThấy điều trái ý can vào nói ra.\nLàm ăn người ghét tính ta,\nDầu mà có ghét cũng là không sao.\nCó tay thương mãi về sau,\nĐó là thuận số phước hào đặng nên.\nTu tâm dưỡng tánh cho bền,\nGia đình phát đạt tuổi tên chói ngời.','Tuổi này mạng Sa Trung Kim. Người có tánh tình cứng cỏi, thông minh, linh cảm tốt, có tài mưu lược. Thuở nhỏ hay đau ốm, bịnh hoạn. Số tự lập, tay trắng dựng cơ đồ vinh hiển, có duyên thương mãi. Tuy nhiên duyên nợ trắc trở, vợ chồng hay xung khắc hoặc phải dời đổi nơi ăn chốn ở mới yên. Số đặng quới nhơn trợ giúp nhưng tánh tình nóng nảy cần sửa đổi. Hậu vận giàu sang, gia đạo hưng vượng.'),(1,7,'Nu','Sa Trung Kim','Đoán xem số mạng như là,\nGiáp Ngọ Kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nSớm sanh bổn mạng chẳng may,\nTrong mình có bịnh thường hay đau rầy.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt rầy mong sang giàu.\nTa làm ra của biết bao,\nGia đình tạo lập đặng vinh quang.\nSố ta chồng vợ chẳng toàn,\nDời đổi nhà cửa nhiều khi rã phân.\nĐời sau sum hiệp ân cần,\nCũng là khắc ý là phần số ta.\nCơ mưu léo lắt vậy mà,\nChí khí cứng cỏi dám qua mặt người.\nCó duyên đi đứng tốt tươi,\nQuới nhơn trợ giúp cũng xong xong.\nTánh người sau trước chẳng đông,\nVui lòng thương vội buồn lòng ghét mau.\nLòng lo nhiều việc lao xao,\nThấy điều trái ý can vào nói ra.\nLàm ăn người ghét tính ta,\nDầu mà có ghét cũng là không sao.\nCó tay thương mãi về sau,\nĐó là thuận số phước hào đặng nên.\nTu tâm dưỡng tánh cho bền,\nGia đình phát đạt tuổi tên chói ngời.','Nữ mạng Giáp Ngọ, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình đoan trang, siêng năng lo liệu. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi xứ sở. Hậu vận đặng hưởng phước an nhàn vinh hoa, hưởng lộc tổ tiên.'),(1,9,'Nam','Tuyền Trung Thủy','Đoán xem số mạng như là,\nGiáp Thân mạng Thủy số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người đặng hưởng tu hành,\nÍt khi cực khổ phước lành thảnh thơi.\nMiệng linh nói trước những lời,\nNhững điều hung kiết nói thời chẳng sai.\nSố có quyền tước trong tay,\nGần người sang trọng ý rày mến thương.\nGiữ thân số phận bất lương,\nMột lần tế nặng bị thương tật rày.\nSố ta y lộc tiền tài,\nGia đình no đủ hôm nay an toàn.\nTánh tình hòa thuận tâm khoan,\nÔn nhu mềm mỏng là đàng thiện lương.\nTuổi xanh vận tơ gió sương,\nNgựa nghiêng đôi độ là đường khổ tâm.\nTrung niên vãng cảnh tài lâm,\nLớn tuổi phát đạt của cầm bền lâu.\nKhông phần chơi bạn ngõ hầu,\nTin cậy tử tế đáo đầu phản tâm.\nĐệ huynh cốt nhục tình thâm,\nNghĩa tình ấm lạnh có cầm như không.\nSố trai có khắc con dòng,\nBằng mà số gái phải phòng khắc phu.\nMạng này lớn tuổi đi tu,\nXuất gia đầu Phật ngao du cửa thuyền.\nTa nên tiện tánh tâm kiên,\nNhẹ điều khắc kỵ đặng yên gia đình.','Tuổi này mạng Tuyền Trung Thủy. Người có tánh ôn hòa, mềm mỏng, thông minh và có linh cảm tốt. Thuở nhỏ bôn ba gian nan, một lần té nặng mang tật. Số đặng quới nhơn thương mến, có quyền tước. Tuy nhiên, duyên nợ khắc hào phu thê, anh em lạnh nhạt không nhờ cậy đặng. Hậu vận phát đạt vinh hiển, gia đạo an vui. Cần tu tâm dưỡng tánh để hóa giải hình xung.'),(1,9,'Nu','Tuyền Trung Thủy','Đoán xem số mạng như là,\nGiáp Thân mạng Thủy số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người đặng hưởng tu hành,\nÍt khi cực khổ phước lành thảnh thơi.\nMiệng linh nói trước những lời,\nNhững điều hung kiết nói thời chẳng sai.\nSố có quyền tước trong tay,\nGần người sang trọng ý rày mến thương.\nGiữ thân số phận bất lương,\nMột lần tế nặng bị thương tật rày.\nSố ta y lộc tiền tài,\nGia đình no đủ hôm nay an toàn.\nTánh tình hòa thuận tâm khoan,\nÔn nhu mềm mỏng là đàng thiện lương.\nTuổi xanh vận tơ gió sương,\nNgựa nghiêng đôi độ là đường khổ tâm.\nTrung niên vãng cảnh tài lâm,\nLớn tuổi phát đạt của cầm bền lâu.\nKhông phần chơi bạn ngõ hầu,\nTin cậy tử tế đáo đầu phản tâm.\nĐệ huynh cốt nhục tình thâm,\nNghĩa tình ấm lạnh có cầm như không.\nSố trai có khắc con dòng,\nBằng mà số gái phải phòng khắc phu.\nMạng này lớn tuổi đi tu,\nXuất gia đầu Phật ngao du cửa thuyền.\nTa nên tiện tánh tâm kiên,\nNhẹ điều khắc kỵ đặng yên gia đình.','Nữ mạng Giáp Thân, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, cần kiệm lo toan gia đình. Số này tuổi trẻ vất vả, trung vận gặp quới nhơn trợ giúp, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(1,11,'Nam','Sơn Đầu Hỏa','Đoán xem số mạng như là,\nGiáp Tuất mạng Hỏa số ta như vầy.\nTuổi Thổ mạng Hỏa số nầy,\nSớm sanh có bịnh đủ đầy thuốc thang.\nMặt tròn tánh sáng dung nhan,\nCó duyên đi đứng người toan yêu vì.\nLòng hay lo lắng vậy thì,\nĐêm lo ngày liệu gắn ghi gia đình.\nPhá tối chiếu mạng giữ gìn,\nCó số mất của thình lình chẳng hay.\nTánh người không độc lòng ngay,\nGiận người thì nói giận rày bỏ qua.\nĐời sanh cực khổ số ta,\nDẫu mà có của cũng là khổ tâm.\nTrong tay nghề nghiệp tự tâm,\nTay khéo xảo biến phước lâm lệ tàng.\nKhi nào gặp việc khó toan,\nTrong ngày trong buổi tình càng mau thông.\nDẫu mà có học tốn công,\nHọc nhiều biết ít trong lòng lăng xao.\nVợ chồng hòa hiệp sơ giao,\nTrăm năm tơ tóc tâm bào vầy vui.\nHào con phát đạt Trời xui,\nĐa sanh dị dưỡng dễ nuôi con bầy.\nCủa tiền lộc thực số nầy,\nGiá đàng sung túc đủ đầy vinh quang.\nTánh hay giữ phận ngày đàng,\nKhông chịu nhờ bọn không can việc người.\nTa nên tích đức vẹn mười,\nNgõ hầu phát đạt tốt tươi gia đình.','Tuổi này mạng Sơn Đầu Hỏa, đặng tuổi Thổ tương sanh. Người có tánh tình ngay thẳng, dung nhan sáng sủa, có duyên với người ngoài nhưng tâm hay lo lắng bồn chồn. Thuở nhỏ hay đau ốm. Số tự lập, tay khéo léo, nghề nghiệp vững vàng. Tuy có của nhưng số cực thân, hậu vận mới đặng hưởng vinh hoa, con cái phát đạt.'),(1,11,'Nu','Sơn Đầu Hỏa','Đoán xem số mạng như là,\nGiáp Tuất mạng Hỏa số ta như vầy.\nTuổi Thổ mạng Hỏa số nầy,\nSớm sanh có bịnh đủ đầy thuốc thang.\nMặt tròn tánh sáng dung nhan,\nCó duyên đi đứng người toan yêu vì.\nLòng hay lo lắng vậy thì,\nĐêm lo ngày liệu gắn ghi gia đình.\nPhá tối chiếu mạng giữ gìn,\nCó số mất của thình lình chẳng hay.\nTánh người không độc lòng ngay,\nGiận người thì nói giận rày bỏ qua.\nĐời sanh cực khổ số ta,\nDẫu mà có của cũng là khổ tâm.\nTrong tay nghề nghiệp tự tâm,\nTay khéo xảo biến phước lâm lệ tàng.\nKhi nào gặp việc khó toan,\nTrong ngày trong buổi tình càng mau thông.\nDẫu mà có học tốn công,\nHọc nhiều biết ít trong lòng lăng xao.\nVợ chồng hòa hiệp sơ giao,\nTrăm năm tơ tóc tâm bào vầy vui.\nHào con phát đạt Trời xui,\nĐa sanh dị dưỡng dễ nuôi con bầy.\nCủa tiền lộc thực số nầy,\nGiá đàng sung túc đủ đầy vinh quang.\nTánh hay giữ phận ngày đàng,\nKhông chịu nhờ bọn không can việc người.\nTa nên tích đức vẹn mười,\nNgõ hầu phát đạt tốt tươi gia đình.','Nữ mạng Giáp Tuất, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, siêng năng lo liệu. Số này có tay cầm của, hậu vận đặng gia đạo an vui, hưởng phước đức từ sự tu tâm dưỡng tánh.'),(2,2,'Nam','Hải Trung Kim','Đoán xem số mạng như là,\nẤt Sửu Kim mạng số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nPhước đức chiếu mạng đặng lành,\nCó tay cầm của lộc dành về sau.\nLương duyên cay đắng biết bao,\nKhắc xung chồng vợ dễ nào đặng an.\nTuổi xuân dời đổi đôi phần,\nCảnh gia mình một lo toan gia đình.\nSố ta phải ráng giữ gìn,\nPhạm vào nơi chốn tội tình tù lao.\nKhông phần giúp đỡ quản bao,\nBuổi đầu tử tế đến sau phản lòng.\nNgoại nhơn dưỡng ấy là xong,\nCòn trong thân tộc chẳng mong vui gì.\nBà con lãnh đạm vậy thì,\nSố ta tự lập đặng khi sang giàu.\nCó bịnh chỗ kín khỏi nào,\nPhải mang tiểu tật về sau thọ tường.\nTánh người khảng khái lo lường,\nThấy việc ham học là đường khôn ngoan.\nTuổi Xuân không đặng vẹn toàn,\nCách nơi cha mẹ xa đàn làm ăn.\nỞ nơi xứ cũ khó khăn,\nVương mang tật bệnh lăng xăng tổn tài.\nẤu niên thời vận đắng cay,\nVận niên phát đạt hưởng rày về sau.\nThờ ân bố đức đổi dời,\nNgày sau đặng hưởng phước hào thảnh thơi.','Tuổi này đặng phước đức chiếu mạng. Có tay cầm của, lộc dành về sau. Tuy nhiên lương duyên cay đắng, khắc xung chồng vợ. Số tự lập, tuổi trẻ bôn ba cực khổ, hậu vận mới phát đạt sang giàu. Tánh người khảng khái, hiếu học.'),(2,2,'Nu','Hải Trung Kim','Đoán xem số mạng như là,\nẤt Sửu Kim mạng số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nPhước đức chiếu mạng đặng lành,\nCó tay cầm của lộc dành về sau.\nLương duyên cay đắng biết bao,\nKhắc xung chồng vợ dễ nào đặng an.\nTuổi xuân dời đổi đôi phần,\nCảnh gia mình một lo toan gia đình.\nSố ta phải ráng giữ gìn,\nPhạm vào nơi chốn tội tình tù lao.\nKhông phần giúp đỡ quản bao,\nBuổi đầu tử tế đến sau phản lòng.\nNgoại nhơn dưỡng ấy là xong,\nCòn trong thân tộc chẳng mong vui gì.\nBà con lãnh đạm vậy thì,\nSố ta tự lập đặng khi sang giàu.\nCó bịnh chỗ kín khỏi nào,\nPhải mang tiểu tật về sau thọ tường.\nTánh người khảng khái lo lường,\nThấy việc ham học là đường khôn ngoan.\nTuổi Xuân không đặng vẹn toàn,\nCách nơi cha mẹ xa đàn làm ăn.\nỞ nơi xứ cũ khó khăn,\nVương mang tật bệnh lăng xăng tổn tài.\nẤu niên thời vận đắng cay,\nVận niên phát đạt hưởng rày về sau.\nThờ ân bố đức đổi dời,\nNgày sau đặng hưởng phước hào thảnh thơi.','Nữ mạng Ất Sửu, thờ bà Cửu Thiên Huyền Nữ độ mạng. Số này có tay cầm của, hậu vận giàu sang. Thuở nhỏ gặp nhiều gian nan, đổi dời xứ sở mới làm ăn khá.'),(2,4,'Nam','Đại Khuê Thủy','Đoán xem số mạng như là,\nẤt Mẹo mạng Thủy số ta như vầy.\nTuổi Mộc mạng Thủy số nầy hạp rày.\nNgười mềm mỏng tốt thay,\nKính người trọng người tánh hay giữ gìn.\nBịnh phù chiếu mạng hung tình,\nCó tiểu tật bịnh thân hình thường khi.\nCó duyên đi đứng vậy thì,\nQuới nhơn yêu chuộng người thì thương tình.\nNgười có mưu kế thông minh,\nVăn hay võ biết số duyên nhiều nơi.\nSố ta cửa nhà đổi dời,\nNghiệp nghề tráo chất tay thời mờ mang.\nSố ta có tước quyền ban,\nCông danh chức phận bến bờ vẹn rày.\nĐời sau hiệp an khương trăm năm,\nHữu phước trung vận tương lai gia đình.\nSố này không trọn vẹn toàn,\nTích đức thiện chưởng đức trời ban cảnh già.','Tuổi này mạng Đại Khuê Thủy. Người có tánh tình mềm mỏng, hiền lành, kính trọng người khác. Số thông minh, có tài mưu lược, văn hay võ giỏi. Tuy nhiên, thuở nhỏ hay đau ốm, bị bệnh triền miên. Số phải ly hương lập nghiệp, dời đổi nhà cửa nhiều lần mới thành công. Duyên nợ trắc trở, vợ chồng hay xung khắc. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(2,4,'Nu','Đại Khuê Thủy','Đoán xem số mạng như là,\nẤt Mẹo mạng Thủy số ta như vầy.\nTuổi Mộc mạng Thủy số nầy hạp rày.\nNgười mềm mỏng tốt thay,\nKính người trọng người tánh hay giữ gìn.\nBịnh phù chiếu mạng hung tình,\nCó tiểu tật bịnh thân hình thường khi.\nCó duyên đi đứng vậy thì,\nQuới nhơn yêu chuộng người thì thương tình.\nNgười có mưu kế thông minh,\nVăn hay võ biết số duyên nhiều nơi.\nSố ta cửa nhà đổi dời,\nNghiệp nghề tráo chất tay thời mờ mang.\nSố ta có tước quyền ban,\nCông danh chức phận bến bờ vẹn rày.\nĐời sau hiệp an khương trăm năm,\nHữu phước trung vận tương lai gia đình.\nSố này không trọn vẹn toàn,\nTích đức thiện chưởng đức trời ban cảnh già.','Nữ mạng Ất Mẹo, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(2,6,'Nam','Phúc Đăng Hỏa','Đoán xem số mạng như là,\nẤt Tỵ mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nPhước đức chiếu mạng chẳng may,\nHào tài thạnh vượng có tay cầm tiền.\nTánh ưa trang điểm tự nhiên,\nĂn ở sạch sẽ lòng vui hay thay.\nLòng rộng rộng rãi lại ngay,\nBan đêm giấc mộng thấy bay lừng mình.\nPhu thê không trọn chung tình,\nHiệp tan đôi độ tình lãng xao.\nVợ chồng chẳng đặng vui nào,\nLấy sự nhẫn nại đặng bền dài lâu.\nTù lao số phạm âu sầu,\nPhải phòng hình phạt ngõ hầu một khi.\nThông minh tánh sáng vậy thì,\nThấy việc mau hiểu làm thì khéo khôn.\nNgười chỉ chí khí chẳng bồn chồn,\nKhoa đàn hiển đạt người tôn yêu vì.\nAnh em cách trở vậy thì,\nMột người một xứ để chi đặng gần.\nGia đình dời đổi đôi lần,\nMới là tạo lập đặng phần bền lâu.\nThị phi lời tiếng nhiều câu,\nCứu người không đặng người âu hại thầm.\nĐầu lòng sanh gái khó cầm,\nMuốn mà sanh đặng trai cầm quí thay.\nKhá nên tích đức hậu lai,\nNgày sau đặng hưởng tiền tài thảnh thơi.','Tuổi này mạng Phúc Đăng Hỏa. Người có tánh tình rộng rãi, sạch sẽ, vui vẻ nhưng hay mộng mị, linh tính tốt. Số thông minh, khéo léo, có tài tổ chức và lãnh đạo. Tuy nhiên, duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa nhiều lần mới yên. Có số phạm tù lao, cần đề phòng. Số tự lập, không nhờ đặng anh em. Hào con cái khó nuôi, con trai thì quý. Hậu vận giàu sang, tiền tài phát đạt nhờ tu nhân tích đức.'),(2,6,'Nu','Phúc Đăng Hỏa','Đoán xem số mạng như là,\nẤt Tỵ mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nPhước đức chiếu mạng chẳng may,\nHào tài thạnh vượng có tay cầm tiền.\nTánh ưa trang điểm tự nhiên,\nĂn ở sạch sẽ lòng vui hay thay.\nLòng rộng rộng rãi lại ngay,\nBan đêm giấc mộng thấy bay lừng mình.\nPhu thê không trọn chung tình,\nHiệp tan đôi độ tình lãng xao.\nVợ chồng chẳng đặng vui nào,\nLấy sự nhẫn nại đặng bền dài lâu.\nTù lao số phạm âu sầu,\nPhải phòng hình phạt ngõ hầu một khi.\nThông minh tánh sáng vậy thì,\nThấy việc mau hiểu làm thì khéo khôn.\nNgười chỉ chí khí chẳng bồn chồn,\nKhoa đàn hiển đạt người tôn yêu vì.\nAnh em cách trở vậy thì,\nMột người một xứ để chi đặng gần.\nGia đình dời đổi đôi lần,\nMới là tạo lập đặng phần bền lâu.\nThị phi lời tiếng nhiều câu,\nCứu người không đặng người âu hại thầm.\nĐầu lòng sanh gái khó cầm,\nMuốn mà sanh đặng trai cầm quí thay.\nKhá nên tích đức hậu lai,\nNgày sau đặng hưởng tiền tài thảnh thơi.','Nữ mạng Ất Tỵ, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo liệu gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(2,8,'Nam','Sa Trung Kim','Đoán xem số mạng như là,\nẤt Mùi Kim mạng số ta như vầy.\nTuổi cùng với mạng dặng vầy tương sanh.\nTâm tánh sáng láng khôn lành,\nMặt tròn vui vẻ phước sanh duyên phần.\nBịnh phù chiếu mạng ở thân,\nMình có tiểu bịnh khó khăn dứt rày.\nLòng hay lo tính đêm ngày,\nKhổ tâm tự lự trong ngoài làm ưn.\nTuổi xuân cần kiệm siêng năng,\nCũng là đủ dụng chưa bằng vãng niên.\nNửa đời phát đạt của tiền,\nLớn tuổi an hưởng bình yên cảnh già.\nAnh em thiếu sức đó là,\nAi lo phận nấy khó mà nhờ nhau.\nGia đình dời đổi khỏi nào,\nLập nơi khác xứ khắc hào mẹ cha.\nPhu thê hội hiệp giao hòa,\nLỡ duyên buổi trước sau là đặng nên.\nHào con cũng đặng vững bền,\nCũng là đều đủ tự nên có phần.\nTâm không định trước cân phân,\nThấy thời làm đại không cần tính toan.\nCó duyên đi đứng xa đàng,\nNgười đều tử tế như hàng người quen.\nChiêm bao ngó thấy không hèn,\nNhẹ mình hay bổng qua miền núi sông.\nKhá nên cứu giúp thi công,\nGia đình phát đạt phước hồng thảnh thơi.','Tuổi này mạng Sa Trung Kim. Người có tánh tình sáng láng, hiền lành, gương mặt tròn vui vẻ, hay làm ơn giúp người nhưng dễ bị phụ bạc. Thuở nhỏ khó nuôi, hay có tiểu bệnh khó dứt. Số tự lập, tay trắng tạo nên cơ nghiệp, anh em không nhờ vả đặng. Duyên nợ trắc trở buổi đầu, dời đổi xứ sở mới đặng bền lâu. Hậu vận phát đạt, đặng vinh quang, gia đạo an vui. Cần tích đức thi ân để hưởng phước thảnh thơi.'),(2,8,'Nu','Sa Trung Kim','Đoán xem số mạng như là,\nẤt Mùi Kim mạng số ta như vầy.\nTuổi cùng với mạng dặng vầy tương sanh.\nTâm tánh sáng láng khôn lành,\nMặt tròn vui vẻ phước sanh duyên phần.\nBịnh phù chiếu mạng ở thân,\nMình có tiểu bịnh khó khăn dứt rày.\nLòng hay lo tính đêm ngày,\nKhổ tâm tự lự trong ngoài làm ưn.\nTuổi xuân cần kiệm siêng năng,\nCũng là đủ dụng chưa bằng vãng niên.\nNửa đời phát đạt của tiền,\nLớn tuổi an hưởng bình yên cảnh già.\nAnh em thiếu sức đó là,\nAi lo phận nấy khó mà nhờ nhau.\nGia đình dời đổi khỏi nào,\nLập nơi khác xứ khắc hào mẹ cha.\nPhu thê hội hiệp giao hòa,\nLỡ duyên buổi trước sau là đặng nên.\nHào con cũng đặng vững bền,\nCũng là đều đủ tự nên có phần.\nTâm không định trước cân phân,\nThấy thời làm đại không cần tính toan.\nCó duyên đi đứng xa đàng,\nNgười đều tử tế như hàng người quen.\nChiêm bao ngó thấy không hèn,\nNhẹ mình hay bổng qua miền núi sông.\nKhá nên cứu giúp thi công,\nGia đình phát đạt phước hồng thảnh thơi.','Nữ mạng Ất Mùi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, hay giúp người. Số này tuổi trẻ lận đận duyên nợ, lao tâm khổ trí. Trung vận đặng khá, hậu vận hưởng phước an nhàn, gia đạo hưng vượng.'),(2,10,'Nam','Tuyền Trung Thủy','Đoán xem số mạng như là,\nẤt Dậu mạng Thủy số ta như vầy.\nTuổi Kim mạng Thủy số nầy hạp rày.\nSớm sanh có bịnh chẳng may,\nHoặc cùng với mạng hai đây hạp rày.\nSố người trưởng thọ phước hào sống lâu.\nChí khí cứng cỏi cao sâu,\nVui miệng hay nói chẳng cầu tiền tài.\nVui miệng hay nói cầu tiền tài,\nTrí sáng mau hiểu tài lành tâm linh.\nGia đình tạo lập xong xuôi,\nTiền tài y lộc dù nuôi đủ dùng.\nAnh em tuy có chẳng cùng,\nĐều là thiếu sức khó lòng cậy nương.\nViệc chi ta tự liệu ân,\nTin hùn can thiệp chớ nên việc gì.\nKhông cần chơi bạn số ni,\nVì tánh bằng hữu sau thì buồn than.\nLương duyên vợ chồng toàn,\nĐôi đằng tơ tóc thì bền lâu.\nLàm ăn gặp vận số ta,\nCó duyên gần đặng người vinh,\nHoặc có chức phận trọng tình người sang.\nBà con thân tộc hòa an,\nMến thương thuận thảo vẹn toàn nghĩa ân.\nTánh người cứng cỏi không vân,\nChẳng chịu co uốn là phần nghịch ta.\nĐoán xem số mạng phần qua,\nKhổ tâm nhiều thuở mới là vững nên.\nTu tâm dưỡng tánh cho bền,\nNhẹ điều khắc kỵ đặng nên cửa nhà.','Tuổi này mạng Tuyền Trung Thủy. Người có tánh tình ngay thẳng, cứng cỏi, không ưa xu nịnh. Trí tuệ sáng suốt, có tài linh cảm. Thuở nhỏ hay đau ốm nhưng số đặng trường thọ. Gia đạo yên ổn, đủ ăn đủ mặc. Tuy nhiên số không nhờ đặng bạn bè, hùn hạp dễ sanh buồn than. Hậu vận vinh hiển, đặng người sang trọng kính trọng. Cần tu tâm để giữ vững cơ nghiệp.'),(2,10,'Nu','Tuyền Trung Thủy','Đoán xem số mạng như là,\nẤt Dậu mạng Thủy số ta như vầy.\nTuổi Kim mạng Thủy số nầy hạp rày.\nSớm sanh có bịnh chẳng may,\nHoặc cùng với mạng hai đây hạp rày.\nSố người trưởng thọ phước hào sống lâu.\nChí khí cứng cỏi cao sâu,\nVui miệng hay nói chẳng cầu tiền tài.\nVui miệng hay nói cầu tiền tài,\nTrí sáng mau hiểu tài lành tâm linh.\nGia đình tạo lập xong xuôi,\nTiền tài y lộc dù nuôi đủ dùng.\nAnh em tuy có chẳng cùng,\nĐều là thiếu sức khó lòng cậy nương.\nViệc chi ta tự liệu ân,\nTin hùn can thiệp chớ nên việc gì.\nKhông cần chơi bạn số ni,\nVì tánh bằng hữu sau thì buồn than.\nLương duyên vợ chồng toàn,\nĐôi đằng tơ tóc thì bền lâu.\nLàm ăn gặp vận số ta,\nCó duyên gần đặng người vinh,\nHoặc có chức phận trọng tình người sang.\nBà con thân tộc hòa an,\nMến thương thuận thảo vẹn toàn nghĩa ân.\nTánh người cứng cỏi không vân,\nChẳng chịu co uốn là phần nghịch ta.\nĐoán xem số mạng phần qua,\nKhổ tâm nhiều thuở mới là vững nên.\nTu tâm dưỡng tánh cho bền,\nNhẹ điều khắc kỵ đặng nên cửa nhà.','Nữ mạng Ất Dậu, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình cần kiệm, siêng năng lo toan gia đạo. Số này thuở nhỏ chịu nhiều vất vả, trung vận phát đạt, hậu vận hưởng phước an nhàn vinh hoa.'),(2,12,'Nam','Sơn Đầu Hỏa','Đoán xem số mạng như là,\nẤt Hợi mạng hỏa số ta như vầy.\nTuổi Thủy mạng Hỏa số nầy,\nSớm sanh có bịnh ghẻ chẳng may.\nTrong mình bịnh ghẻ chẳng may,\nHoặc thiếu máu huyết hôm nay thân hình.\nNgười có tánh sáng lình lình,\nChưa tới biết trước ý tình mau thông.\nCó duyên tánh khéo ở lòng,\nNgười lại thầm ghét bất đồng ý ta.\nTuổi nhỏ số khắc mẹ cha,\nHoặc cha cùng mẹ chịu rày gian nan.\nTuổi xuân nhiều việc tai nàn,\nKhắc hào phu phụ không toàn căn duyên.\nLỡ duyên buổi trước ưu phiền,\nĐời sau hội hiệp vẹn tuyền trăm năm.\nTrung niên vãng cảnh tài lâm,\nNửa đời phát đạt cũng cầm thiếu chi.\nThương hay mang tiếng thị phi,\nRa vào miệng lưỡi vậy thì sâm ngôn.\nTánh người dưới trọng trên tôn,\nThiên Thọ chiếu mạng bảo tồn sống lâu.\nSố này con khẩn con cầu,\nMới là nuôi đặng ngõ hầu về sau.\nĐêm nằm giấc mộng chiêm bao,\nThấy thân đặng nhẹ bay mau lừng mình.\nMạng này dễ lập gia đình,\nCó tay cầm của giữ gìn đặng lâu.\nTa nên tích đức rộng sâu,\nLập nên cơ nghiệp ngõ hầu thảnh thơi.','Tuổi này mạng Sơn Đầu Hỏa. Người có tánh sáng suốt, linh cảm tốt, khéo léo trong giao tiếp nhưng cũng hay bị người thầm ghét. Thuở nhỏ khó nuôi, khắc cha mẹ, căn duyên trắc trở phải dời đổi mới yên. Hậu vận phát đạt, tiền tài dư dả, có số trường thọ. Cần tu nhân tích đức để giữ gìn cơ nghiệp.'),(2,12,'Nu','Sơn Đầu Hỏa','Đoán xem số mạng như là,\nẤt Hợi mạng hỏa số ta như vầy.\nTuổi Thủy mạng Hỏa số nầy,\nSớm sanh có bịnh ghẻ chẳng may.\nTrong mình bịnh ghẻ chẳng may,\nHoặc thiếu máu huyết hôm nay thân hình.\nNgười có tánh sáng lình lình,\nChưa tới biết trước ý tình mau thông.\nCó duyên tánh khéo ở lòng,\nNgười lại thầm ghét bất đồng ý ta.\nTuổi nhỏ số khắc mẹ cha,\nHoặc cha cùng mẹ chịu rày gian nan.\nTuổi xuân nhiều việc tai nàn,\nKhắc hào phu phụ không toàn căn duyên.\nLỡ duyên buổi trước ưu phiền,\nĐời sau hội hiệp vẹn tuyền trăm năm.\nTrung niên vãng cảnh tài lâm,\nNửa đời phát đạt cũng cầm thiếu chi.\nThương hay mang tiếng thị phi,\nRa vào miệng lưỡi vậy thì sâm ngôn.\nTánh người dưới trọng trên tôn,\nThiên Thọ chiếu mạng bảo tồn sống lâu.\nSố này con khẩn con cầu,\nMới là nuôi đặng ngõ hầu về sau.\nĐêm nằm giấc mộng chiêm bao,\nThấy thân đặng nhẹ bay mau lừng mình.\nMạng này dễ lập gia đình,\nCó tay cầm của giữ gìn đặng lâu.\nTa nên tích đức rộng sâu,\nLập nên cơ nghiệp ngõ hầu thảnh thơi.','Nữ mạng Ất Hợi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, cần kiệm. Số này tuổi trẻ bôn ba gian khổ, hậu vận đặng hưởng phước an nhàn, gia đạo vinh hiển.'),(3,1,'Nam','Giang Hạ Thủy','Đoán xem số mạng như là,\nBính Tý mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây không toàn.\nĐiều Khách chiếu mạng chẳng an,\nMột lần té nặng phải mang tật rày.\nHoặc là sông giếng hôm nay,\nSông sâu sóng lớn nạn tai phải phòng.\nCủa tiền khó giữ cho xong,\nTay làm ra của khó mong giữ tròn.\nThiếu niên tài lộc hao mòn,\nTrung niên phát đạt lại còn vinh vang.\nSố này tay có quyền ban,\nCùng là chức tước gần hàng quới nhơn.\nĐời sanh thanh khiết không sờn,\nGiận hờn dễ dạ căm hờn nhớ dai.\nMiệng nói nhơn nghĩa ai hay,\nLòng thời lo vẫn lo đài khó phân.\nTo gan lớn mật chẳng cần,\nĐến khi nói cộc không phân trẻ già.\nKhông phần chơi bạn số ta,\nCan thiệp tin cậy việc mà xong đâu.\nPhu thê hội hiệp đáo đầu,\nLỡ duyên buổi trước ngõ hầu đời sau.\nThông minh chí khí phước hào,\nMột đời thanh khiết sang giàu bậc trung.\nLàm ăn những việc không cùng,\nViệc nhỏ nên đặng lớn dùng chẳng xong.\nTa nên tích cực ở lòng,\nMong nhờ an hưởng trong vòng vãng niên.','Tuổi này mạng Giang Hạ Thủy. Tánh tình thanh khiết, thông minh, to gan lớn mật nhưng có phần nóng nảy. Thuở nhỏ bôn ba, tài lộc hao mòn, một phen gặp nạn tai về sông nước hoặc té ngã. Số có tay cầm quyền, chức tước, hậu vận phát đạt giàu sang bậc trung. Duyên nợ trắc trở, phải dời đổi một lần mới yên. Không có phần nhờ bạn bè.'),(3,1,'Nu','Giang Hạ Thủy','Đoán xem số mạng như là,\nBính Tý mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây không toàn.\nĐiều Khách chiếu mạng chẳng an,\nMột lần té nặng phải mang tật rày.\nHoặc là sông giếng hôm nay,\nSông sâu sóng lớn nạn tai phải phòng.\nCủa tiền khó giữ cho xong,\nTay làm ra của khó mong giữ tròn.\nThiếu niên tài lộc hao mòn,\nTrung niên phát đạt lại còn vinh vang.\nSố này tay có quyền ban,\nCùng là chức tước gần hàng quới nhơn.\nĐời sanh thanh khiết không sờn,\nGiận hờn dễ dạ căm hờn nhớ dai.\nMiệng nói nhơn nghĩa ai hay,\nLòng thời lo vẫn lo đài khó phân.\nTo gan lớn mật chẳng cần,\nĐến khi nói cộc không phân trẻ già.\nKhông phần chơi bạn số ta,\nCan thiệp tin cậy việc mà xong đâu.\nPhu thê hội hiệp đáo đầu,\nLỡ duyên buổi trước ngõ hầu đời sau.\nThông minh chí khí phước hào,\nMột đời thanh khiết sang giàu bậc trung.\nLàm ăn những việc không cùng,\nViệc nhỏ nên đặng lớn dùng chẳng xong.\nTa nên tích cực ở lòng,\nMong nhờ an hưởng trong vòng vãng niên.','Nữ mạng Bính Tý, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đảm đang, cần kiệm, lo cho gia đình. Số này tuổi trẻ vất vả, trung vận gặp quới nhơn hỗ trợ mà làm ăn phát đạt, hậu vận hưởng phước thanh nhàn.'),(3,3,'Nam','Lư Trung Hỏa','Đoán xem số mạng như là,\nBính Dần mạng hỏa số ta như vầy.\nTuổi cùng với mạng hay đây khắc rày.\nQuê hương xa cách chẳng may,\nTay khó cầm của tiền tài đầy vơi.\nBôn ba lo tính nhiều nơi,\nLàm thời không định tính thời bỏ qua.\nChớ tin lòng dạ người ta,\nHùn hạp tin cậy việc mà xong đâu.\nVợ chồng cách trở buổi đầu,\nĐời sau hội hiệp ngõ hầu xa phương.\nTự tâm liệu tính lo lường,\nTrung niên tiền của tầm thường bực trung.\nTánh người cứng cỏi không cùng,\nTo gan lớn mật tự tùng một mình.\nCó số gần đặng người Vinh,\nHoặc có quyền tước thân tình người sang.\nĐêm nằm lo tính không an,\nChưn tay đi đứng ngõ toan xa đường.\nPhù trầm số phạm bất lương,\nSông sâu sóng lớn bị thương một lần.\nMạng sanh nhờ có giải Thần,\nRủi thì gặp nạn đặng phần nhẹ qua.\nSố này xa cách mẹ cha,\nCùng là huynh đệ ruột rà phân chia.\nHữu phước thì khỏi lìa chia,\nLàm ăn xa xứ trở về quê hương.\nSố này không trọn kiết tường,\nNên làm Âm chất an khương gia đình.','Số có gần đặng người Vinh, Hoặc có quyền tước thân tình người sang. Đêm nằm lo tính không an, Chưn tay đi đứng ngõ toan xa đường. Số này mạng sanh nhờ có giải Thần, rủi thì gặp nạn đặng phần nhẹ qua. Số xa cách mẹ cha, anh em ruột rà phân chia.'),(3,3,'Nu','Lư Trung Hỏa','Đoán xem số mạng như là,\nBính Dần mạng hỏa số ta như vầy.\nTuổi cùng với mạng hay đây khắc rày.\nQuê hương xa cách chẳng may,\nTay khó cầm của tiền tài đầy vơi.\nBôn ba lo tính nhiều nơi,\nLàm thời không định tính thời bỏ qua.\nChớ tin lòng dạ người ta,\nHùn hạp tin cậy việc mà xong đâu.\nVợ chồng cách trở buổi đầu,\nĐời sau hội hiệp ngõ hầu xa phương.\nTự tâm liệu tính lo lường,\nTrung niên tiền của tầm thường bực trung.\nTánh người cứng cỏi không cùng,\nTo gan lớn mật tự tùng một mình.\nCó số gần đặng người Vinh,\nHoặc có quyền tước thân tình người sang.\nĐêm nằm lo tính không an,\nChưn tay đi đứng ngõ toan xa đường.\nPhù trầm số phạm bất lương,\nSông sâu sóng lớn bị thương một lần.\nMạng sanh nhờ có giải Thần,\nRủi thì gặp nạn đặng phần nhẹ qua.\nSố này xa cách mẹ cha,\nCùng là huynh đệ ruột rà phân chia.\nHữu phước thì khỏi lìa chia,\nLàm ăn xa xứ trở về quê hương.\nSố này không trọn kiết tường,\nNên làm Âm chất an khương gia đình.','Nữ mạng Bính Dần, thờ Bà Chúa Ngọc Nương Nương độ mạng. Số này tánh tình cứng cỏi, to gan lớn mật. Tuổi trẻ bôn ba, lao đao về duyên nợ, hậu vận mới yên ổn phát đạt.'),(3,5,'Nam','Sa Trung Thổ','Đoán xem số mạng như là,\nBính Thìn mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nNgười có mưu kế khôn lành,\nTánh hay gây gắt tung hoành tự tâm.\nGiận ở thời lo trả oán đền ơn.\nSố ta đi đứng nguồn cơn,\nBốn ba nhiều chỗ chi sờn lo toan.\nTính luân duyên nợ ân cần,\nNgười có mưu kế khôn lành,\nTâm tánh hay tự mình.\nMưu lược trong bụng ít tin lòng người.\nVăn Xương chiếu mạng tối tươi,\nSáng hay mau hiểu việc chi thong dong.\nSáng hào con chiếu vợ Châu Trần,\nLương duyên đôi độ hai lần mới nên.\nĐời sau cách xử đặng bền,\nHào con Nam nữ đôi bên bình an.\nĐệ huynh cốt nhục tình thâm,\nĐổi lòng lãnh đạm đền ơn lo toan.\nÔi niên thời vận quanh co,\nNửa đời phát đạt như đò đến nơi.\nLàm ăn tình lớn trong đời,\nĐàn làm quan chức đặng hiển vinh.\nTa nên tích thiện xem kinh,\nMong hưởng hậu vận gia đình an khương.','Tuổi này mạng Sa Trung Thổ. Người có tính thông minh, mưu lược, khéo léo nhưng hay nóng nảy, giận hờn. Số tự lập, tay trắng tạo nên cơ nghiệp, bôn ba nhiều nơi. Duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa mới yên. Hào con cái và anh em đông đúc, hòa thuận. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh. Có số làm quan chức.'),(3,5,'Nu','Sa Trung Thổ','Đoán xem số mạng như là,\nBính Thìn mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nNgười có mưu kế khôn lành,\nTánh hay gây gắt tung hoành tự tâm.\nGiận ở thời lo trả oán đền ơn.\nSố ta đi đứng nguồn cơn,\nBốn ba nhiều chỗ chi sờn lo toan.\nTính luân duyên nợ ân cần,\nNgười có mưu kế khôn lành,\nTâm tánh hay tự mình.\nMưu lược trong bụng ít tin lòng người.\nVăn Xương chiếu mạng tối tươi,\nSáng hay mau hiểu việc chi thong dong.\nSáng hào con chiếu vợ Châu Trần,\nLương duyên đôi độ hai lần mới nên.\nĐời sau cách xử đặng bền,\nHào con Nam nữ đôi bên bình an.\nĐệ huynh cốt nhục tình thâm,\nĐổi lòng lãnh đạm đền ơn lo toan.\nÔi niên thời vận quanh co,\nNửa đời phát đạt như đò đến nơi.\nLàm ăn tình lớn trong đời,\nĐàn làm quan chức đặng hiển vinh.\nTa nên tích thiện xem kinh,\nMong hưởng hậu vận gia đình an khương.','Nữ mạng Bính Thìn, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(3,7,'Nam','Thiên Hà Thủy','Đoán xem số mạng như là,\nBính Ngọ mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSớm sanh có bịnh chẳng may,\nThường khi đau ốm hôm nay trong mình.\nĐời sanh xung khắc buồn tình,\nRầu lo loạn đoạn gia đình quanh năm.\nLạt lòng tánh rộng trong tầm,\nKhông thù ghét oán thù thâm một ai.\nSố có quyền tước trong tay,\nQuới nhơn nhờ giúp đỡ phần lòng.\nHào tài cũng đặng bình thường,\nĐủ ăn đủ mặc gia đường ấm no.\nLiên can chiếu mạng rạng rỡ,\nCầm tiền chiếu mạng rạng rỡ\nTin cậy giúp đỡ lo phần lòng.\nAnh em riêng thất khó đặng đồng,\nĐều riêng gia thất khó đặng đồng.\nVợ chồng cách trở đôi lần,\nĐời sau khắc xứ đặng phần bền lâu.\nTâm linh biết trước đời sau,\nNhững điều hung kiết nói nổi không rày.\nCó nghề hoặc tài nghệ tốt thay,\nHoặc là tiền mãi ấm no tài năng.\nTuổi xuân tiền mãi ấm no tài năng,\nĐến khi vãng cảnh khoe lo gia đình.\nHào con không đặng vẹn toàn,\nĐầu lòng sanh gái số có ít trai.\nTa nên tích đức hậu lai,\nMong nhờ vãng cảnh hưởng rày thảnh thơi.','Tuổi này mạng Thiên Hà Thủy. Tánh tình rộng rãi, ôn hòa, không thù ghét ai nhưng hay lo nghĩ và có linh tính tốt. Thuở nhỏ hay đau ốm, bịnh hoạn. Số đặng quới nhơn trợ giúp, có quyền chức, tài năng hoặc tay nghề khéo léo. Tuy nhiên duyên nợ trắc trở, vợ chồng hay ly tán hoặc dời đổi nhà cửa mới yên. Hào con cái ít, đầu lòng thường là con gái. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(3,7,'Nu','Thiên Hà Thủy','Đoán xem số mạng như là,\nBính Ngọ mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSớm sanh có bịnh chẳng may,\nThường khi đau ốm hôm nay trong mình.\nĐời sanh xung khắc buồn tình,\nRầu lo loạn đoạn gia đình quanh năm.\nLạt lòng tánh rộng trong tầm,\nKhông thù ghét oán thù thâm một ai.\nSố có quyền tước trong tay,\nQuới nhơn nhờ giúp đỡ phần lòng.\nHào tài cũng đặng bình thường,\nĐủ ăn đủ mặc gia đường ấm no.\nLiên can chiếu mạng rạng rỡ,\nCầm tiền chiếu mạng rạng rỡ\nTin cậy giúp đỡ lo phần lòng.\nAnh em riêng thất khó đặng đồng,\nĐều riêng gia thất khó đặng đồng.\nVợ chồng cách trở đôi lần,\nĐời sau khắc xứ đặng phần bền lâu.\nTâm linh biết trước đời sau,\nNhững điều hung kiết nói nổi không rày.\nCó nghề hoặc tài nghệ tốt thay,\nHoặc là tiền mãi ấm no tài năng.\nTuổi xuân tiền mãi ấm no tài năng,\nĐến khi vãng cảnh khoe lo gia đình.\nHào con không đặng vẹn toàn,\nĐầu lòng sanh gái số có ít trai.\nTa nên tích đức hậu lai,\nMong nhờ vãng cảnh hưởng rày thảnh thơi.','Nữ mạng Bính Ngọ, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(3,9,'Nam','Sơn Hạ Hỏa','Đoán xem số mạng như là,\nBính Thân mạng Hỏa số ta như vầy.\nTuổi Kim mạng Hỏa số này khắc rày.\nTánh can đảm lòng ngay, không sợ ai chống kình.\nThái Dương chiếu mạng hiển vinh,\nThấy việc mau hiểu, sáng thông tài tình.\nTay làm của, gia đình phát đạt,\nNhưng nợ duyên, khắc, rẽ, chia xa.\nĐời sau hội hiệp, cửa nhà vinh vang,\nTrung niên phát đạt, sang giàu bực trung.\nLàm ăn nghề nghiệp, không cùng,\nTay nghề khéo léo, bôn ba nhọc nhằn.\nSố ta khắc hại con dòng,\nBằng mà số gái, phòng chồng khắc ly.\nCoi chừng phạm tội tù chi,\nPhòng thân một kiếp, tu trì phước duyên.','Tuổi này mạng Sơn Hạ Hỏa. Người có tánh tình can đảm, ngay thẳng, thông minh sáng suốt. Số có tài nghệ khéo léo, làm ăn phát đạt, tiền của đủ dùng. Tuy nhiên duyên nợ trắc trở, vợ chồng hay khắc khẩu. Số khắc con cái (Nam khắc con, Nữ khắc chồng). Tuổi trẻ vất vả, trung vận mới phát đạt. Cần tu tâm dưỡng tánh để phòng hạn tù lao và giữ gìn gia đạo.'),(3,9,'Nu','Sơn Hạ Hỏa','Đoán xem số mạng như là,\nBính Thân mạng Hỏa số ta như vầy.\nTuổi Kim mạng Hỏa số này khắc rày.\nTánh can đảm lòng ngay, không sợ ai chống kình.\nThái Dương chiếu mạng hiển vinh,\nThấy việc mau hiểu, sáng thông tài tình.\nTay làm của, gia đình phát đạt,\nNhưng nợ duyên, khắc, rẽ, chia xa.\nĐời sau hội hiệp, cửa nhà vinh vang,\nTrung niên phát đạt, sang giàu bực trung.\nLàm ăn nghề nghiệp, không cùng,\nTay nghề khéo léo, bôn ba nhọc nhằn.\nSố ta khắc hại con dòng,\nBằng mà số gái, phòng chồng khắc ly.\nCoi chừng phạm tội tù chi,\nPhòng thân một kiếp, tu trì phước duyên.','Nữ mạng Bính Thân, thờ Cậu Tài, Cậu Quý độ mạng. Tánh tình lanh lợi, đảm đang. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi, hậu vận đặng hưởng an nhàn sung túc.'),(3,11,'Nam','Ốc Thượng Thổ','Đoán xem số mạng như là,\nBính Tuất mạng Thổ số ta như vầy.\nTuổi Thổ mạng Thổ số nầy,\nKhó nuôi thuở nhỏ chẳng lành,\nỐm đau kể thác nhọc nhằn mẹ cha.\nTrầm Phù chiếu mạng cho ta,\nTé sông cùng giếng mây màn phòng âu.\nTánh người khéo léo đuôi đầu,\nVậy việc làm kỹ lưỡng ngõ hầu xứng tâm.\nCủa tiền ta khó giữ cầm,\nSớm vô cửa trước tối tầm cửa sau.\nĐối người tử tế dường nào,\nTrở lòng phản ý biết bao nhiêu lần.\nThiếu tình nhơ mật là phần,\nTánh hiền ý nhắc rõ phân thiện hòa.\nNgười sang yêu chuộng trọng ta,\nKẻ nhỏ đem dạ vậy mà phản tâm.\nHưởng nơi tài nghệ ấm thân đó là,\nNgười có tánh sáng hiểu xa,\nGặp những việc khó tính sau mau thành.\nBổn thân ta khá giữ lành,\nMột lần té nặng chị đành tật thân.\nGia đình dời đổi đôi lần,\nMới là đặng vững tự tâm lập thành.\nLương duyên chồng vợ chẳng lành,\nĐời sau khác xứ tương sanh ở đời.\nThì ân bố đức nhiều nơi,\nHưởng nhờ hậu vận thảnh thơi gia đình.','Tuổi này mạng Ốc Thượng Thổ. Người có tánh tình hiền hòa, khéo léo, làm việc kỹ lưỡng và có tài năng nghệ thuật hoặc tay nghề cao. Thuở nhỏ khó nuôi, hay đau ốm khiến cha mẹ vất vả. Số tự lập, tay trắng dựng cơ đồ, phải dời đổi nhà cửa nhiều lần mới ổn định. Tuy có tài lộc nhưng khó giữ tiền bạc thuở trẻ. Duyên nợ trắc trở, phải dời đổi mới yên. Cần tu tâm dưỡng tánh để hậu vận đặng hưởng phước an nhàn.'),(3,11,'Nu','Ốc Thượng Thổ','Đoán xem số mạng như là,\nBính Tuất mạng Thổ số ta như vầy.\nTuổi Thổ mạng Thổ số nầy,\nKhó nuôi thuở nhỏ chẳng lành,\nỐm đau kể thác nhọc nhằn mẹ cha.\nTrầm Phù chiếu mạng cho ta,\nTé sông cùng giếng mây màn phòng âu.\nTánh người khéo léo đuôi đầu,\nVậy việc làm kỹ lưỡng ngõ hầu xứng tâm.\nCủa tiền ta khó giữ cầm,\nSớm vô cửa trước tối tầm cửa sau.\nĐối người tử tế dường nào,\nTrở lòng phản ý biết bao nhiêu lần.\nThiếu tình nhơ mật là phần,\nTánh hiền ý nhắc rõ phân thiện hòa.\nNgười sang yêu chuộng trọng ta,\nKẻ nhỏ đem dạ vậy mà phản tâm.\nHưởng nơi tài nghệ ấm thân đó là,\nNgười có tánh sáng hiểu xa,\nGặp những việc khó tính sau mau thành.\nBổn thân ta khá giữ lành,\nMột lần té nặng chị đành tật thân.\nGia đình dời đổi đôi lần,\nMới là đặng vững tự tâm lập thành.\nLương duyên chồng vợ chẳng lành,\nĐời sau khác xứ tương sanh ở đời.\nThì ân bố đức nhiều nơi,\nHưởng nhờ hậu vận thảnh thơi gia đình.','Nữ mạng Bính Tuất, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, siêng năng. Số này tuổi trẻ gian nan, nhiều phen dời đổi xứ sở. Trung vận đặng quới nhơn trợ giúp, hậu vận hưởng phước thái bình, gia đạo hưng vượng.'),(4,2,'Nam','Giang Hạ Thủy','Đoán xem số mạng như là,\nĐinh Sửu mạng Thủy số ta như vầy.\nTuổi Thổ mạng Thủy số ta như vầy.\nCó tật bịnh kín có vầy trường sanh.\nThấu Dương chiếu mạng khôn lanh,\nTánh sáng mau hiểu tài lành tâm linh.\nVẻ vui gương diện ý tình,\nChiêm bao thường thấy mẹ mình bay đi.\nLong Thần chiếu mạng phù trì,\nTay làm ra của vậy thì như chơi.\nSố này tạo lập nên đời,\nGia đình phú túc chói ngời thịnh danh.\nCó duyên đặng chữ tam sanh,\nNợ duyên dễ tạo đễ thành nguyệt hoa.\nMột đời khó trọn đó là,\nỞ đặng bền vững đó là phước sanh.\nĐệ huynh cốt nhục chẳng lành,\nNhơn tình ấm lạnh dạ đành lãng xao.\nKhó nuôi con kiến dễ nào,\nTốn hao tiền của phước hào đặng nên.\nSố ở một chỗ không bền,\nĐổi dời khác xứ lập nên gia đình.\nCách nơi cha mẹ dưỡng sinh,\nẤy là thuận số kiết tinh độ rày.\nSố này ít có nạn tai,\nKiết tinh đa chiếu hôm nay vững vàng.\nCó đau máu huyết chẳng an,\nThường khi nhức mỏi hoặc sang ghẻ rầy.\nTa nên Chưởng Đức lâu ngày,\nGia đình an hưởng tiền tài vượng tăng.','Tuổi này mạng Giang Hạ Thủy. Tánh tình sáng suốt, mau hiểu, có tài lành tâm linh. Thuở nhỏ hay có tật bệnh kín. Số này tay làm ra của dễ dàng, gia đình giàu có, tiếng tăm lừng lẫy. Tuy nhiên duyên nợ trắc trở, vợ chồng khó ở bền một đời. Khắc hào anh em và con cái (khó nuôi). Số phải ly hương lập nghiệp mới tốt. Hậu vận vượng phát, gia đạo vinh hiển.'),(4,2,'Nu','Giang Hạ Thủy','Đoán xem số mạng như là,\nĐinh Sửu mạng Thủy số ta như vầy.\nTuổi Thổ mạng Thủy số ta như vầy.\nCó tật bịnh kín có vầy trường sanh.\nThấu Dương chiếu mạng khôn lanh,\nTánh sáng mau hiểu tài lành tâm linh.\nVẻ vui gương diện ý tình,\nChiêm bao thường thấy mẹ mình bay đi.\nLong Thần chiếu mạng phù trì,\nTay làm ra của vậy thì như chơi.\nSố này tạo lập nên đời,\nGia đình phú túc chói ngời thịnh danh.\nCó duyên đặng chữ tam sanh,\nNợ duyên dễ tạo đễ thành nguyệt hoa.\nMột đời khó trọn đó là,\nỞ đặng bền vững đó là phước sanh.\nĐệ huynh cốt nhục chẳng lành,\nNhơn tình ấm lạnh dạ đành lãng xao.\nKhó nuôi con kiến dễ nào,\nTốn hao tiền của phước hào đặng nên.\nSố ở một chỗ không bền,\nĐổi dời khác xứ lập nên gia đình.\nCách nơi cha mẹ dưỡng sinh,\nẤy là thuận số kiết tinh độ rày.\nSố này ít có nạn tai,\nKiết tinh đa chiếu hôm nay vững vàng.\nCó đau máu huyết chẳng an,\nThường khi nhức mỏi hoặc sang ghẻ rầy.\nTa nên Chưởng Đức lâu ngày,\nGia đình an hưởng tiền tài vượng tăng.','Nữ mạng Đinh Sửu, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đảm đang, có tay cầm của. Số này tuổi trẻ bôn ba, hậu vận đặng an nhàn sung túc, hưởng phước đức tổ tiên.'),(4,4,'Nam','Lư Trung Hỏa','Đoán xem số mạng như là,\nĐinh Mẹo mạng hỏa số ta như vầy.\nKhó nuôi thuở nhỏ mạng nầy ốm đau.\nCó số phạm chốn tù lao,\nNên làm Âm chất phước hào đặng qua.\nThị phi sanh tiếng rầy rà,\nThương mang khẩu thiệt sanh ra buồn phiền.\nSố này duyên nợ khó tìm,\nCăn duyên nhiều chở ưu phiền đổi xây.\nKhó nuôi con kiến số nầy,\nHao tốn tiền của còn dày phước phần.\nGia đình tạo lập nhiều lần,\nĐặng nên cơ nghiệp đến gần tuổi cao.\nĐoán rằng thiên phá làm vào,\nDầu của cha mẹ dễ nào cầm lâu.\nĐêm nằm lo tính cao sâu,\nTay làm ra cửa ngõ hầu trông mang.\nMiệng lưỡi lanh lợi sáng thông,\nCó duyên đi đứng phước hồng xứ xa.\nTay chơn mau lẹ ý ta,\nTánh người vui vẻ, miệng mà bải buôi.\nƯa nơi an tịnh lòng vui,\nViệc làm không trọn đầu đuôi việc gì.\nĂn mặc chẳng thiếu số ni,\nCủa tiền thường có vậy thì vào ra.\nĐến khi gặp vận tự ta tạo thành,\nKhá nên tích đức làm lành,\nMong sau phát đạt phước sanh gia đình.','Tánh người vui vẻ, miệng mà bải buôi. Ưa nơi an tịnh lòng vui. Việc làm không trọn đầu đuôi việc gì. Ăn mặc chẳng thiếu số ni, Của tiền thường có vậy thì vào ra. Đến khi gặp vận tự ta tạo thành. Khá nên tích đức làm lành. Mong sau phát đạt phước sanh gia đình.'),(4,4,'Nu','Lư Trung Hỏa','Đoán xem số mạng như là,\nĐinh Mẹo mạng hỏa số ta như vầy.\nKhó nuôi thuở nhỏ mạng nầy ốm đau.\nCó số phạm chốn tù lao,\nNên làm Âm chất phước hào đặng qua.\nThị phi sanh tiếng rầy rà,\nThương mang khẩu thiệt sanh ra buồn phiền.\nSố này duyên nợ khó tìm,\nCăn duyên nhiều chở ưu phiền đổi xây.\nKhó nuôi con kiến số nầy,\nHao tốn tiền của còn dày phước phần.\nGia đình tạo lập nhiều lần,\nĐặng nên cơ nghiệp đến gần tuổi cao.\nĐoán rằng thiên phá làm vào,\nDầu của cha mẹ dễ nào cầm lâu.\nĐêm nằm lo tính cao sâu,\nTay làm ra cửa ngõ hầu trông mang.\nMiệng lưỡi lanh lợi sáng thông,\nCó duyên đi đứng phước hồng xứ xa.\nTay chơn mau lẹ ý ta,\nTánh người vui vẻ, miệng mà bải buôi.\nƯa nơi an tịnh lòng vui,\nViệc làm không trọn đầu đuôi việc gì.\nĂn mặc chẳng thiếu số ni,\nCủa tiền thường có vậy thì vào ra.\nĐến khi gặp vận tự ta tạo thành,\nKhá nên tích đức làm lành,\nMong sau phát đạt phước sanh gia đình.','Nữ mạng Đinh Mẹo, thờ Bà Chúa Ngọc Nương Nương độ mạng. Số này thuở nhỏ khó nuôi, lớn lên lanh lợi, sáng suốt. Căn duyên trắc trở nhiều lần mới đặng an bài. Hậu vận có của ăn của để.'),(4,6,'Nam','Sa Trung Thổ','Đoán xem số mạng như là,\nĐinh Tỵ mạng Thổ số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nTâm linh tánh sáng tài nghệ tâm thông.\nCó duyên duyên trong tầm lòng.\nViệc chi lo tính tâm đồng dễ nưng.\nThiên Cổ chiếu mạng thường từng,\nTrong mình nhức mỏi ghẻ sưng có hoài.\nThị phi tiền tiếng rầy rà,\nMiệng lưỡi người ngược xuôi thường hoài.\nĐời sanh đặng nhẹ nạn tai,\nĐịa giải độ mạng qua rày rủi ro.\nThiên ân bố đức ráng lo,\nNgày sau hưởng ấm an nhàn.','Tuổi này mạng Sa Trung Thổ. Tánh tình thông minh, sáng suốt, có tài nghệ và linh cảm tốt. Số đặng Địa Giải độ mạng nên nhẹ bớt tai nạn. Tuy nhiên, trong mình hay nhức mỏi, có ghẻ sưng. Miệng lưỡi dễ sanh thị phi. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Vợ chồng xung khắc, duyên nợ trắc trở. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm tích đức.'),(4,6,'Nu','Sa Trung Thổ','Đoán xem số mạng như là,\nĐinh Tỵ mạng Thổ số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nTâm linh tánh sáng tài nghệ tâm thông.\nCó duyên duyên trong tầm lòng.\nViệc chi lo tính tâm đồng dễ nưng.\nThiên Cổ chiếu mạng thường từng,\nTrong mình nhức mỏi ghẻ sưng có hoài.\nThị phi tiền tiếng rầy rà,\nMiệng lưỡi người ngược xuôi thường hoài.\nĐời sanh đặng nhẹ nạn tai,\nĐịa giải độ mạng qua rày rủi ro.\nThiên ân bố đức ráng lo,\nNgày sau hưởng ấm an nhàn.','Nữ mạng Đinh Tỵ, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(4,8,'Nam','Thiên Hà Thủy','Đoán xem số mạng như là,\nĐinh Mùi mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSanh kế thác chẳng may,\nỐm đau lận đận nạn tai nhiều lần.\nMạng sanh nhở nhỏ có Giải Thần,\nĐỡ che phù hộ đặng phần nhẹ qua.\nTrầm Phù phạm số của ta,\nSông sâu sóng lớn rủi mà thiệt thân.\nLòng nay tin tánh chẳng cần,\nLòng hay lo tính lận đận lấm tầm.\nHào tài ta khó giữ cầm,\nLàm ra có của ta tầm đường hao.\nKhông phần chơi bạn quản bao,\nPhần tính chẳng phân bạn thân quản bao.\nAnh em thân tộc có rằng,\nCách xa làm đặng khó hàng cậy nương.\nVợ chồng cách trở đổi phương,\nĐời sau hiệp an khương lâu dài.\nHào con chậm trễ muộn thay,\nSanh nhiều nuôi ít khó rày đủ đông.\nSố ta nhờ chút phước hồng,\nSố có quyền tước hoặc trong nghiệp nghề.\nGia đình dời đổi nhiều bề,\nChưn đi nhiều chỗ khó hề một nơi.\nKhá nên tích đức ở đời,\nNhẹ điều khắc kỵ thảnh cảnh gia.','Tuổi này mạng Thiên Hà Thủy. Người có tánh tình ngay thẳng, linh cảm tốt nhưng hay lo nghĩ nhiều. Thuở nhỏ khó nuôi, hay đau ốm, bị bệnh triền miên. Số này có Giải Thần độ mạng nên nhẹ bớt tai nạn sông nước. Của tiền khó giữ thuở trẻ. Số tự lập, không nhờ đặng bạn bè và anh em. Duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa mới yên. Hào con cái muộn màng, khó nuôi. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(4,8,'Nu','Thiên Hà Thủy','Đoán xem số mạng như là,\nĐinh Mùi mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSanh kế thác chẳng may,\nỐm đau lận đận nạn tai nhiều lần.\nMạng sanh nhở nhỏ có Giải Thần,\nĐỡ che phù hộ đặng phần nhẹ qua.\nTrầm Phù phạm số của ta,\nSông sâu sóng lớn rủi mà thiệt thân.\nLòng nay tin tánh chẳng cần,\nLòng hay lo tính lận đận lấm tầm.\nHào tài ta khó giữ cầm,\nLàm ra có của ta tầm đường hao.\nKhông phần chơi bạn quản bao,\nPhần tính chẳng phân bạn thân quản bao.\nAnh em thân tộc có rằng,\nCách xa làm đặng khó hàng cậy nương.\nVợ chồng cách trở đổi phương,\nĐời sau hiệp an khương lâu dài.\nHào con chậm trễ muộn thay,\nSanh nhiều nuôi ít khó rày đủ đông.\nSố ta nhờ chút phước hồng,\nSố có quyền tước hoặc trong nghiệp nghề.\nGia đình dời đổi nhiều bề,\nChưn đi nhiều chỗ khó hề một nơi.\nKhá nên tích đức ở đời,\nNhẹ điều khắc kỵ thảnh cảnh gia.','Nữ mạng Đinh Mùi, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(4,10,'Nam','Sơn Hạ Hỏa','Đoán xem số mạng như là,\nĐinh Dậu mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hay đây khắc rầy.\nTánh nhứt hay sợ hôm nay,\nNghe việc động tịnh lo hoài không an.\nTâm linh biết trước rõ ràng,\nHồ nghi thì có đàng chẳng sai.\nThị phi mang tiếng thường hoài,\nNhiều lời tiếng ở ngoài đèm pha.\nTuổi xuân thời vận bôn ba,\nNgựa nghiêng cực nhọc số ta đổi dời.\nNửa đời đặng hưởng thạnh thơi,\nCủa tiền phát đạt vậy thời đặng nên.\nLương duyên trắc trở đôi bên,\nĐời sau hội hiệp vững bền với nhau.\nTánh hay vui vẻ bào hao,\nThương người trọng nghĩa quân bao nhơn tình.\nÝ người cứng cỏi một mình,\nChẳng chịu eo uốn chở bình luận ai.\nHào con không trọn hôm nay,\nSanh ra tưởng thiếu nổi rầy tổn hao.\nThiên Đức chiếu mạng phước hào,\nNhẹ điều tai nạn xâm vào bổn thân.\nNhư phong hình tội một lần,\nHoặc có tiểu bịnh là phần số ta.\nMạng không nghèo khổ vậy mà,\nDầu mà thiên phước cũng là ấm no.\nKhá nên bố đức giúp cho,\nGia đình hạnh phúc bởi do hiền lành.','Tuổi này mạng Sơn Hạ Hỏa. Người có tánh tình ngay thẳng, nhạy cảm, linh tính rất tốt, chưa việc gì tới đã hay nghi ngại. Thuở nhỏ bôn ba vất vả, nhiều phen dời đổi nhà cửa. Số tự lập, không nhờ đặng anh em thân tộc, hậu vận mới đặng giàu sang vinh hiển. Duyên nợ buổi đầu trắc trở, sau mới đặng sum vầy bền vững. Đặng Thiên Đức chiếu mạng nên nhẹ bớt tai nàn, trường thọ. Cần tu tâm dưỡng tánh để giữ gìn phước lộc.'),(4,10,'Nu','Sơn Hạ Hỏa','Đoán xem số mạng như là,\nĐinh Dậu mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hay đây khắc rầy.\nTánh nhứt hay sợ hôm nay,\nNghe việc động tịnh lo hoài không an.\nTâm linh biết trước rõ ràng,\nHồ nghi thì có đàng chẳng sai.\nThị phi mang tiếng thường hoài,\nNhiều lời tiếng ở ngoài đèm pha.\nTuổi xuân thời vận bôn ba,\nNgựa nghiêng cực nhọc số ta đổi dời.\nNửa đời đặng hưởng thạnh thơi,\nCủa tiền phát đạt vậy thời đặng nên.\nLương duyên trắc trở đôi bên,\nĐời sau hội hiệp vững bền với nhau.\nTánh hay vui vẻ bào hao,\nThương người trọng nghĩa quân bao nhơn tình.\nÝ người cứng cỏi một mình,\nChẳng chịu eo uốn chở bình luận ai.\nHào con không trọn hôm nay,\nSanh ra tưởng thiếu nổi rầy tổn hao.\nThiên Đức chiếu mạng phước hào,\nNhẹ điều tai nạn xâm vào bổn thân.\nNhư phong hình tội một lần,\nHoặc có tiểu bịnh là phần số ta.\nMạng không nghèo khổ vậy mà,\nDầu mà thiên phước cũng là ấm no.\nKhá nên bố đức giúp cho,\nGia đình hạnh phúc bởi do hiền lành.','Nữ mạng Đinh Dậu, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình hiền hậu, siêng năng lo toan gia đạo. Số này thuở nhỏ chịu nhiều gian nan, hậu vận đặng hưởng phước an nhàn vinh hoa, gia đạo hưng vượng nhờ phước đức tổ tiên.'),(4,12,'Nam','Ốc Thượng Thổ','Đoán xem số mạng như là,\nĐinh Hợi mạng Thổ số ta như vầy.\nTuổi cùng với mạng hay đây khắc rày.\nBệnh phù chiếu mạng chẳng hay,\nVấn vương bịnh hoạn thường ngày bổn thân.\nTánh người vui vẻ là phần,\nBải buôi trọng đãi nghĩa ân ngọt ngào.\nĐối người tử tế dường nào,\nPhục nơi ngoài mặt tâm bào phản khi.\nCủa tiền y lộc số ni,\nCũng là đặng hưởng vậy thì bực trung.\nQuân bao thời giận không cùng,\nNgửa nghiêng đôi độ thung dung mới là.\nNợ duyên dễ tạo số ta,\nMột đời bền vững rày là khắc nhau.\nThông minh tánh khéo lẹ mau,\nThượng tôn hạ trọng phước hào thiện tâm.\nSố ta hưởng thọ lâu năm,\nTâm thành thiện sự phước lâm an toàn.\nHào con khắc đứa đầu hàng,\nMuộn thời nuôi dễ sớm đặng đầu.\nTự ta tạo lập mới mầu,\nKhó nương nhờ hưởng trong bầu đợi huynh.\nTạo nên cơ nghiệp gia đình,\nKhác xứ cha mẹ kinh dinh cửa nhà.\nKhông gần thân tộc số ta,\nMột mình toan liệu cao xa lỗ lời.\nKhá nên tích thiện ở đời,\nGia đình phong túc hưởng nơi an phần.','Tuổi này mạng Ốc Thượng Thổ. Người có tánh vui vẻ, bải buôi, đối đãi ngọt ngào nhưng cần phòng kẻ phản phúc. Tánh tình sáng suốt, khéo léo, có tâm hướng thiện. Thuở nhỏ hay bệnh hoạn, thiếu máu huyết. Số tự lập, tay trắng dựng cơ nghiệp, phải ly hương mới phát đạt. Vợ chồng bền vững nhưng hay xung khắc ý muốn. Hào con cái muộn màng mới tốt. Hậu vận đặng giàu sang phú túc, trường thọ.'),(4,12,'Nu','Ốc Thượng Thổ','Đoán xem số mạng như là,\nĐinh Hợi mạng Thổ số ta như vầy.\nTuổi cùng với mạng hay đây khắc rày.\nBệnh phù chiếu mạng chẳng hay,\nVấn vương bịnh hoạn thường ngày bổn thân.\nTánh người vui vẻ là phần,\nBải buôi trọng đãi nghĩa ân ngọt ngào.\nĐối người tử tế dường nào,\nPhục nơi ngoài mặt tâm bào phản khi.\nCủa tiền y lộc số ni,\nCũng là đặng hưởng vậy thì bực trung.\nQuân bao thời giận không cùng,\nNgửa nghiêng đôi độ thung dung mới là.\nNợ duyên dễ tạo số ta,\nMột đời bền vững rày là khắc nhau.\nThông minh tánh khéo lẹ mau,\nThượng tôn hạ trọng phước hào thiện tâm.\nSố ta hưởng thọ lâu năm,\nTâm thành thiện sự phước lâm an toàn.\nHào con khắc đứa đầu hàng,\nMuộn thời nuôi dễ sớm đặng đầu.\nTự ta tạo lập mới mầu,\nKhó nương nhờ hưởng trong bầu đợi huynh.\nTạo nên cơ nghiệp gia đình,\nKhác xứ cha mẹ kinh dinh cửa nhà.\nKhông gần thân tộc số ta,\nMột mình toan liệu cao xa lỗ lời.\nKhá nên tích thiện ở đời,\nGia đình phong túc hưởng nơi an phần.','Nữ mạng Đinh Hợi, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình hiền hậu, lo toan gia đình chu tất. Số này tuổi trẻ bôn ba, trung vận đặng quới nhơn trợ giúp, hậu vận hưởng phước an nhàn vinh hoa.'),(5,1,'Nam','Thích Lịch Hỏa','Đoán xem số mạng như là,\nMậu Tý mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nNhất sanh nhất tử chẳng may,\nKế thác thuở nhỏ phước rày đặng qua.\nVận hay dời đổi bôn ba,\nThường hay đi đứng cửa nhà phiêu lưu.\nDầu ta rộng trí sâu mưu,\nCũng là đủ dụng phiền ưu vận thời.\nVợ chồng thay đổi nhiều nơi,\nKhổ tâm chồng vợ tiếng lời không an.\nNgười có mưu kế đa đoan,\nKhó ai qua mặt vững vàng phần đông.\nNgười sang thương mến phước hồng,\nNhơn tính tử tế đối lòng đỡ nâng.\nTiểu nhơn kẻ nhỏ không chừng,\nPhản tâm chọi ý đã từng nhiều khi.\nThông minh tánh sáng vậy thì,\nTánh toán kế chước dễ gì thua ai.\nĐời sanh tay có nghệ tài,\nHứa tài vô mạng khó rày dặng nên.\nHào con không đặng trọn bên,\nSanh đa dưỡng thiếu tự yên lo lường.\nLàm ăn khởi lớn bất tường,\nNhỏ thời nên việc đặng thường bực trung.\nTánh người ngay thẳng chẳng cùng,\nSố nầy nam nữ đều trùng lương duyên.\nTa nên tích đức tám kiên,\nNhẹ điều khắc kỵ vững yên gia đình.','Tuổi này mạng Thích Lịch Hỏa. Tánh tình ngay thẳng, thông minh, mưu mẹo, có tài nghệ khéo léo. Thuở nhỏ khó nuôi, hay đau ốm. Số bôn ba vất vả, thường dời đổi nhà cửa và nơi ăn chốn ở. Duyên nợ trắc trở, vợ chồng hay xung khắc lời qua tiếng lại. Số tự lập, đặng người sang trọng thương mến nhưng phòng kẻ tiểu nhân phản phúc. Hậu vận đặng bình an, hưởng lộc bực trung.'),(5,1,'Nu','Thích Lịch Hỏa','Đoán xem số mạng như là,\nMậu Tý mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rầy.\nNhất sanh nhất tử chẳng may,\nKế thác thuở nhỏ phước rày đặng qua.\nVận hay dời đổi bôn ba,\nThường hay đi đứng cửa nhà phiêu lưu.\nDầu ta rộng trí sâu mưu,\nCũng là đủ dụng phiền ưu vận thời.\nVợ chồng thay đổi nhiều nơi,\nKhổ tâm chồng vợ tiếng lời không an.\nNgười có mưu kế đa đoan,\nKhó ai qua mặt vững vàng phần đông.\nNgười sang thương mến phước hồng,\nNhơn tính tử tế đối lòng đỡ nâng.\nTiểu nhơn kẻ nhỏ không chừng,\nPhản tâm chọi ý đã từng nhiều khi.\nThông minh tánh sáng vậy thì,\nTánh toán kế chước dễ gì thua ai.\nĐời sanh tay có nghệ tài,\nHứa tài vô mạng khó rày dặng nên.\nHào con không đặng trọn bên,\nSanh đa dưỡng thiếu tự yên lo lường.\nLàm ăn khởi lớn bất tường,\nNhỏ thời nên việc đặng thường bực trung.\nTánh người ngay thẳng chẳng cùng,\nSố nầy nam nữ đều trùng lương duyên.\nTa nên tích đức tám kiên,\nNhẹ điều khắc kỵ vững yên gia đình.','Nữ mạng Mậu Tý, thờ Phật Bà Quan Âm độ mạng. Tánh tình đoan trang, cần kiệm lo toan. Số này tuổi trẻ lận đận gian nan, phải chịu nhiều phen dời đổi, hậu vận nhờ tu tâm dưỡng tánh mà đặng hưởng phước vinh hoa gia đạo hưng vượng.'),(5,3,'Nam','Thành Đầu Thổ','Đoán xem số mạng như là,\nMậu Dần mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố này ta có quyền hành,\nNgười sang trọng đãi công danh chói ngời.\nĐi đến xứ khác nơi nơi,\nNói riêng ít tiếng lạ thời như quen.\nTánh người rộng rãi lòng bền,\nToan gan lớn mật sang hèn không phân.\nTâm người không độc giai nhân,\nGiận người không có tánh gần trượng phu.\nTa nên dưỡng tánh tu tâm,\nCủa tiền như thể đèn lu cạn dần.\nGiàu nghèo ta khó lo âu,\nNhiều phen dời đổi sanh sầu số ta,\nPhu thê xung khắc bất hòa,\nĐổi đời duyên nợ gẫm mà đắng cay.\nĐệ huynh cốt nhục chân tay,\nAnh em khác xứ ở rày phương xa.\nKhông nhờ thân tộc khó nương,\nTự tay tạo lập lo lường đặng nên.\nBổn thân ta giữ cho bền,\nMột lần tế nặng chịu nên tật rày.\nHình yếu đuối lại có tài,\nThông minh tánh sáng ai tài khôn lanh.\nHào con ta chẳng đặng lành,\nKhông trông nhờ cậy dạ đành lãng xao.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Tuổi này mạng Thành Đầu Thổ. Tánh tình rộng rãi, gan dạ, có số quyền hành và đặng người sang trọng kính trọng. Số ly hương lập nghiệp mới thành công. Tuy nhiên duyên nợ trắc trở, vợ chồng xung khắc. Số tự lập, không nhờ đặng anh em thân tộc. Hào con cái khó hiển đạt. Cần tu thân tích đức để hậu vận đặng an nhàn.'),(5,3,'Nu','Thành Đầu Thổ','Đoán xem số mạng như là,\nMậu Dần mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố này ta có quyền hành,\nNgười sang trọng đãi công danh chói ngời.\nĐi đến xứ khác nơi nơi,\nNói riêng ít tiếng lạ thời như quen.\nTánh người rộng rãi lòng bền,\nToan gan lớn mật sang hèn không phân.\nTâm người không độc giai nhân,\nGiận người không có tánh gần trượng phu.\nTa nên dưỡng tánh tu tâm,\nCủa tiền như thể đèn lu cạn dần.\nGiàu nghèo ta khó lo âu,\nNhiều phen dời đổi sanh sầu số ta,\nPhu thê xung khắc bất hòa,\nĐổi đời duyên nợ gẫm mà đắng cay.\nĐệ huynh cốt nhục chân tay,\nAnh em khác xứ ở rày phương xa.\nKhông nhờ thân tộc khó nương,\nTự tay tạo lập lo lường đặng nên.\nBổn thân ta giữ cho bền,\nMột lần tế nặng chịu nên tật rày.\nHình yếu đuối lại có tài,\nThông minh tánh sáng ai tài khôn lanh.\nHào con ta chẳng đặng lành,\nKhông trông nhờ cậy dạ đành lãng xao.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Nữ mạng Mậu Dần, thờ Phật Bà Quan Âm độ mạng. Tánh tình ngay thẳng, có chí khí. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi mới ổn định cơ nghiệp. Hậu vận đặng hưởng phước thái bình.'),(5,5,'Nam','Đại Lâm Mộc','Đoán xem số mạng như là,\nMậu Thìn mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ chẳng lành,\nGiải Thần độ mạng phước dành về sau.\nPhù trầm số mạng khởi nào,\nSông sâu sóng lớn phạm vào một phen.\nChớ tin lòng dạ người quen,\nNgày sau trở lại bạc đen phản lòng.\nCủa tiền khó giữ cho xong,\nLàm ra có của chịu vòng tổn hao.\nCông danh có số phước hào,\nCó mạng quyền tước đứng vào công môn.\nVợ chồng xung khắc ngữ ngôn,\nLấy sự nhẫn nại bảo tồn dài lâu.\nĐệ huynh xa cách ngõ hầu,\nThương nhau để dạ có thâm tình.\nTánh người cứng cỏi không tin,\nThánh Thần không tưởng chống kình quỷ ma.\nMiệng Phật lòng rắn đó là,\nĐồ mưu thiết kế cao xa lỗ lời.\nBuổi đầu tính lớn vậy thời,\nĐến sau tính nhỏ đổi dời bỏ qua.\nLàm nơi nói ngã vậy mà,\nXung cha khắc mẹ tự ta lo lường.\nHao tài cũng đặng tầm thường,\nTrung niên tạo lập gia đường hiển vang.\nSố này nên chữ tâm khoan,\nNgõ hầu hưởng đặng phước ban gia đình.','Tuổi này có số mạng quyền tước đứng vào công môn. Tuy nhiên vợ chồng hay xung khắc ngữ ngôn, nên lấy sự nhẫn nại làm đầu. Số phải xa cách anh em, tự thân lập nghiệp. Tánh người cứng cỏi, hậu vận gia đường hiển vang.'),(5,5,'Nu','Đại Lâm Mộc','Đoán xem số mạng như là,\nMậu Thìn mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ chẳng lành,\nGiải Thần độ mạng phước dành về sau.\nPhù trầm số mạng khởi nào,\nSông sâu sóng lớn phạm vào một phen.\nChớ tin lòng dạ người quen,\nNgày sau trở lại bạc đen phản lòng.\nCủa tiền khó giữ cho xong,\nLàm ra có của chịu vòng tổn hao.\nCông danh có số phước hào,\nCó mạng quyền tước đứng vào công môn.\nVợ chồng xung khắc ngữ ngôn,\nLấy sự nhẫn nại bảo tồn dài lâu.\nĐệ huynh xa cách ngõ hầu,\nThương nhau để dạ có thâm tình.\nTánh người cứng cỏi không tin,\nThánh Thần không tưởng chống kình quỷ ma.\nMiệng Phật lòng rắn đó là,\nĐồ mưu thiết kế cao xa lỗ lời.\nBuổi đầu tính lớn vậy thời,\nĐến sau tính nhỏ đổi dời bỏ qua.\nLàm nơi nói ngã vậy mà,\nXung cha khắc mẹ tự ta lo lường.\nHao tài cũng đặng tầm thường,\nTrung niên tạo lập gia đường hiển vang.\nSố này nên chữ tâm khoan,\nNgõ hầu hưởng đặng phước ban gia đình.','Nữ mạng Mậu Thìn, thờ Phật Bà Quan Âm độ mạng. Tánh tình ngay thẳng, có số quyền hành. Thuở nhỏ khó nuôi, lớn lên đặng phước đức giải hạn, gia đình phát đạt về sau.'),(5,7,'Nam','Thiên Thượng Hỏa','Đoán xem số mạng như là,\nMậu Ngọ mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nLòng hay rối rấm lo hoài,\nLo đôn lo đáo ngày ngày bận rộn.\nSố ta kẻ chuộng người khâm,\nNgười đều ưa chuộng duyên phận.\nTâm tánh chánh chiếu bốn thân,\nLao tù số phạm một lần chẳng sai.\nPhù thê xung khắc hôm nay,\nNguyệt quật án ở của ta.\nPhu thê xung khắc hôm nay,\nĐổi đời đổi độ là một phen.\nĐổi đời đổi độ là một phen,\nTánh hay thương dưới kính trên.\nQuân bao rộng rãi tuổi niên,\nPhước đức chiếu mạng tầm tay tiền tài.\nGià khó mà nên đặng hoặc sanh tật rày.\nGiàu nan biến đổi bao ngày,\nGian nan tánh tánh tự tâm.\nTự tay tạo lập phước đặng lành,\nXung khắc cha mẹ cam đành,\nKhó ở gần đặng hoặc sanh tật rày.\nHào con không đặng đủ đông,\nSanh đa dưỡng thiếu tự yên lo lường.\nKhá nên chưởng đức cẩn ngơ,\nTâm tánh hiền lương thuở nhỏ ngày sau.','Tuổi này mạng Thiên Thượng Hỏa. Người có tính hiền lương, tâm tính rộng rãi, được nhiều người yêu mến. Tuy nhiên, đời sống cá nhân hay có nhiều phiền muộn, vợ chồng xung khắc, duyên nợ trắc trở. Số tự lập, tay trắng tạo nên cơ nghiệp, không nhờ đặng cha mẹ. Có số phạm lao lý. Hào con cái ít, khó nuôi. Cần tu tâm dưỡng tánh để hóa giải tai ương và giữ gìn phước lộc.'),(5,7,'Nu','Thiên Thượng Hỏa','Đoán xem số mạng như là,\nMậu Ngọ mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nLòng hay rối rấm lo hoài,\nLo đôn lo đáo ngày ngày bận rộn.\nSố ta kẻ chuộng người khâm,\nNgười đều ưa chuộng duyên phận.\nTâm tánh chánh chiếu bốn thân,\nLao tù số phạm một lần chẳng sai.\nPhù thê xung khắc hôm nay,\nNguyệt quật án ở của ta.\nPhu thê xung khắc hôm nay,\nĐổi đời đổi độ là một phen.\nĐổi đời đổi độ là một phen,\nTánh hay thương dưới kính trên.\nQuân bao rộng rãi tuổi niên,\nPhước đức chiếu mạng tầm tay tiền tài.\nGià khó mà nên đặng hoặc sanh tật rày.\nGiàu nan biến đổi bao ngày,\nGian nan tánh tánh tự tâm.\nTự tay tạo lập phước đặng lành,\nXung khắc cha mẹ cam đành,\nKhó ở gần đặng hoặc sanh tật rày.\nHào con không đặng đủ đông,\nSanh đa dưỡng thiếu tự yên lo lường.\nKhá nên chưởng đức cẩn ngơ,\nTâm tánh hiền lương thuở nhỏ ngày sau.','Nữ mạng Mậu Ngọ, thờ Phật Bà Quan Âm độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(5,9,'Nam','Đại Dịch Thổ','Đoán xem số mạng như là,\nMậu Thân mạng Thổ số ta như vầy.\nTuổi Kim mạng Thổ số nầy,\nTánh ưa kiến điền lòng lành,\nSố cơ mưu khéo léo nói lời lòng.\nTâm linh biết trước trong vòng kiết hung.\nViệc làm mau lẹ không cùng,\nMỗi lời cay đắng tại tâm khó rày.\nGiận gây gắt tung hoành tự tâm,\nCó số quyền tước trong tay,\nQuới nhơn trong đãi người hay yêu vì.\nĐiều Khách chiếu mạng chẳng may,\nPhải phòng té nặng một khi tật rày.\nTrong mình thường có bị bịnh hoài,\nKhi đau khi đặng chẳng may tật thân.\nVợ chồng xung khắc buồn tình,\nĐổi dời đôi độ gia đình mới an.\nAnh em cách trở xa nhau,\nMột người một xứ gia đàng làm ăn.\nHào tài đủ dụng thương hằng,\nGia đình no ấm không ai rằng bực trung.\nÝ ham làm khó đinh ninh,\nMuốn thời cho gặp, nào nũng bó mau.\nHào con tùy có lao xao,\nĐến ngày hậu nhựt để nào cây nương.\nSố ta không trọn kiết tường,\nXuất gia đầu Phật an khương tuổi già.\nKhá nên tích thiện đó là,\nMong sau an hưởng hậu ta an lành.','Tuổi này mạng Đại Dịch Thổ. Người có tánh tình thông minh, mưu lược, khéo léo, hay làm điều thiện. Thuở nhỏ hay đau ốm, bị bệnh triền miên. Số đặng quới nhơn trợ giúp, có quyền chức. Tuy nhiên, duyên nợ trắc trở, vợ chồng xung khắc hoặc dời đổi nhà cửa mới yên. Số tự lập, không nhờ đặng anh em thân tộc. Hào con cái khó nuôi. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(5,9,'Nu','Đại Dịch Thổ','Đoán xem số mạng như là,\nMậu Thân mạng Thổ số ta như vầy.\nTuổi Kim mạng Thổ số nầy,\nTánh ưa kiến điền lòng lành,\nSố cơ mưu khéo léo nói lời lòng.\nTâm linh biết trước trong vòng kiết hung.\nViệc làm mau lẹ không cùng,\nMỗi lời cay đắng tại tâm khó rày.\nGiận gây gắt tung hoành tự tâm,\nCó số quyền tước trong tay,\nQuới nhơn trong đãi người hay yêu vì.\nĐiều Khách chiếu mạng chẳng may,\nPhải phòng té nặng một khi tật rày.\nTrong mình thường có bị bịnh hoài,\nKhi đau khi đặng chẳng may tật thân.\nVợ chồng xung khắc buồn tình,\nĐổi dời đôi độ gia đình mới an.\nAnh em cách trở xa nhau,\nMột người một xứ gia đàng làm ăn.\nHào tài đủ dụng thương hằng,\nGia đình no ấm không ai rằng bực trung.\nÝ ham làm khó đinh ninh,\nMuốn thời cho gặp, nào nũng bó mau.\nHào con tùy có lao xao,\nĐến ngày hậu nhựt để nào cây nương.\nSố ta không trọn kiết tường,\nXuất gia đầu Phật an khương tuổi già.\nKhá nên tích thiện đó là,\nMong sau an hưởng hậu ta an lành.','Nữ mạng Mậu Thân, thờ Phật Bà Quan Âm độ mạng. Tánh tình đoan trang, hiền hậu, hay làm việc thiện. Số này tuổi trẻ bôn ba gian khổ, trung vận phát đạt tiền tài, hậu vận hưởng phước an nhàn sung túc.'),(5,11,'Nam','Bình Địa Mộc','Đoán xem số mạng như là,\nMậu Tuất mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố ta có quyền hành đặng công danh chói ngời.\nĐi đến xứ khác nơi nơi,\nNói riêng ít tiếng lạ thời như quen.\nTánh người rộng rãi lòng bền,\nToan gan lớn mật sang hèn không phân.\nTâm người không độc giai nhân,\nGiận người không có tánh gần trượng phu.\nTa nên dưỡng tánh tu tâm,\nCủa tiền như thể đèn lu cạn dần.\nGiàu nghèo ta khó lo âu,\nNhiều phen dời đổi sanh sầu số ta.\nPhu thê xung khắc bất hòa,\nĐổi đời duyên nợ gẫm mà đắng cay.\nĐệ huynh cốt nhục chân tay,\nAnh em khác xứ ở rày phương xa.\nKhông nhờ thân tộc khó nương,\nTự tay tạo lập lo lường đặng nên.\nBổn thân ta giữ cho bền,\nMột lần té nặng chịu nên tật rày.\nHình yếu đuối lại có tài,\nThông minh tánh sáng ai tài khôn lanh.\nHào con ta chẳng đặng lành,\nKhông trông nhờ cậy dạ đành lãng xao.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Tuổi này mạng Bình Địa Mộc. Người có tánh tình rộng rãi, gan dạ, có số quyền hành và đặng người sang trọng kính nể. Số ly hương lập nghiệp mới thành công, nói năng khéo léo đi đâu cũng có người mến. Tuy nhiên, duyên nợ trắc trở, vợ chồng hay xung khắc. Số tự lập, không nhờ đặng anh em thân tộc. Hào con cái khó hiển đạt hoặc không nhờ cậy đặng. Cần tu thân tích đức để hậu vận đặng an nhàn, phòng tai nạn té ngã.'),(5,11,'Nu','Bình Địa Mộc','Đoán xem số mạng như là,\nMậu Tuất mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố ta có quyền hành đặng công danh chói ngời.\nĐi đến xứ khác nơi nơi,\nNói riêng ít tiếng lạ thời như quen.\nTánh người rộng rãi lòng bền,\nToan gan lớn mật sang hèn không phân.\nTâm người không độc giai nhân,\nGiận người không có tánh gần trượng phu.\nTa nên dưỡng tánh tu tâm,\nCủa tiền như thể đèn lu cạn dần.\nGiàu nghèo ta khó lo âu,\nNhiều phen dời đổi sanh sầu số ta.\nPhu thê xung khắc bất hòa,\nĐổi đời duyên nợ gẫm mà đắng cay.\nĐệ huynh cốt nhục chân tay,\nAnh em khác xứ ở rày phương xa.\nKhông nhờ thân tộc khó nương,\nTự tay tạo lập lo lường đặng nên.\nBổn thân ta giữ cho bền,\nMột lần té nặng chịu nên tật rày.\nHình yếu đuối lại có tài,\nThông minh tánh sáng ai tài khôn lanh.\nHào con ta chẳng đặng lành,\nKhông trông nhờ cậy dạ đành lãng xao.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Nữ mạng Mậu Tuất, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình đoan trang, siêng năng lo liệu việc nhà chu tất. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi, hậu vận nhờ đức dày mà đặng hưởng phước an nhàn vinh hoa.'),(6,2,'Nam','Thích Lịch Hỏa','Đoán xem số mạng như là,\nKỷ Sửu mạng Hỏa số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nGương diện sáng láng khôn lanh,\nBổn thân có bịnh thường sanh đau hoài.\nSố ta lộc tiền tài,\nCủa tiền phát đạt ngày rày ấm thân.\nĐời sanh ta ít khổ thân,\nTự nhiên lo đủ ngày ngày thảnh thơi.\nNgao du vui vẻ ăn chơi,\nNgười không khổ trí trong đời rảnh rang.\nSố này tay có quyền ban,\nCông danh chức phận người sang yêu vì.\nKhông phần chơi bạn số ni,\nTin phần can thiệp dễ khi đặng tròn.\nĐối người trọng hậu lòng son,\nNgày sau trở mặt lại còn phản tâm.\nThan lộc lãnh thảm buồn thầm,\nCùng là huynh đệ khó lòng thờ nhau.\nVợ chồng cách trở đôi phương,\nĐời sau hội hiệp an khương lâu dài.\nHào con chậm trễ muộn thay,\nSanh nhiều nuôi ít khó rày đủ đông.\nSố ta nhờ chút phước hồng,\nSố có quyền tước hoặc trong nghiệp nghề.\nSố này dời đổi nhiều bề,\nCủa tiền tài nghệ trong lòng bàn tay.\nSố ta dời đổi cửa nhà đôi phen,\nTích thiện bố đức lòng bền,\nHưởng ngày hậu nhựt như đèn thêm chư.','Tuổi này mạng Thích Lịch Hỏa. Tánh tình ngay thẳng, sáng suốt, có tài nghệ và mưu trí. Thuở nhỏ hay có bệnh hoạn vương mang. Số đặng người sang trọng yêu vì, có quyền chức hoặc tài nghệ khéo léo giúp lập nên cơ nghiệp. Tuy nhiên duyên nợ trắc trở, phải dời đổi nhà cửa hoặc ly hương mới ổn định. Số không có phần nhờ bạn bè. Hào con cái muộn màng mới tốt. Cảnh già đặng thảnh thơi, phong túc.'),(6,2,'Nu','Thích Lịch Hỏa','Đoán xem số mạng như là,\nKỷ Sửu mạng Hỏa số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nGương diện sáng láng khôn lanh,\nBổn thân có bịnh thường sanh đau hoài.\nSố ta lộc tiền tài,\nCủa tiền phát đạt ngày rày ấm thân.\nĐời sanh ta ít khổ thân,\nTự nhiên lo đủ ngày ngày thảnh thơi.\nNgao du vui vẻ ăn chơi,\nNgười không khổ trí trong đời rảnh rang.\nSố này tay có quyền ban,\nCông danh chức phận người sang yêu vì.\nKhông phần chơi bạn số ni,\nTin phần can thiệp dễ khi đặng tròn.\nĐối người trọng hậu lòng son,\nNgày sau trở mặt lại còn phản tâm.\nThan lộc lãnh thảm buồn thầm,\nCùng là huynh đệ khó lòng thờ nhau.\nVợ chồng cách trở đôi phương,\nĐời sau hội hiệp an khương lâu dài.\nHào con chậm trễ muộn thay,\nSanh nhiều nuôi ít khó rày đủ đông.\nSố ta nhờ chút phước hồng,\nSố có quyền tước hoặc trong nghiệp nghề.\nSố này dời đổi nhiều bề,\nCủa tiền tài nghệ trong lòng bàn tay.\nSố ta dời đổi cửa nhà đôi phen,\nTích thiện bố đức lòng bền,\nHưởng ngày hậu nhựt như đèn thêm chư.','Nữ mạng Kỷ Sửu, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình vui vẻ, hiền hậu, hay làm việc nghĩa. Số này tuổi trẻ bôn ba gian khổ, trung vận phát tài, hậu vận hưởng phước vinh hoa gia đạo hưng vượng.'),(6,6,'Nam','Đại Lâm Mộc','Đoán xem số mạng như là,\nKỷ Tỵ mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ chẳng lành,\nSớm sanh có bệnh đủ đầu thuốc thang.\nĐiếu khách chiếu mạng chẳng an,\nPhải phòng té nặng vương mang tật rày.\nSố này duyên nợ đổi thay,\nCăn duyên nhiều chỗ đắng cay nợ tình.\nĐến khi Loan Phụng hòa minh,\nNếu chưa phước đức đinh ninh ở đời.\nNgười có tánh nhát vậy thời,\nVăn chương ham học trong đời sáng thông.\nTâm linh biết trước ở lòng,\nSố người lại có vào công danh.\nCó tay thương mãi tai lành,\nSố có trâu ruộng lộc dành về sau.\nTính toan lo liệu quản bao,\nViệc làm kỹ lưỡng muốn mau vừa lòng.\nSanh nhằm chữ bịnh long đong,\nHay có bịnh tật nó hằng vấn vương.\nRồi lo rộn trí lại thường,\nTánh cao lo thấp tư tương gia đình.\nThương người trợ giúp đinh ninh,\nKhông phần chơi bạn thâm tình không ơn.\nNgười có chí khí không sờn,\nKhông chịu nhờ bạn để hờn cho ai.\nSố này đầu gái hay trai,\nNên trào thành đức lâu ngày về sau.\nHưởng đặng sự nghiệp sang giàu,\nGia đình yên ổn đặng hào hiển vang.','Tuổi này đặng phước đức chiếu mạng, có tay thương mãi tai lành. Người có tánh hiền lành, ham học, văn chương sáng thông. Số có quyền tước công danh, trâu ruộng lộc dành về sau. Tuy nhiên thuở nhỏ khó nuôi, hay có bịnh tật vấn vương. Số tự lập, không nhờ bạn bè.'),(6,6,'Nu','Đại Lâm Mộc','Đoán xem số mạng như là,\nKỷ Tỵ mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nKhó nuôi thuở nhỏ chẳng lành,\nSớm sanh có bệnh đủ đầu thuốc thang.\nĐiếu khách chiếu mạng chẳng an,\nPhải phòng té nặng vương mang tật rày.\nSố này duyên nợ đổi thay,\nCăn duyên nhiều chỗ đắng cay nợ tình.\nĐến khi Loan Phụng hòa minh,\nNếu chưa phước đức đinh ninh ở đời.\nNgười có tánh nhát vậy thời,\nVăn chương ham học trong đời sáng thông.\nTâm linh biết trước ở lòng,\nSố người lại có vào công danh.\nCó tay thương mãi tai lành,\nSố có trâu ruộng lộc dành về sau.\nTính toan lo liệu quản bao,\nViệc làm kỹ lưỡng muốn mau vừa lòng.\nSanh nhằm chữ bịnh long đong,\nHay có bịnh tật nó hằng vấn vương.\nRồi lo rộn trí lại thường,\nTánh cao lo thấp tư tương gia đình.\nThương người trợ giúp đinh ninh,\nKhông phần chơi bạn thâm tình không ơn.\nNgười có chí khí không sờn,\nKhông chịu nhờ bạn để hờn cho ai.\nSố này đầu gái hay trai,\nNên trào thành đức lâu ngày về sau.\nHưởng đặng sự nghiệp sang giàu,\nGia đình yên ổn đặng hào hiển vang.','Nữ mạng Kỷ Tỵ, thờ Bà Chúa Ngọc Nương Nương độ mạng. Tánh tình hiền hậu, siêng năng. Số này có tay cầm của, hậu vận giàu sang vinh hiển. Thuở nhỏ hay đau ốm, cần cầu nguyện trời phật phù hộ.'),(6,8,'Nam','Thiên Thượng Hỏa','Đoán xem số mạng như là,\nKỷ Mùi mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nNgười có thiện tánh lòng lành,\nThường thương giúp đỡ chẳng đành hại ai.\nBịnh phù chiếu mạng chẳng may,\nThường khi có bịnh ở rày trong thân.\nLòng hay lo tính phần vân,\nRỗi rộn rộng trí ít phần rảnh tầm.\nĐặng phần lo ấm phước lành hưởng nhơn.\nLuận xem duyên nợ đa đoan,\nTơ tính nhiều chỗ hiệp ta đôi lần.\nTánh hay hòa thuận thân nhân,\nYêu chuộng bằng hữu phận phàn nhơn.\nCó số lộc quan chức cũng đặng phần rảnh rang.\nSố ta đời đổi gia đàng,\nKhác xứ cha mẹ vẹn toàn lập nên.\nBà con lãnh đạm đôi bên,\nNghĩa tình lợt lạt tẻ tự yên lo lường.\nViệc làm ý chẳng chu trượng,\nMuốn thời làm đại tánh thường đổi thay.\nMiệng vui lòng chịu việc ngay,\nTánh sáng mau hiểu số rày sống lâu.\nHạn ba mươi sáu lo âu,\nQua khỏi an ngõ hầu bình an.\nThi ân bố đức tám khoan,\nHưởng ngày hậu nhựt gia đàng khương ninh.','Tuổi này mạng Thiên Thượng Hỏa. Tánh tình hiền lành, thiện lương, hay giúp đỡ người khác. Số thông minh, có tài năng và mưu trí. Thuở nhỏ hay đau ốm, bị bệnh triền miên. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa nhiều lần mới yên. Có số làm quan chức. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(6,8,'Nu','Thiên Thượng Hỏa','Đoán xem số mạng như là,\nKỷ Mùi mạng Hỏa số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nNgười có thiện tánh lòng lành,\nThường thương giúp đỡ chẳng đành hại ai.\nBịnh phù chiếu mạng chẳng may,\nThường khi có bịnh ở rày trong thân.\nLòng hay lo tính phần vân,\nRỗi rộn rộng trí ít phần rảnh tầm.\nĐặng phần lo ấm phước lành hưởng nhơn.\nLuận xem duyên nợ đa đoan,\nTơ tính nhiều chỗ hiệp ta đôi lần.\nTánh hay hòa thuận thân nhân,\nYêu chuộng bằng hữu phận phàn nhơn.\nCó số lộc quan chức cũng đặng phần rảnh rang.\nSố ta đời đổi gia đàng,\nKhác xứ cha mẹ vẹn toàn lập nên.\nBà con lãnh đạm đôi bên,\nNghĩa tình lợt lạt tẻ tự yên lo lường.\nViệc làm ý chẳng chu trượng,\nMuốn thời làm đại tánh thường đổi thay.\nMiệng vui lòng chịu việc ngay,\nTánh sáng mau hiểu số rày sống lâu.\nHạn ba mươi sáu lo âu,\nQua khỏi an ngõ hầu bình an.\nThi ân bố đức tám khoan,\nHưởng ngày hậu nhựt gia đàng khương ninh.','Nữ mạng Kỷ Mùi, thờ Phật Bà Quan Âm độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(6,10,'Nam','Đại Dịch Thổ','Đoán xem số mạng như là,\nKỷ Dậu mạng Thổ số ta như vầy.\nTuổi Kim mạng Thổ số nầy,\nThái Dương chiếu mạng khôn lanh,\nThông minh tánh sáng tài lành tâm linh.\nĐịa giải độ mạng an ninh,\nÍt gặp tai nạn thân mình đặng an.\nHào tài làm đặng dễ dàng,\nCủa tiền phát đạt tầm khoanh chẳng chừng.\nTánh cứng cỏi hay tự xưng,\nNgười ghét lỗ miệng chê bợ người.\nTình cao lo thấp vẹn mười,\nThâm thẳm chẳng rảnh khiến người bồn chồn.\nÝ người chịu khó kính tôn,\nThân tộc không cậy đài khỏi một mình.\nGiúp người lại phản phận mình,\nCạnh tranh phối ngẫu chồng vợ trăm năm.\nLương duyên chồng vợ trăm năm,\nKhắc hào khẩu thiệt buồn thầm tỵ nhau.\nTrong mình ít có bị bịnh đau,\nNhưng thường nhức mỏi một sanh trong thân.\nCó tay thương mãi đặng phần,\nSanh tài thuận lợi an cần lập nên.\nSố người trưởng thọ sống bền,\nTài năng lộc kế tự yên lo lường.\nHào con số đặng kiết tường,\nSớm sanh gái an khương con bầy.\nTa nên dưỡng tánh tu tâm,\nMong hưởng vãng cảnh đủ đầy thảnh thơi.','Tuổi này mạng Đại Dịch Thổ. Người có tính thông minh, sáng suốt, có tài năng và mưu trí. Số đặng Địa Giải độ mạng nên ít gặp tai nạn, thân thể an lành. Tuy nhiên, tính tình cứng cỏi, đôi khi tự phụ, dễ gây hiềm khích với người khác. Duyên nợ trắc trở, vợ chồng hay xung khắc lời qua tiếng lại. Số tự lập, không nhờ đặng anh em thân tộc. Hậu vận đặng giàu sang, trường thọ, con cái hiển đạt nhờ tu tâm dưỡng tánh.'),(6,10,'Nu','Đại Dịch Thổ','Đoán xem số mạng như là,\nKỷ Dậu mạng Thổ số ta như vầy.\nTuổi Kim mạng Thổ số nầy,\nThái Dương chiếu mạng khôn lanh,\nThông minh tánh sáng tài lành tâm linh.\nĐịa giải độ mạng an ninh,\nÍt gặp tai nạn thân mình đặng an.\nHào tài làm đặng dễ dàng,\nCủa tiền phát đạt tầm khoanh chẳng chừng.\nTánh cứng cỏi hay tự xưng,\nNgười ghét lỗ miệng chê bợ người.\nTình cao lo thấp vẹn mười,\nThâm thẳm chẳng rảnh khiến người bồn chồn.\nÝ người chịu khó kính tôn,\nThân tộc không cậy đài khỏi một mình.\nGiúp người lại phản phận mình,\nCạnh tranh phối ngẫu chồng vợ trăm năm.\nLương duyên chồng vợ trăm năm,\nKhắc hào khẩu thiệt buồn thầm tỵ nhau.\nTrong mình ít có bị bịnh đau,\nNhưng thường nhức mỏi một sanh trong thân.\nCó tay thương mãi đặng phần,\nSanh tài thuận lợi an cần lập nên.\nSố người trưởng thọ sống bền,\nTài năng lộc kế tự yên lo lường.\nHào con số đặng kiết tường,\nSớm sanh gái an khương con bầy.\nTa nên dưỡng tánh tu tâm,\nMong hưởng vãng cảnh đủ đầy thảnh thơi.','Nữ mạng Kỷ Dậu, thờ Phật Bà Quan Âm độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đạo chu đáo. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi xứ sở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(6,12,'Nam','Bình Địa Mộc','Đoán xem số mạng như là,\nKỷ Hợi mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nXuyên tâm chiếu mạng chẳng may,\nHay lo hay tính thường ngày khổ tâm.\nTánh ý mau lẹ sáng tầm,\nChuộng sợ ăn uống không cần dở ngon.\nChẳng may duyên nợ không tròn,\nĐổi đời xung khắc lại còn khó nương.\nTa nên nhẫn nại nhịn nhường,\nCó số hậu nhựt gia đường chỉ đôi.\nTiền tài y lộc an ngôi,\nẤm thân đủ dụng tài bồi bực trung.\nĐệ huynh thiếu sức không cùng,\nBà con lãnh đạm khó tầm nhờ nhau.\nSố người trường thọ phước hào,\nÔn lương hòa nhã tâm bào hiền lương.\nTánh hay tôn trọng kính nhường,\nKhi buồn khách đến tìm phương vui cười.\nCó tay thương mãi vẹn mười,\nCó lộc mua bán số người đặng nên.\nKhắc hào trưởng tử không bền,\nĐầu lòng sanh gái chẳng hên khắc rầy.\nTam hình chiếu mạng chẳng may,\nPhải phòng tù tội nạn tai một lần.\nLanh lợi khéo léo ân cần,\nCủa tiền lộc thực đặng phần ấm no.\nTích thiện dưỡng tánh khá lo,\nGia đình phát đạt Trời cho hưởng nhờ.','Tuổi này mạng Bình Địa Mộc. Người có tánh tình hiền lương, ôn hòa, khéo léo trong giao tiếp nhưng hay lo nghĩ nhiều. Số phải ly hương lập nghiệp mới thành công. Tuy nhiên, duyên nợ trắc trở, hay có sự xung khắc trong gia đạo. Cần nhẫn nại, đề phòng hạn tù tội. Hậu vận đặng hưởng phước an nhàn, nhờ tài khéo léo và biết tích thiện mà đặng vinh hoa.'),(6,12,'Nu','Bình Địa Mộc','Đoán xem số mạng như là,\nKỷ Hợi mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nXuyên tâm chiếu mạng chẳng may,\nHay lo hay tính thường ngày khổ tâm.\nTánh ý mau lẹ sáng tầm,\nChuộng sợ ăn uống không cần dở ngon.\nChẳng may duyên nợ không tròn,\nĐổi đời xung khắc lại còn khó nương.\nTa nên nhẫn nại nhịn nhường,\nCó số hậu nhựt gia đường chỉ đôi.\nTiền tài y lộc an ngôi,\nẤm thân đủ dụng tài bồi bực trung.\nĐệ huynh thiếu sức không cùng,\nBà con lãnh đạm khó tầm nhờ nhau.\nSố người trường thọ phước hào,\nÔn lương hòa nhã tâm bào hiền lương.\nTánh hay tôn trọng kính nhường,\nKhi buồn khách đến tìm phương vui cười.\nCó tay thương mãi vẹn mười,\nCó lộc mua bán số người đặng nên.\nKhắc hào trưởng tử không bền,\nĐầu lòng sanh gái chẳng hên khắc rầy.\nTam hình chiếu mạng chẳng may,\nPhải phòng tù tội nạn tai một lần.\nLanh lợi khéo léo ân cần,\nCủa tiền lộc thực đặng phần ấm no.\nTích thiện dưỡng tánh khá lo,\nGia đình phát đạt Trời cho hưởng nhờ.','Nữ mạng Kỷ Hợi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo liệu gia đình chu đáo. Số này tuổi trẻ vất vả, trung vận đặng quới nhơn trợ giúp, hậu vận hưởng phước an nhàn.'),(7,1,'Nam','Bích Thượng Thổ','Đoán xem số mạng như là,\nCanh Tý mạng Thổ số ta như vầy.\nTuổi cùng với mạng hạp rày.\nSớm sanh bổn mạng chẳng may,\nKhó nuôi kể thác nạn tai buổi đầu.\nLục xung chiếu mạng âu sầu,\nTánh nóng lo tính ngõ hầu chớ an.\nÝ cứng mạnh người ghét ngang,\nTiểu nhơn phân ý lầm than ngỡ huyền.\nSố ta có tước quyền,\nQuới nhơn trọng đãi có duyên đi đường.\nGia đình đổi chỗ nhiều phương,\nMở mang nhiều chỗ lo lường nhọc tâm.\nTuổi xuân gió rắc sương dầm,\nBơ vơ côi cút lo tầm khổ thân.\nLương duyên số hệ chẳng gần,\nĐời sau khắc đối đôi phần bất hòa.\nĐệ huynh tình nghĩa cách xa,\nKhó nương nhờ cậy số ta tự thành.\nĐời sanh khó nhọc không đành,\nLớn lên đặng hưởng vinh danh ấm no.\nSố người có nghề nghiệp cho,\nTrai thời thương mãi (bán buôn) ấm no sớm chiều.\nSố ta đặng hưởng phước nhiều,\nCố giữ lòng dạ làm điều thiện căn.\nĐến ngày vãng cảnh an thân,\nĐặng hưởng phước lộc thảnh thơi gia đình.','Tuổi này mạng Bích Thượng Thổ. Người có tánh tình ngay thẳng, cứng cỏi, không ưa xu nịnh. Số thông minh, đặng quới nhơn trọng đãi nhưng thuở nhỏ bôn ba vất vả, hay đau ốm. Số ly hương lập nghiệp mới đặng thành công. Vợ chồng buổi đầu xung khắc, anh em thân tộc không nhờ cậy đặng. Hậu vận đặng giàu sang, vinh hiển, hưởng phước an nhàn.'),(7,1,'Nu','Bích Thượng Thổ','Đoán xem số mạng như là,\nCanh Tý mạng Thổ số ta như vầy.\nTuổi cùng với mạng hạp rày.\nSớm sanh bổn mạng chẳng may,\nKhó nuôi kể thác nạn tai buổi đầu.\nLục xung chiếu mạng âu sầu,\nTánh nóng lo tính ngõ hầu chớ an.\nÝ cứng mạnh người ghét ngang,\nTiểu nhơn phân ý lầm than ngỡ huyền.\nSố ta có tước quyền,\nQuới nhơn trọng đãi có duyên đi đường.\nGia đình đổi chỗ nhiều phương,\nMở mang nhiều chỗ lo lường nhọc tâm.\nTuổi xuân gió rắc sương dầm,\nBơ vơ côi cút lo tầm khổ thân.\nLương duyên số hệ chẳng gần,\nĐời sau khắc đối đôi phần bất hòa.\nĐệ huynh tình nghĩa cách xa,\nKhó nương nhờ cậy số ta tự thành.\nĐời sanh khó nhọc không đành,\nLớn lên đặng hưởng vinh danh ấm no.\nSố người có nghề nghiệp cho,\nTrai thời thương mãi (bán buôn) ấm no sớm chiều.\nSố ta đặng hưởng phước nhiều,\nCố giữ lòng dạ làm điều thiện căn.\nĐến ngày vãng cảnh an thân,\nĐặng hưởng phước lộc thảnh thơi gia đình.','Nữ mạng Canh Tý, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, lanh lợi. Số này tuổi trẻ bôn ba, dời đổi xứ sở nhiều lần, hậu vận nhờ đức dày mà đặng hưởng phước an nhàn vinh hiển.'),(7,3,'Nam','Tòng Bá Mộc','Đoán xem số mạng như là,\nCanh Dần mạng Mộc số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nThái Dương chiếu mạng đặng may,\nThông minh tánh sáng thấy rày mau thông.\nSố duyên nơi chốn phần đông,\nNgười sang trọng đãi phước hồng mến thương.\nSố ta xa cách quê hương,\nĐổi dời nhiều chỗ gia đường không an.\nChân tay đi đứng lên đàng,\nLo đôn lo đáo chẳng an trong lòng.\nMiệng hùm gan sứa khó dòng,\nBộ miệng không kín mong dấu rày.\nƯa ai hết của chẳng hay,\nGhét ai hết tiếng chê bai khinh cười.\nPhản phúc vô hậu tánh người,\nTrước thời từ tử buồn cười ngày sau.\nCủa tiền như thể chiêm bao,\nĐủ ăn đủ mặc sớm vào tối ra.\nKhó nhờ cốt nhục số ta,\nMột mình lo liệu vậy mà đặng nên.\nVợ chồng cách trở không bền,\nĐời sau hội hiệp yên nơi gia đình.\nSố người tay có tài tình,\nNghề nghiệp sẵn có trong mình tốt hơn.\nCủa tiền hao hớt nhiều cơn,\nTay làm ra của chi sờn tốn hao.\nTu tâm dưỡng tánh ngày sau,\nNhẹ điều khắc kỵ đặng hào thảnh thơi.','Tuổi này mạng Tòng Bá Mộc. Người có tính thông minh, tánh sáng, đặng quới nhơn trọng đãi. Tuy nhiên số phải ly hương, dời đổi nhiều nơi gia đường mới ổn định. Tánh người ngay thẳng nhưng miệng lưỡi không kín, dễ gây hiềm khích. Số tự lập, không nhờ cậy đặng anh em thân tộc. Duyên nợ trắc trở, phải dời đổi mới yên. Hậu vận đặng hưởng phước thanh nhàn nhờ tài nghệ sẵn có.'),(7,3,'Nu','Tòng Bá Mộc','Đoán xem số mạng như là,\nCanh Dần mạng Mộc số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nThái Dương chiếu mạng đặng may,\nThông minh tánh sáng thấy rày mau thông.\nSố duyên nơi chốn phần đông,\nNgười sang trọng đãi phước hồng mến thương.\nSố ta xa cách quê hương,\nĐổi dời nhiều chỗ gia đường không an.\nChân tay đi đứng lên đàng,\nLo đôn lo đáo chẳng an trong lòng.\nMiệng hùm gan sứa khó dòng,\nBộ miệng không kín mong dấu rày.\nƯa ai hết của chẳng hay,\nGhét ai hết tiếng chê bai khinh cười.\nPhản phúc vô hậu tánh người,\nTrước thời từ tử buồn cười ngày sau.\nCủa tiền như thể chiêm bao,\nĐủ ăn đủ mặc sớm vào tối ra.\nKhó nhờ cốt nhục số ta,\nMột mình lo liệu vậy mà đặng nên.\nVợ chồng cách trở không bền,\nĐời sau hội hiệp yên nơi gia đình.\nSố người tay có tài tình,\nNghề nghiệp sẵn có trong mình tốt hơn.\nCủa tiền hao hớt nhiều cơn,\nTay làm ra của chi sờn tốn hao.\nTu tâm dưỡng tánh ngày sau,\nNhẹ điều khắc kỵ đặng hào thảnh thơi.','Nữ mạng Canh Dần, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình ngay thẳng, siêng năng lo liệu việc nhà. Số này tuổi trẻ bôn ba, nhiều phen thay đổi cơ nghiệp, hậu vận nhờ đức dày mà đặng hưởng an nhàn thái bình.'),(7,5,'Nam','Bạch Lạp Kim','Đoán xem số mạng như là,\nCanh Thìn Kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nBịnh phù chiếu mạng chẳng may,\nThân hình yếu đuối bịnh hoài không an.\nLòng hay lo tính đa đoan,\nTánh người cứng cỏi không tin thần quyền.\nTa mà không sợ chống kình,\nNgười có chí khí ý tình cộc thay.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt giữ gìn trong tay.\nTa làm ra của khó mong giữ tròn,\nThiếu niên tài lộc hao mòn,\nTrung niên phát đạt lại còn sáng thông.\nSố ta tiền của phước hồng,\nĐủ ăn đủ mặc ngõ mong đậu tài.\nGia đình có số đổi thay,\nĐôi lần mới đặng tạo thành gia cư.\nSố ta duyên nợ lỡ làng,\nKhi nào gặp mặt khó yên lòng bền.\nTánh người bền chí lòng nền,\nLàm ăn người ghét bề ngoài vậy thôi.\nChờ ngày trả oán rầy mời an,\nƠn người ra phải cứu mang,\nMong ngày trả nghĩa vẹn toàn mới vui.\nNgười sang trọng đãi bãi buôi,\nCó duyên đi đứng khiến xui thương tình.\nTa nên tích đức giữ gìn,\nBiến hung vi kiết gia đình lập nên.','Tuổi này mạng Bạch Lạp Kim. Tánh tình cứng cỏi, thông minh, linh cảm tốt, chưa tới đã biết trước. Thuở nhỏ thường hay đau ốm, bịnh hoạn. Số tự lập, tay trắng tạo nên cơ nghiệp, nửa đời mới đặng phát đạt. Tuy có của nhưng khó giữ tròn buổi đầu. Duyên nợ trắc trở, phải dời đổi nhà cửa xứ sở mới yên ổn. Cần tu tâm dưỡng tánh để gặp hung hóa kiết.'),(7,5,'Nu','Bạch Lạp Kim','Đoán xem số mạng như là,\nCanh Thìn Kim mạng số ta như vầy.\nTuổi cùng với mạng hai đây hạp rày.\nBịnh phù chiếu mạng chẳng may,\nThân hình yếu đuối bịnh hoài không an.\nLòng hay lo tính đa đoan,\nTánh người cứng cỏi không tin thần quyền.\nTa mà không sợ chống kình,\nNgười có chí khí ý tình cộc thay.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt giữ gìn trong tay.\nTa làm ra của khó mong giữ tròn,\nThiếu niên tài lộc hao mòn,\nTrung niên phát đạt lại còn sáng thông.\nSố ta tiền của phước hồng,\nĐủ ăn đủ mặc ngõ mong đậu tài.\nGia đình có số đổi thay,\nĐôi lần mới đặng tạo thành gia cư.\nSố ta duyên nợ lỡ làng,\nKhi nào gặp mặt khó yên lòng bền.\nTánh người bền chí lòng nền,\nLàm ăn người ghét bề ngoài vậy thôi.\nChờ ngày trả oán rầy mời an,\nƠn người ra phải cứu mang,\nMong ngày trả nghĩa vẹn toàn mới vui.\nNgười sang trọng đãi bãi buôi,\nCó duyên đi đứng khiến xui thương tình.\nTa nên tích đức giữ gìn,\nBiến hung vi kiết gia đình lập nên.','Nữ mạng Canh Thìn, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình ngay thẳng, bền chí. Số này tuổi trẻ vất vả, trung vận đặng quới nhơn hỗ trợ, hậu vận hưởng phước an nhàn, gia đạo phát đạt vinh hiển.'),(7,7,'Nam','Lộ Bàn Thổ','Đoán xem số mạng như là,\nCanh Ngọ mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người đặng có quyền hành,\nNgười sang trọng đặng phước sanh yêu vì.\nTánh người không độc vậy thì,\nGiận người nói dữ chẳng ghi vào lòng.\nTánh ưa hoa nguyệt long đong,\nY toan dâm dục đặng mong vui vầy.\nGia đình có số đổi xây,\nĐôi lần mới đặng dựng gầy lập nên.\nTâm trí lo tính không bền,\nLo đôn lo đáo không nên việc vì ?\nTin người giúp đỡ sau thì phản tâm.\nMạng sanh thiên phước chiếu lâm,\nTâm linh biết trước ngõ tầm sáng thông.\nTánh người rộng rãi khoan hồng,\nRa nơi công chúng phần đông vững vàng.\nCủa tiền lộc thực ban,\nĐủ ăn, đủ mặc đặng an đó là.\nSố này xa cách mẹ cha,\nCùng huynh đệ số ta không gần.\nTự tâm lo liệu ân cần,\nKhông nhờ cốt nhục lại phần khắc nhau.\nVợ chồng đời đổi đời sau,\nMới là sum hiệp cùng nhau ở đời.\nSố nầy nam nữ vậy thời,\nNên làm Âm đức hưởng nơi cảnh già.','Tuổi này đặng phước đức chiếu mạng, có quyền hành. Tánh tình rộng rãi, khoan hồng, tâm trí linh cảm tốt. Tuy nhiên duyên nợ trắc trở, phải dời đổi một lần mới yên. Số tự lập, không nhờ anh em, khắc hào cốt nhục. Hậu vận đủ ăn đủ mặc, gia đạo vững vàng.'),(7,7,'Nu','Lộ Bàn Thổ','Đoán xem số mạng như là,\nCanh Ngọ mạng Thổ số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người đặng có quyền hành,\nNgười sang trọng đặng phước sanh yêu vì.\nTánh người không độc vậy thì,\nGiận người nói dữ chẳng ghi vào lòng.\nTánh ưa hoa nguyệt long đong,\nY toan dâm dục đặng mong vui vầy.\nGia đình có số đổi xây,\nĐôi lần mới đặng dựng gầy lập nên.\nTâm trí lo tính không bền,\nLo đôn lo đáo không nên việc vì ?\nTin người giúp đỡ sau thì phản tâm.\nMạng sanh thiên phước chiếu lâm,\nTâm linh biết trước ngõ tầm sáng thông.\nTánh người rộng rãi khoan hồng,\nRa nơi công chúng phần đông vững vàng.\nCủa tiền lộc thực ban,\nĐủ ăn, đủ mặc đặng an đó là.\nSố này xa cách mẹ cha,\nCùng huynh đệ số ta không gần.\nTự tâm lo liệu ân cần,\nKhông nhờ cốt nhục lại phần khắc nhau.\nVợ chồng đời đổi đời sau,\nMới là sum hiệp cùng nhau ở đời.\nSố nầy nam nữ vậy thời,\nNên làm Âm đức hưởng nơi cảnh già.','Nữ mạng Canh Ngọ, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình ngay thẳng, đảm đang. Số này thuở nhỏ bôn ba, hậu vận đặng an nhàn sung túc. Cần cầu nguyện trời phật phù hộ để đặng nhẹ nghiệp duyên.'),(7,9,'Nam','Thạch Lựu Mộc','Đoán xem số mạng như là,\nCanh Thân mạng Mộc số ta như vầy.\nTuổi Kim mạng Mộc số nầy khắc rầy,\nSớm sanh bổn mạng chẳng may.\nKhó nuôi kể thác nạn tai buổi đầu.\nKhông phần chơi bạn ngõ hầu,\nMuốn làm làm đại ý không ngừa.\nSố này duyên nợ khó tìm,\nCăn duyên nhiều chỗ đắng cay nợ tình.\nĐến khi Loan Phụng hòa minh,\nNếu chưa phước đức đinh ninh ở đời.\nNgười có tánh nhát vậy thời,\nVăn chương ham học trong đời sáng thông.\nTâm linh biết trước ở lòng,\nSố người lại có vào công danh.\nCó tay thương mãi tai lành,\nSố có trâu ruộng lộc dành về sau.\nTính toan lo liệu quản bao,\nViệc làm kỹ lưỡng muốn mau vừa lòng.\nSanh nhằm chữ bịnh long đong,\nHay có bịnh tật nó hằng vấn vương.\nRồi lo rộn trí lại thường,\nTánh cao lo thấp tư tương gia đình.\nThương người trợ giúp đinh ninh,\nKhông phần chơi bạn thâm tình không ơn.\nNgười có chí khí không sờn,\nKhông chịu nhờ bạn để hờn cho ai.\nSố này đầu gái hay trai,\nNên trào thành đức lâu ngày về sau.\nHưởng đặng sự nghiệp sang giàu,\nGia đình yên ổn đặng hào hiển vang.','Tuổi này mạng Thạch Lựu Mộc. Tánh tình cứng cỏi, ngay thẳng, thông minh, linh cảm tốt. Thuở nhỏ khó nuôi, hay đau ốm, bị bệnh triền miên. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Duyên nợ trắc trở, vợ chồng hay xung khắc lời qua tiếng lại. Hào con cái muộn màng, khó nuôi. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(7,9,'Nu','Thạch Lựu Mộc','Đoán xem số mạng như là,\nCanh Thân mạng Mộc số ta như vầy.\nTuổi Kim mạng Mộc số nầy khắc rầy,\nSớm sanh bổn mạng chẳng may.\nKhó nuôi kể thác nạn tai buổi đầu.\nKhông phần chơi bạn ngõ hầu,\nMuốn làm làm đại ý không ngừa.\nSố này duyên nợ khó tìm,\nCăn duyên nhiều chỗ đắng cay nợ tình.\nĐến khi Loan Phụng hòa minh,\nNếu chưa phước đức đinh ninh ở đời.\nNgười có tánh nhát vậy thời,\nVăn chương ham học trong đời sáng thông.\nTâm linh biết trước ở lòng,\nSố người lại có vào công danh.\nCó tay thương mãi tai lành,\nSố có trâu ruộng lộc dành về sau.\nTính toan lo liệu quản bao,\nViệc làm kỹ lưỡng muốn mau vừa lòng.\nSanh nhằm chữ bịnh long đong,\nHay có bịnh tật nó hằng vấn vương.\nRồi lo rộn trí lại thường,\nTánh cao lo thấp tư tương gia đình.\nThương người trợ giúp đinh ninh,\nKhông phần chơi bạn thâm tình không ơn.\nNgười có chí khí không sờn,\nKhông chịu nhờ bạn để hờn cho ai.\nSố này đầu gái hay trai,\nNên trào thành đức lâu ngày về sau.\nHưởng đặng sự nghiệp sang giàu,\nGia đình yên ổn đặng hào hiển vang.','Nữ mạng Canh Thân, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(7,11,'Nam','Ngai Xuyên Kim','Đoán xem số mạng như là,\nCanh Tuất Kim mạng số ta như vầy.\nTuổi Thổ Kim mạng số nầy,\nLòng rộng rộng rãi ưa điều lành.\nHam điều trong lia chẳng may,\nSố phạm té nặng chịu tật thân.\nNơi tâm lo liệu 10 phần,\nHay rầu lo tính số phận nghi suy.\nSố ta dời đổi nhiều bề,\nMuộn sanh mới đặng vậy thì lập nên.\nNên hay rủi phải lo yên,\nKhông nhờ thân tộc đôi bên quản gì.\nSố có nghề nghiệp vậy thì,\nTài năng nghệ thuật bụng suy toan làm.\nNgười ngay thẳng không tham,\nNgười sang trong đãi số làm công môn.\nĐoán hào chồng vợ hiệp hôn,\nTrăm năm tơ tóc kính yêu vẹn mười.\nHào con thạnh vượng vậy thì,\nSanh nhiều đặng số ni con bầy.\nSố ta có lộc làm thầy,\nViệc làm mưu kế trở xoay lẹ làng.\nCó phận gần đặng người sang,\nBốn phương nghề nghiệp sống sanh sẵn sàng.\nSố ta có lộc hưởng hoài,\nHết rồi có nữa khó rày có dư.\nTa nên tích thiện tâm từ,\nĐến ngày vãng cảnh phước hào hưởng hoài.','Tuổi này mạng Ngai Xuyên Kim. Người có tính hiền lành, rộng rãi, thẳng thắn, có tài năng nghệ thuật và mưu trí. Thuở nhỏ bôn ba vất vả, hay đau ốm, cần phòng tai nạn té ngã. Số đặng quới nhơn trợ giúp, có chức phận trong công môn. Tuy nhiên, duyên nợ trắc trở, phải dời đổi nhà cửa hoặc ly hương mới ổn định. Hào con cái và anh em đông đúc, hòa thuận. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm tích đức.'),(7,11,'Nu','Ngai Xuyên Kim','Đoán xem số mạng như là,\nCanh Tuất Kim mạng số ta như vầy.\nTuổi Thổ Kim mạng số nầy,\nLòng rộng rộng rãi ưa điều lành.\nHam điều trong lia chẳng may,\nSố phạm té nặng chịu tật thân.\nNơi tâm lo liệu 10 phần,\nHay rầu lo tính số phận nghi suy.\nSố ta dời đổi nhiều bề,\nMuộn sanh mới đặng vậy thì lập nên.\nNên hay rủi phải lo yên,\nKhông nhờ thân tộc đôi bên quản gì.\nSố có nghề nghiệp vậy thì,\nTài năng nghệ thuật bụng suy toan làm.\nNgười ngay thẳng không tham,\nNgười sang trong đãi số làm công môn.\nĐoán hào chồng vợ hiệp hôn,\nTrăm năm tơ tóc kính yêu vẹn mười.\nHào con thạnh vượng vậy thì,\nSanh nhiều đặng số ni con bầy.\nSố ta có lộc làm thầy,\nViệc làm mưu kế trở xoay lẹ làng.\nCó phận gần đặng người sang,\nBốn phương nghề nghiệp sống sanh sẵn sàng.\nSố ta có lộc hưởng hoài,\nHết rồi có nữa khó rày có dư.\nTa nên tích thiện tâm từ,\nĐến ngày vãng cảnh phước hào hưởng hoài.','Nữ mạng Canh Tuất, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(8,2,'Nam','Bích Thượng Thổ','Đoán xem số mạng như là,\nTân Sửu mạng Thổ số ta như vầy.\nTuổi cùng với mạng hạp rày.\nSớm sanh bổn mạng chẳng may,\nBệnh hoạn kể thác nhọc nhằn nạn tai.\nSố té sông giếng phạm rày,\nPhạm vào một phen chẳng may đâu ngờ.\nChớ tin lòng dạ người thơ,\nGiúp đỡ lại phản biết bao nhiêu lần.\nQuới nhơn trọng đãi ân cần,\nSố có quyền tước trong vòng công danh.\nCủa tiền lộc thực để dành,\nRa vào thường thấy khó thành đặng lâu.\nHào tài đặng ấy bấy lâu,\nNhưng đặng phát đạt bởi cầu phước sanh.\nXem hào huynh đệ không đành,\nĐều là thiếu sức khó thành gia cư.\nGia đình dời đổi ưu tư,\nĐôi lần mới đặng vững từ đến sau.\nTuổi Xuân thời vận lao đao,\nCách xứ cha mẹ mới mau làm ăn.\nCó tiểu tật bệnh trong mình,\nSống lâu phước thọ chói rạng vinh quang.\nCó tay thương mãi lộc sang,\nMua bán cũng đặng Công Hầu cũng nên.\nLương duyên tơ tóc đặng bền,\nĐời sau khắc xứ tương sanh ở đời.\nThi ân bố đức nhiều nơi,\nHưởng nhờ hậu vận vinh quang an khương.','Tuổi này mạng Bích Thượng Thổ. Người có số quyền tước, công danh hiển đạt nhờ phước đức tổ tiên. Tuy nhiên, thuở nhỏ hay đau ốm, gặp nạn tai sông nước. Số phải ly hương lập nghiệp mới thành công, gia đạo hay dời đổi. Anh em thân tộc không nhờ cậy đặng. Có tài thương mãi (buôn bán), hậu vận đặng vinh quang, trường thọ.'),(8,2,'Nu','Bích Thượng Thổ','Đoán xem số mạng như là,\nTân Sửu mạng Thổ số ta như vầy.\nTuổi cùng với mạng hạp rày.\nSớm sanh bổn mạng chẳng may,\nBệnh hoạn kể thác nhọc nhằn nạn tai.\nSố té sông giếng phạm rày,\nPhạm vào một phen chẳng may đâu ngờ.\nChớ tin lòng dạ người thơ,\nGiúp đỡ lại phản biết bao nhiêu lần.\nQuới nhơn trọng đãi ân cần,\nSố có quyền tước trong vòng công danh.\nCủa tiền lộc thực để dành,\nRa vào thường thấy khó thành đặng lâu.\nHào tài đặng ấy bấy lâu,\nNhưng đặng phát đạt bởi cầu phước sanh.\nXem hào huynh đệ không đành,\nĐều là thiếu sức khó thành gia cư.\nGia đình dời đổi ưu tư,\nĐôi lần mới đặng vững từ đến sau.\nTuổi Xuân thời vận lao đao,\nCách xứ cha mẹ mới mau làm ăn.\nCó tiểu tật bệnh trong mình,\nSống lâu phước thọ chói rạng vinh quang.\nCó tay thương mãi lộc sang,\nMua bán cũng đặng Công Hầu cũng nên.\nLương duyên tơ tóc đặng bền,\nĐời sau khắc xứ tương sanh ở đời.\nThi ân bố đức nhiều nơi,\nHưởng nhờ hậu vận vinh quang an khương.','Nữ mạng Tân Sửu, thờ Ông Quan Bình Thánh Tử độ mạng. Tánh tình đoan trang, khéo léo. Số này tuổi trẻ vất vả, trung vận phát đạt, hậu vận đặng an nhàn, vinh hiển.'),(8,4,'Nam','Tòng Bá Mộc','Đoán xem số mạng như là,\nTân Mẹo mạng Mộc số ta như vầy.\nCó duyên vui vẻ tốt thay,\nMặt trời đầm thắm ít hay duyên tà.\nTâm tư thiện tánh ý hòa,\nGiận nói cho biết bỏ qua không hờn.\nSố ta cách trở căn đơn,\nNhiều nơi duyên nợ keo sơn không bền.\nSau dầu có đặng hiệp nên,\nCũng có khắc đôi bên bất hòa.\nTiền tài y lộc số ta,\nCủa tiền phát đạt cửa nhà ấm no.\nNói ngay chẳng chịu nói co,\nNgười có chí khí lòng lo vững vàng.\nThân ta thì đặng rảnh rang,\nTrí ta chẳng rảnh lại càng khổ tâm.\nTự tay lập nghiệp tài lâm,\nBà con thiếu sức khó tầm nhờ nhau.\nCó tài thương mãi phước hào,\nTrai thời có lộc, gái vào nguyệt hoa.\nThương hay sanh tiếng rầy rà,\nPhải phòng hình phạt số ta có rày.\nKhông phần hưởng của gia tài,\nDầu mà có hưởng phá rày tiêu hao.\nNăm canh giấc mộng chiêm bao,\nTưởng tình xuất hiện chạy mau nhẹ mình.\nKhá nên bố đức xem kinh,\nKhương ninh an hưởng gia đình vượng tăng.','Tuổi này mạng Tòng Bá Mộc. Người có tánh tình vui vẻ, hiền hòa, ngay thẳng và có chí khí vững vàng. Thuở nhỏ bôn ba, trí óc hay lo tính cực tâm. Số tự lực cánh sinh, tay trắng lập nên sự nghiệp, không nhờ cậy đặng anh em bà con. Tuy nhiên, duyên nợ trắc trở, vợ chồng hay xung khắc lời nói. Có tài kinh doanh buôn bán. Cần phòng số phạm hình phạt lao lý. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(8,4,'Nu','Tòng Bá Mộc','Đoán xem số mạng như là,\nTân Mẹo mạng Mộc số ta như vầy.\nCó duyên vui vẻ tốt thay,\nMặt trời đầm thắm ít hay duyên tà.\nTâm tư thiện tánh ý hòa,\nGiận nói cho biết bỏ qua không hờn.\nSố ta cách trở căn đơn,\nNhiều nơi duyên nợ keo sơn không bền.\nSau dầu có đặng hiệp nên,\nCũng có khắc đôi bên bất hòa.\nTiền tài y lộc số ta,\nCủa tiền phát đạt cửa nhà ấm no.\nNói ngay chẳng chịu nói co,\nNgười có chí khí lòng lo vững vàng.\nThân ta thì đặng rảnh rang,\nTrí ta chẳng rảnh lại càng khổ tâm.\nTự tay lập nghiệp tài lâm,\nBà con thiếu sức khó tầm nhờ nhau.\nCó tài thương mãi phước hào,\nTrai thời có lộc, gái vào nguyệt hoa.\nThương hay sanh tiếng rầy rà,\nPhải phòng hình phạt số ta có rày.\nKhông phần hưởng của gia tài,\nDầu mà có hưởng phá rày tiêu hao.\nNăm canh giấc mộng chiêm bao,\nTưởng tình xuất hiện chạy mau nhẹ mình.\nKhá nên bố đức xem kinh,\nKhương ninh an hưởng gia đình vượng tăng.','Nữ mạng Tân Mẹo, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu. Số này thuở nhỏ gian nan, trung vận gặp quới nhơn giúp đỡ mà phát đạt tiền tài, hậu vận đặng hưởng phước thái bình, gia đạo hưng vượng.'),(8,6,'Nam','Bạch Lạp Kim','Đoán xem số mạng như là,\nTân Tỵ Kim mạng số ta như vầy.\nTuổi cùng với mạng hì đầy khắc rầy.\nThuở nhỏ đau đẻ chẳng may,\nHoặc thiếu máu huyết hôm nay nhức mình.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt rầy mong sang giàu.\nTa làm ra của biết bao,\nGia đình tạo lập đặng vinh quang.\nSố ta chồng vợ chẳng toàn,\nĐổi dời cách trở đôi đàng rã phân.\nĐời sau sum hiệp ân cần,\nCũng là khắc ý là phần số ta.\nCơ mưu léo lắt vậy mà,\nChí khí cứng cỏi dám qua mặt người.\nCó duyên đi đứng tốt tươi,\nQuới nhơn trợ giúp cũng xong xong.\nTánh người sau trước chẳng đông,\nVui lòng thương vội buồn lòng ghét mau.\nLòng lo nhiều việc lao xao,\nThấy điều trái ý can vào nói ra.\nLàm ăn người ghét tính ta,\nDầu mà có ghét cũng là không sao.\nCó tay thương mãi về sau,\nĐó là thuận số phước hào đặng nên.\nTu tâm dưỡng tánh cho bền,\nGia đình phát đạt tuổi tên chói ngời.','Tuổi này mạng Bạch Lạp Kim. Tánh tình cứng cỏi, thông minh, có linh cảm tốt. Thuở nhỏ thường hay đau ốm, thiếu máu huyết. Số tự lập, tay trắng tạo nên cơ nghiệp vinh quang. Tuy nhiên duyên nợ trắc trở, vợ chồng hay xung khắc hoặc dời đổi một lần mới yên. Có tay thương mãi, hậu vận giàu sang. Cần tu tâm dưỡng tánh để giữ bền phước lộc.'),(8,6,'Nu','Bạch Lạp Kim','Đoán xem số mạng như là,\nTân Tỵ Kim mạng số ta như vầy.\nTuổi cùng với mạng hì đầy khắc rầy.\nThuở nhỏ đau đẻ chẳng may,\nHoặc thiếu máu huyết hôm nay nhức mình.\nThái Dương chiếu mạng tâm linh,\nChưa tới biết trước ý tình sáng thông.\nLong Thần chiếu mạng phước hồng,\nCủa tiền phát đạt rầy mong sang giàu.\nTa làm ra của biết bao,\nGia đình tạo lập đặng vinh quang.\nSố ta chồng vợ chẳng toàn,\nĐổi dời cách trở đôi đàng rã phân.\nĐời sau sum hiệp ân cần,\nCũng là khắc ý là phần số ta.\nCơ mưu léo lắt vậy mà,\nChí khí cứng cỏi dám qua mặt người.\nCó duyên đi đứng tốt tươi,\nQuới nhơn trợ giúp cũng xong xong.\nTánh người sau trước chẳng đông,\nVui lòng thương vội buồn lòng ghét mau.\nLòng lo nhiều việc lao xao,\nThấy điều trái ý can vào nói ra.\nLàm ăn người ghét tính ta,\nDầu mà có ghét cũng là không sao.\nCó tay thương mãi về sau,\nĐó là thuận số phước hào đặng nên.\nTu tâm dưỡng tánh cho bền,\nGia đình phát đạt tuổi tên chói ngời.','Nữ mạng Tân Tỵ, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình ngay thẳng, siêng năng. Số này tuổi trẻ bôn ba, trung vận đặng quới nhơn trợ giúp mà phát đạt, hậu vận hưởng phước an nhàn.'),(8,8,'Nam','Lộ Bàn Thổ','Đoán xem số mạng như là,\nTân Mùi mạng thổ số ta như vầy.\nTuổi cùng số mạng đặng vầy tương sanh.\nPhước đức chiếu số đặng lành,\nTiền tài phát đạt tạo thành gia cư.\nTánh người mau lẹ lo tư,\nUống ăn cũng dễ không từ món chi.\nTù lao số phạm vậy thì,\nBất buộc hình phạt số ni có rày.\nPhu thê số phận đắng cay,\nQuả Tú chiếu mạng hôm nay trễ chầy.\nĐến sau Loan Phụng hiệp bầy,\nĐôi đàng khác xứ sum vầy nợ duyên.\nÝ tình không hạp sanh phiền,\nLấy sự nhẫn nại bình yên ở đời.\nĐối người tử tế vậy thời,\nSau ngày tranh phản tiếng lời vào ra.\nĐêm thanh lo tính vậy mà,\nChơn đi nhiều chỗ số ta đời đời.\nQuê hương tổ phụ cách nơi,\nTạo lập khác xứ vậy thời đặng nên.\nBà con lãnh đạm đôi bên,\nKhông nhờ thân tộc tự yên lo lường.\nTâm tánh rộng rãi ôn lương,\nĐầu lòng sanh gái an khương gia đình.\nCảnh già số ở một mình,\nTự quyền làm chủ gia đình làm ăn.\nTa nên tích đức lòng hằng,\nNhẹ điều khắc kỵ mong rằng thảnh thơi.','Tuổi này đặng phước đức chiếu lành. Tiền tài phát đạt tạo thành gia cư. Tánh người mau lẹ, uống ăn dễ. Tuy nhiên số phạm hình phạt tù lao, phu thê trắc trở, phải dời đổi xứ sở hoặc cưới muộn mới yên. Số tự lập, không nhờ thân tộc. Hậu vận an nhàn, có số làm chủ.'),(8,8,'Nu','Lộ Bàn Thổ','Đoán xem số mạng như là,\nTân Mùi mạng thổ số ta như vầy.\nTuổi cùng số mạng đặng vầy tương sanh.\nPhước đức chiếu số đặng lành,\nTiền tài phát đạt tạo thành gia cư.\nTánh người mau lẹ lo tư,\nUống ăn cũng dễ không từ món chi.\nTù lao số phạm vậy thì,\nBất buộc hình phạt số ni có rày.\nPhu thê số phận đắng cay,\nQuả Tú chiếu mạng hôm nay trễ chầy.\nĐến sau Loan Phụng hiệp bầy,\nĐôi đàng khác xứ sum vầy nợ duyên.\nÝ tình không hạp sanh phiền,\nLấy sự nhẫn nại bình yên ở đời.\nĐối người tử tế vậy thời,\nSau ngày tranh phản tiếng lời vào ra.\nĐêm thanh lo tính vậy mà,\nChơn đi nhiều chỗ số ta đời đời.\nQuê hương tổ phụ cách nơi,\nTạo lập khác xứ vậy thời đặng nên.\nBà con lãnh đạm đôi bên,\nKhông nhờ thân tộc tự yên lo lường.\nTâm tánh rộng rãi ôn lương,\nĐầu lòng sanh gái an khương gia đình.\nCảnh già số ở một mình,\nTự quyền làm chủ gia đình làm ăn.\nTa nên tích đức lòng hằng,\nNhẹ điều khắc kỵ mong rằng thảnh thơi.','Nữ mạng Tân Mùi, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình vui vẻ, siêng năng lo liệu việc nhà. Số này thuở nhỏ bôn ba cực khổ, về sau đặng hưởng phước thái bình, gia đình hưng vượng.'),(8,10,'Nam','Thạch Lựu Mộc','Đoán xem số mạng như là,\nTân Dậu mạng Mộc số ta như vầy.\nTuổi Kim mạng Mộc số nầy khắc rầy,\nBịnh phù chiếu mạng chẳng may.\nTánh ít mau lẹ hay xét suy.\nGiận cứng tối dạ lòng thì hiền lương.\nÝ ưa ca xướng lại thường,\nVẻ vui tánh tánh không đặng ngao kiêu.\nLuận xem tiền của đặng giàu,\nHưởng sự no ấm ít nhiều bực trung.\nMiệng hay vui nói chẳng chừng,\nNgười đều thương mến bao dung tấm lòng.\nSố ta duyên nợ vợ chồng,\nCách đời thứ nhứt phước hồng đổi sau.\nÍt hay nói việc hòa hao,\nThấy việc mới chắc nói nào chẳng tin.\nXem hào thân tộc đệ huynh,\nKhông đặng hòa thuận ý tình thờ sơ.\nKhông lộc mua bán cậy nhờ,\nHoặc là công nghệ trông chờ cậy nên.\nAnh em khác xứ ở lo ên,\nMới là nên đặng tuổi đời với tôi.\nHào con khó đặng vậy thời,\nĐau ốm trận trước Trời dời qua.\nChớ nên chiến đấu hạp ý ta,\nViệc người phải quày vậy mà luân phân.\nTa nên tích thiện thi ân,\nMong ngày vãng cảnh hưởng phần khương ninh.','Tuổi này mạng Thạch Lựu Mộc. Người có tính hiền lành, trung thực nhưng hay lo nghĩ và ít quyết đoán. Số thông minh, có tài năng và mưu trí. Thuở nhỏ hay đau ốm, bịnh tật. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa mới yên. Hào con cái và anh em ít nhờ cậy đặng. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(8,10,'Nu','Thạch Lựu Mộc','Đoán xem số mạng như là,\nTân Dậu mạng Mộc số ta như vầy.\nTuổi Kim mạng Mộc số nầy khắc rầy,\nBịnh phù chiếu mạng chẳng may.\nTánh ít mau lẹ hay xét suy.\nGiận cứng tối dạ lòng thì hiền lương.\nÝ ưa ca xướng lại thường,\nVẻ vui tánh tánh không đặng ngao kiêu.\nLuận xem tiền của đặng giàu,\nHưởng sự no ấm ít nhiều bực trung.\nMiệng hay vui nói chẳng chừng,\nNgười đều thương mến bao dung tấm lòng.\nSố ta duyên nợ vợ chồng,\nCách đời thứ nhứt phước hồng đổi sau.\nÍt hay nói việc hòa hao,\nThấy việc mới chắc nói nào chẳng tin.\nXem hào thân tộc đệ huynh,\nKhông đặng hòa thuận ý tình thờ sơ.\nKhông lộc mua bán cậy nhờ,\nHoặc là công nghệ trông chờ cậy nên.\nAnh em khác xứ ở lo ên,\nMới là nên đặng tuổi đời với tôi.\nHào con khó đặng vậy thời,\nĐau ốm trận trước Trời dời qua.\nChớ nên chiến đấu hạp ý ta,\nViệc người phải quày vậy mà luân phân.\nTa nên tích thiện thi ân,\nMong ngày vãng cảnh hưởng phần khương ninh.','Nữ mạng Tân Dậu, thờ Bà Chúa Tiên Nương Nương độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(8,12,'Nam','Ngai Xuyên Kim','Đoán xem số mạng như là,\nTân Hợi mạng Kim số ta như vầy.\nTuổi Thủy Kim mạng số nầy,\nThái Dương chiếu mạng khôn lanh,\nThấy việc mau hiểu tánh tâm linh.\nLời nói chắc thiệt rõ ràng,\nKhông chịu thay đổi ý tình sâu xa.\nChẳng rằng chớ nói đến ta,\nThấy vậy bất hạp thời chẳng gần.\nTay làm ra nhiều sự cần,\nThất bại nhiều độ đặng phần ấm no.\nTánh người hay tính hay lo,\nĐịa giải độ mạng rủi ro nhẹ rày.\nCó duyên đi đứng đặng may,\nNgười đều tử tế từ xưa giao tình.\nSố ta duyên nợ linh đinh,\nĐôi ba cách trở gia đình mới an.\nCửa nhà dời đổi nhiều phen,\nLập nơi chỗ mới bền lâu.\nAnh em một chút chớ âu lo lường.\nMột người một chút chớ âu lo lường.\nSố có lộc mà không thương,\nCó tay mua bán là đặng lập nên.\nSố người trưởng thọ đặng bền sông sâu,\nTuổi xuân tài lộc chẳng đầu,\nĐến khi vãng cảnh ngõ hầu vinh huê.\nKhá nên chưởng đức dự kế,\nMong nhờ hậu vận gia tề phong vinh.','Tuổi này mạng Ngai Xuyên Kim. Người có tánh tình ngay thẳng, linh tính tốt, thông minh, lanh lợi. Số đặng Địa Giải độ mạng nên nhẹ bớt tai nạn. Số tự lập, tay trắng tạo nên cơ nghiệp, không nhờ đặng bà con thân tộc. Duyên nợ trắc trở, vợ chồng hay xung khắc hoặc phải dời đổi nhà cửa nhiều lần mới yên. Tuy có tài lộc nhưng khó giữ của thuở trẻ. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(8,12,'Nu','Ngai Xuyên Kim','Đoán xem số mạng như là,\nTân Hợi mạng Kim số ta như vầy.\nTuổi Thủy Kim mạng số nầy,\nThái Dương chiếu mạng khôn lanh,\nThấy việc mau hiểu tánh tâm linh.\nLời nói chắc thiệt rõ ràng,\nKhông chịu thay đổi ý tình sâu xa.\nChẳng rằng chớ nói đến ta,\nThấy vậy bất hạp thời chẳng gần.\nTay làm ra nhiều sự cần,\nThất bại nhiều độ đặng phần ấm no.\nTánh người hay tính hay lo,\nĐịa giải độ mạng rủi ro nhẹ rày.\nCó duyên đi đứng đặng may,\nNgười đều tử tế từ xưa giao tình.\nSố ta duyên nợ linh đinh,\nĐôi ba cách trở gia đình mới an.\nCửa nhà dời đổi nhiều phen,\nLập nơi chỗ mới bền lâu.\nAnh em một chút chớ âu lo lường.\nMột người một chút chớ âu lo lường.\nSố có lộc mà không thương,\nCó tay mua bán là đặng lập nên.\nSố người trưởng thọ đặng bền sông sâu,\nTuổi xuân tài lộc chẳng đầu,\nĐến khi vãng cảnh ngõ hầu vinh huê.\nKhá nên chưởng đức dự kế,\nMong nhờ hậu vận gia tề phong vinh.','Nữ mạng Tân Hợi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(9,1,'Nam','Tang Đố Mộc','Đoán xem số mạng như là,\nNhâm Tý mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người có tiếng công danh,\nMiệng lanh hay nói việc lành hiệt hung.\nPhước đức chiếu mạng thung dung,\nHào tài thạnh vượng gia trung vui vầy.\nLuân xem duyên nợ số này,\nKhắc hào chồng vợ đổi dời nhiều lần.\nTình duyên hòa nguyệt phản vân,\nMuộn thời sanh đặng phận bền lâu.\nTam hình số phạm giữ âu,\nPhải phòng tù tội có hầu một khi.\nSố ta tâm khổ vậy thì,\nThân đành đặng rảnh quản gì khổ tâm.\nBà con lãnh đạm buồn thầm,\nAnh em thiếu sức có cầm như không.\nSố ta nhỏ đặng phước hồng,\nĐặng phần sang số trong vòng hiển vang.\nLàm ăn lớn việc không toàn,\nNhỏ thời nên việc dễ đàng đặng nên.\nThường sanh lỗi tiếng không êm,\nRầy rà dễ dệt bớt thêm thường hoài.\nNgười có cốt cách tốt thay,\nThấy việc mau hiểu ý rày thông minh.\nHào con thạnh vượng hiển vinh,\nSanh trai hai đứa gia đình lập nên.\nTu tâm dưỡng tánh cho bền,\nHưởng nhờ vãng cảnh đặng thành thơi.','Tuổi này mạng Tang Đố Mộc. Người có tính thông minh, khéo léo, miệng lưỡi lanh lợi nhưng dễ bị tai tiếng thị phi. Số đặng phước đức chiếu mạng nên gia đạo vui vẻ, tài lộc dồi dào. Tuy nhiên, duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa nhiều lần mới yên. Có số phạm tù tội, cần đề phòng. Số tự lập, không nhờ đặng anh em bà con. Hào con cái hiển đạt, con trai đầu lòng. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(9,1,'Nu','Tang Đố Mộc','Đoán xem số mạng như là,\nNhâm Tý mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nSố người có tiếng công danh,\nMiệng lanh hay nói việc lành hiệt hung.\nPhước đức chiếu mạng thung dung,\nHào tài thạnh vượng gia trung vui vầy.\nLuân xem duyên nợ số này,\nKhắc hào chồng vợ đổi dời nhiều lần.\nTình duyên hòa nguyệt phản vân,\nMuộn thời sanh đặng phận bền lâu.\nTam hình số phạm giữ âu,\nPhải phòng tù tội có hầu một khi.\nSố ta tâm khổ vậy thì,\nThân đành đặng rảnh quản gì khổ tâm.\nBà con lãnh đạm buồn thầm,\nAnh em thiếu sức có cầm như không.\nSố ta nhỏ đặng phước hồng,\nĐặng phần sang số trong vòng hiển vang.\nLàm ăn lớn việc không toàn,\nNhỏ thời nên việc dễ đàng đặng nên.\nThường sanh lỗi tiếng không êm,\nRầy rà dễ dệt bớt thêm thường hoài.\nNgười có cốt cách tốt thay,\nThấy việc mau hiểu ý rày thông minh.\nHào con thạnh vượng hiển vinh,\nSanh trai hai đứa gia đình lập nên.\nTu tâm dưỡng tánh cho bền,\nHưởng nhờ vãng cảnh đặng thành thơi.','Nữ mạng Nhâm Tý, thờ Ông Tứ Vi độ mạng. Tánh tình đoan trang, hiền hậu, lo liệu gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(9,3,'Nam','Kim Bạch Kim','Đoán xem số mạng như là,\nNhâm Dần Kim mạng số ta như vầy.\nTuổi Mộc Kim mạng số nầy khắc rầy,\nĐiều Khách chiếu mạng chẳng may.\nMột lần té nặng bịnh rày tật thân.\nĐời sanh cay đắng nhiều phen gian truân.\nBốn ba đi đứng không ngừng,\nChưn đi nhiều chỗ đã từng lo toan.\nNhiều số chức tước quyền ban,\nNhiều người yêu chuộng gần hàng quới nhơn.\nHao tài tốn kém nguồn cơn,\nCũng là đủ dụng chí lớn lao.\nViệc làm bụng tính lao xao,\nKhó đặng kỹ sự việc nào cho xong.\nViệc chi ta chớ tin lòng,\nTin cậy giúp đỡ khó trông tròn lòng.\nMiệng vui hay nói lòng son,\nThông minh tánh sáng lại còn trí mưu.\nVợ chồng xung khắc sầu ưu,\nHoặc là cách trở hồi câu bất hòa.\nSông sâu sóng lớn kỵ ta,\nChìm ghe té giếng dặm mà một phen.\nTánh hay tìm hiểm việc hèn,\nChí khí cứng cỏi sang hèn không phân.\nĐời sanh nhiều nơi toan tính,\nĐặng người trong thế đặng phần ấm no.\nTa nên dưỡng đức khá lo,\nMong ngày phát đạt Trời cho hưởng phần.','Tuổi này mạng Kim Bạch Kim. Người có tánh tình thông minh, có tài mưu lược, chí khí cứng cỏi nhưng dễ bị tiểu nhân ghét. Thuở nhỏ bôn ba gian truân, hay bịnh tật, cần đề phòng tai nạn sông nước hoặc té ngã. Số đặng quới nhơn trợ giúp, có chức tước quyền ban nhưng của tiền hao tốn thuở trẻ. Duyên nợ trắc trở, vợ chồng xung khắc hoặc dời đổi nhà cửa mới yên. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(9,3,'Nu','Kim Bạch Kim','Đoán xem số mạng như là,\nNhâm Dần Kim mạng số ta như vầy.\nTuổi Mộc Kim mạng số nầy khắc rầy,\nĐiều Khách chiếu mạng chẳng may.\nMột lần té nặng bịnh rày tật thân.\nĐời sanh cay đắng nhiều phen gian truân.\nBốn ba đi đứng không ngừng,\nChưn đi nhiều chỗ đã từng lo toan.\nNhiều số chức tước quyền ban,\nNhiều người yêu chuộng gần hàng quới nhơn.\nHao tài tốn kém nguồn cơn,\nCũng là đủ dụng chí lớn lao.\nViệc làm bụng tính lao xao,\nKhó đặng kỹ sự việc nào cho xong.\nViệc chi ta chớ tin lòng,\nTin cậy giúp đỡ khó trông tròn lòng.\nMiệng vui hay nói lòng son,\nThông minh tánh sáng lại còn trí mưu.\nVợ chồng xung khắc sầu ưu,\nHoặc là cách trở hồi câu bất hòa.\nSông sâu sóng lớn kỵ ta,\nChìm ghe té giếng dặm mà một phen.\nTánh hay tìm hiểm việc hèn,\nChí khí cứng cỏi sang hèn không phân.\nĐời sanh nhiều nơi toan tính,\nĐặng người trong thế đặng phần ấm no.\nTa nên dưỡng đức khá lo,\nMong ngày phát đạt Trời cho hưởng phần.','Nữ mạng Nhâm Dần, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, cần kiệm lo toan gia đình. Số này tuổi trẻ bôn ba gian khổ, trung vận phát đạt tiền tài, hậu vận hưởng phước an nhàn sung túc.'),(9,5,'Nam','Trường Lưu Thủy','Đoán xem số mạng như là,\nNhâm Thìn mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nKhó nuôi thuở nhỏ chẳng may,\nĐau ốm kế thác nạn tai buổi đầu.\nPhù trầm chiếu mạng phòng âu,\nPhải phòng té giếng sông sâu kỵ rày.\nTé sông té giếng một khi,\nSố có quyền tước vậy thời,\nCũng là chức phận kịp kỳ công môn.\nNgười sang trọng đãi kính tôn,\nRa tay trợ giúp bảo tồn nghĩa ân.\nKẻ nhỏ phản ý khó phân,\nChớ nên tin bạn sau lần phản tâm.\nCủa tiền ta khó giữ cầm,\nTay làm ra của tầm đường tổn hao.\nTánh không định trước việc nào,\nMuốn làm làm đại tay mau khéo nghề.\nSiêng năng cần kiệm gia tề,\nTay chân chẳng nghỉ nhiều bề tính lo.\nTuổi xuân rộn trí lần dò,\nLớn lên cũng đặng ấm no gia đình.\nVợ chồng sum hiệp định ninh,\nHào con thạnh vượng hiển vinh thay là.\nMiệng hiền lòng dữ tánh ta,\nThương thời để dạ ghét mà để tâm.\nCơ mưu khéo léo sáng tầm,\nThông minh danh lợi tại tâm trung bình.\nKhá xem họa phước tùy hình,\nLàm nhiều điều thiện an ninh vững bền.\nTuổi xuân rộn trí lần dò,\nLớn lên cũng đặng ấm no gia đình.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Tuổi này mạng Trường Lưu Thủy. Người có tính thông minh, mưu mẹo, khéo tay nghề và siêng năng. Thuở nhỏ khó nuôi, hay đau ốm, cần đề phòng tai nạn sông nước hoặc té ngã. Số đặng quới nhơn trợ giúp, có quyền chức trong công môn. Tuy nhiên, tính tình đôi khi nóng nảy, miệng hiền lòng dữ, dễ bị bạn bè phản tâm. Của tiền khó giữ thuở trẻ, trung vận mới ổn định. Vợ chồng hòa thuận, con cái vinh hiển. Cần làm điều thiện để hậu vận đặng bền vững.'),(9,5,'Nu','Trường Lưu Thủy','Đoán xem số mạng như là,\nNhâm Thìn mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nKhó nuôi thuở nhỏ chẳng may,\nĐau ốm kế thác nạn tai buổi đầu.\nPhù trầm chiếu mạng phòng âu,\nPhải phòng té giếng sông sâu kỵ rày.\nTé sông té giếng một khi,\nSố có quyền tước vậy thời,\nCũng là chức phận kịp kỳ công môn.\nNgười sang trọng đãi kính tôn,\nRa tay trợ giúp bảo tồn nghĩa ân.\nKẻ nhỏ phản ý khó phân,\nChớ nên tin bạn sau lần phản tâm.\nCủa tiền ta khó giữ cầm,\nTay làm ra của tầm đường tổn hao.\nTánh không định trước việc nào,\nMuốn làm làm đại tay mau khéo nghề.\nSiêng năng cần kiệm gia tề,\nTay chân chẳng nghỉ nhiều bề tính lo.\nTuổi xuân rộn trí lần dò,\nLớn lên cũng đặng ấm no gia đình.\nVợ chồng sum hiệp định ninh,\nHào con thạnh vượng hiển vinh thay là.\nMiệng hiền lòng dữ tánh ta,\nThương thời để dạ ghét mà để tâm.\nCơ mưu khéo léo sáng tầm,\nThông minh danh lợi tại tâm trung bình.\nKhá xem họa phước tùy hình,\nLàm nhiều điều thiện an ninh vững bền.\nTuổi xuân rộn trí lần dò,\nLớn lên cũng đặng ấm no gia đình.\nTa nên tích đức về sau,\nNhị điều khắc kỵ đặng hào thảnh thơi.','Nữ mạng Nhâm Thìn, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình ngay thẳng, siêng năng lo liệu việc gia đình. Số này tuổi trẻ bôn ba, nhiều phen thay đổi cơ nghiệp, hậu vận đặng hưởng phước an nhàn sung túc.'),(9,7,'Nam','Dương Liễu Mộc','Đoán xem số mạng như là,\nNhâm Ngọ mạng Mộc số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nĐiều Khách chiếu mạng chẳng may,\nPhải phòng té nặng chịu rày tật thân.\nChìm ghe té giếng một lần,\nPhải phòng sông giếng là phần kỵ ta.\nTánh ưa trồng tỉa đó là,\nTấm lòng rộng rãi ham mà thiện tâm.\nCủa tiền ta khó giữ cầm,\nLàm ra có của lại tầm đường ho.\nSố khắc cha mẹ dễ nào,\nLàm cho phụ mẫu lao đao thương hình.\nTánh người cần kiệm giữ gìn,\nTuổi xuân lận đận gia đình khó nên.\nTrung niên vận giá đặng bền,\nLớn tuổi tạo lập đặng nên gia đình.\nSố ta gần đặng người vinh,\nHoặc có quyền tước thân tình người sang.\nVợ chồng sum hiệp vẹn toàn,\nTrên hòa dưới thuận đôi đàng yêu thương.\nHào con cùng đặng kiết tường,\nSanh nhiều nuôi dễ an khương thạnh hành.\nThông linh lòng dạ hiền lành,\nRa nơi công chúng đặng rành trí lo.\nTuổi xuân khổ nhọc lần dò,\nNhiều điều tai ách như đò đi sông.\nKhá nên dưỡng đức bền lòng,\nNgày sau đặng hưởng phước hồng thảnh thơi.','Tuổi này mạng Dương Liễu Mộc. Người có tính hiền lành, thông linh, rộng rãi và hay làm việc thiện. Thuở nhỏ bôn ba vất vả, gặp nhiều tai ách như đi đò trên sông, phòng té ngã hay sông nước. Khắc cha mẹ. Số tự lập, tay trắng tạo nên cơ nghiệp, hậu vận vinh hiển giàu sang. Vợ chồng hòa thuận, con cái đông đúc dễ nuôi.'),(9,7,'Nu','Dương Liễu Mộc','Đoán xem số mạng như là,\nNhâm Ngọ mạng Mộc số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nĐiều Khách chiếu mạng chẳng may,\nPhải phòng té nặng chịu rày tật thân.\nChìm ghe té giếng một lần,\nPhải phòng sông giếng là phần kỵ ta.\nTánh ưa trồng tỉa đó là,\nTấm lòng rộng rãi ham mà thiện tâm.\nCủa tiền ta khó giữ cầm,\nLàm ra có của lại tầm đường ho.\nSố khắc cha mẹ dễ nào,\nLàm cho phụ mẫu lao đao thương hình.\nTánh người cần kiệm giữ gìn,\nTuổi xuân lận đận gia đình khó nên.\nTrung niên vận giá đặng bền,\nLớn tuổi tạo lập đặng nên gia đình.\nSố ta gần đặng người vinh,\nHoặc có quyền tước thân tình người sang.\nVợ chồng sum hiệp vẹn toàn,\nTrên hòa dưới thuận đôi đàng yêu thương.\nHào con cùng đặng kiết tường,\nSanh nhiều nuôi dễ an khương thạnh hành.\nThông linh lòng dạ hiền lành,\nRa nơi công chúng đặng rành trí lo.\nTuổi xuân khổ nhọc lần dò,\nNhiều điều tai ách như đò đi sông.\nKhá nên dưỡng đức bền lòng,\nNgày sau đặng hưởng phước hồng thảnh thơi.','Nữ mạng Nhâm Ngọ, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình cần kiệm, lo liệu việc nhà chu tất. Số này tuổi trẻ gian nan, phải chịu nhiều phen dời đổi, hậu vận nhờ đức dày mà đặng hưởng an nhàn thái bình.'),(9,9,'Nam','Kiếm Phong Kim','Đoán xem số mạng như là,\nNhâm Thân Kim mạng số ta như vầy.\nTuổi cùng mạng Kim mạng số ta như vầy.\nKhó nuôi thuở nhỏ đủ đầy thuốc thang.\nThường hay bịnh hoạn vương mang,\nGiải Thần độ mạng nhẹ an thân hình.\nPhù Trầm số mạng giữ gìn,\nSông sâu sóng lớn hữu tình một lần.\nThường hay đi đứng phân vân,\nGia đình khác xứ lập thân đặng thành.\nHuyết vận chiếu mạng chẳng lành,\nTay khó cầm của phải đành tốn hao.\nLàm ăn tự tin chớ nao,\nTin người hùn hạp ngày sau không tròn.\nThông minh cơ biết lòng son,\nCơ mưu léo lắt lại còn sáng thông.\nQuới nhơn trọng đãi phước hồng,\nRa vào nơi chốn phép công yêu vì.\nCó tay tài nghệ vậy thì,\nTánh người cần kiệm số ni lập thành.\nĐệ huynh xung khắc chẳng lành,\nCốt nhục tuy có rõ ràng như không.\nSố trai khắc hại con dòng,\nSố gái phạm ấy phải phòng khắc phu.\nTrái ý nói cộc phòng thù,\nNgười ghét bộ miệng công phu nhọc lòng.\nCố tu niệm phước hồng,\nGia đình tiền của trong vòng bực trung.\nTa nên tích đức bồi vun,\nHậu nhựt an hưởng ngõ cùng thảnh thơi.','Tuổi này mạng Kiếm Phong Kim, đặng quới nhơn trọng đãi. Người có tính thông minh, cơ mưu, sáng suốt và có tài nghệ khéo léo. Tuy nhiên, thuở nhỏ khó nuôi, hay bị bệnh hoạn. Số phải ly hương lập nghiệp mới thành công. Khắc hào anh em và con cái. Hậu vận an nhàn, tiền của bực trung.'),(9,9,'Nu','Kiếm Phong Kim','Đoán xem số mạng như là,\nNhâm Thân Kim mạng số ta như vầy.\nTuổi cùng mạng Kim mạng số ta như vầy.\nKhó nuôi thuở nhỏ đủ đầy thuốc thang.\nThường hay bịnh hoạn vương mang,\nGiải Thần độ mạng nhẹ an thân hình.\nPhù Trầm số mạng giữ gìn,\nSông sâu sóng lớn hữu tình một lần.\nThường hay đi đứng phân vân,\nGia đình khác xứ lập thân đặng thành.\nHuyết vận chiếu mạng chẳng lành,\nTay khó cầm của phải đành tốn hao.\nLàm ăn tự tin chớ nao,\nTin người hùn hạp ngày sau không tròn.\nThông minh cơ biết lòng son,\nCơ mưu léo lắt lại còn sáng thông.\nQuới nhơn trọng đãi phước hồng,\nRa vào nơi chốn phép công yêu vì.\nCó tay tài nghệ vậy thì,\nTánh người cần kiệm số ni lập thành.\nĐệ huynh xung khắc chẳng lành,\nCốt nhục tuy có rõ ràng như không.\nSố trai khắc hại con dòng,\nSố gái phạm ấy phải phòng khắc phu.\nTrái ý nói cộc phòng thù,\nNgười ghét bộ miệng công phu nhọc lòng.\nCố tu niệm phước hồng,\nGia đình tiền của trong vòng bực trung.\nTa nên tích đức bồi vun,\nHậu nhựt an hưởng ngõ cùng thảnh thơi.','Nữ mạng Nhâm Thân, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình cần kiệm, có tài đảm đang việc nhà. Số này tuổi trẻ vất vơ, hậu vận nhờ đức rộng tâm lành mà đặng hưởng phước vinh hoa.'),(9,11,'Nam','Đại Hải Thủy','Đoán xem số mạng như là,\nNhâm Tuất mạng Thủy số ta như vầy.\nTuổi Thổ mạng Thủy số nầy,\nPhải phòng té nặng chịu rày tổn thân.\nSố người đau ốm nhiều lần không an.\nSố ta có quyền ban,\nChức tước danh phận là đặng lập nên.\nTánh yểm mồm móp tâm bình,\nKinh trên thương dưới tánh công bình.\nLuân xem tiền của gia đình,\nThiếu niên đủ dụng an ninh qua ngày.\nTrung niên vãng cảnh lâu dài,\nAn lành tự loại hưởng rày thảnh thơi.\nCó công nghệ vậy thì,\nHoặc làm thấy thợ trong đời ấm thân.\nTay khéo tánh sáng siêng năng,\nBốn phương phước phận vẹn phần xứ xây.\nSổ gái khắc phu đó là,\nHào con sanh dưỡng đặng mà bực trung.\nChiêm bao thường thấy tự tung,\nBay lượn lòng lặn thung dung lẹ làng.\nĐời sanh nên chữ thong khoan,\nKiết tinh đa chiếu hôm nay vững vàng.\nKhá trau tâm niệm để đành,\nCứu nhân tích đức hậu đài.','Tuổi này mạng Đại Hải Thủy. Người có tánh tình thông minh, tài giỏi, có chí khí. Số đặng quyền chức, danh phận trong đời. Thuở nhỏ hay đau ốm, bịnh tật, cần phòng tai nạn sông nước hoặc té ngã. Tánh tình thẳng thắn, công bình, được người trên kính trọng, người dưới tin yêu. Hào con cái muộn màng, khó nuôi. Số tự lập, tay trắng tạo nên cơ nghiệp, hậu vận đặng giàu sang, an nhàn nhờ tu tâm tích đức.'),(9,11,'Nu','Đại Hải Thủy','Đoán xem số mạng như là,\nNhâm Tuất mạng Thủy số ta như vầy.\nTuổi Thổ mạng Thủy số nầy,\nPhải phòng té nặng chịu rày tổn thân.\nSố người đau ốm nhiều lần không an.\nSố ta có quyền ban,\nChức tước danh phận là đặng lập nên.\nTánh yểm mồm móp tâm bình,\nKinh trên thương dưới tánh công bình.\nLuân xem tiền của gia đình,\nThiếu niên đủ dụng an ninh qua ngày.\nTrung niên vãng cảnh lâu dài,\nAn lành tự loại hưởng rày thảnh thơi.\nCó công nghệ vậy thì,\nHoặc làm thấy thợ trong đời ấm thân.\nTay khéo tánh sáng siêng năng,\nBốn phương phước phận vẹn phần xứ xây.\nSổ gái khắc phu đó là,\nHào con sanh dưỡng đặng mà bực trung.\nChiêm bao thường thấy tự tung,\nBay lượn lòng lặn thung dung lẹ làng.\nĐời sanh nên chữ thong khoan,\nKiết tinh đa chiếu hôm nay vững vàng.\nKhá trau tâm niệm để đành,\nCứu nhân tích đức hậu đài.','Nữ mạng Nhâm Tuất, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(10,2,'Nam','Tang Đố Mộc','Đoán xem số mạng như là,\nQuí Sửu mạng Mộc số ta như vầy.\nTuổi Thổ mạng Mộc số nầy,\nNgười đều yêu chuộng mến thương.\nBịnh phù chiếu mạng hữu thường,\nCó tiểu tật bịnh ở thường trong thân.\nSố ta khắc cha mẹ phân vân,\nHoặc là cách trở hoặc phản mối côi.\nLuận xem thịnh vượng vô rồi,\nTay làm thịnh vượng vô rồi hao ra.\nĐời sanh khó trí đó là,\nRỗi lo rộn trí tính mà rảnh rang.\nTánh người lớn to gan,\nSố ta trưởng thọ tầm khoanh vui vầy.\nSố ta duyên nợ đổi xây,\nCách đời thứ nhứt sum vầy đôi sau.\nAnh em thiếu sức quản bao,\nNghèo giàu giản dị dễ nào lập nên.\nSố ta cách xử quê xưa,\nKhác xứ cha mẹ vừa lập nên.\nBằng mà có sớm chẳng đầu,\nMà có sớm chẳng đầu\nCó tay tài nghệ vậy mà,\nSố tát đối đổi của nhà đôi phen.\nTích thiện bố đức lòng bền,\nHưởng ngày hậu nhựt như đèn thêm chư.','Tuổi này mạng Tang Đố Mộc. Người có tính hiền lành, được yêu mến, tánh tình ngay thẳng. Thuở nhỏ hay có tiểu bệnh, khắc cha mẹ hoặc phải ly hương. Số tự lập, tay trắng tạo nên cơ nghiệp, tài lộc dồi dào. Tuy nhiên duyên nợ buổi đầu trắc trở, dời đổi nhà cửa xứ sở mới yên. Hậu vận đặng giàu sang, trường thọ nhờ tu tâm tích đức.'),(10,2,'Nu','Tang Đố Mộc','Đoán xem số mạng như là,\nQuí Sửu mạng Mộc số ta như vầy.\nTuổi Thổ mạng Mộc số nầy,\nNgười đều yêu chuộng mến thương.\nBịnh phù chiếu mạng hữu thường,\nCó tiểu tật bịnh ở thường trong thân.\nSố ta khắc cha mẹ phân vân,\nHoặc là cách trở hoặc phản mối côi.\nLuận xem thịnh vượng vô rồi,\nTay làm thịnh vượng vô rồi hao ra.\nĐời sanh khó trí đó là,\nRỗi lo rộn trí tính mà rảnh rang.\nTánh người lớn to gan,\nSố ta trưởng thọ tầm khoanh vui vầy.\nSố ta duyên nợ đổi xây,\nCách đời thứ nhứt sum vầy đôi sau.\nAnh em thiếu sức quản bao,\nNghèo giàu giản dị dễ nào lập nên.\nSố ta cách xử quê xưa,\nKhác xứ cha mẹ vừa lập nên.\nBằng mà có sớm chẳng đầu,\nMà có sớm chẳng đầu\nCó tay tài nghệ vậy mà,\nSố tát đối đổi của nhà đôi phen.\nTích thiện bố đức lòng bền,\nHưởng ngày hậu nhựt như đèn thêm chư.','Nữ mạng Quý Sửu, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.'),(10,4,'Nam','Kim Bạch Kim','Đoán xem số mạng như là,\nQuí Mẹo Kim mạng số ta như vầy.\nTuổi Mộc Kim mạng số nầy khắc rầy,\nBốn thân có bịnh chẳng may.\nHoặc thiếu máu huyết hôm nay nhức mình.\nThái Dương chiếu mạng thông minh,\nTâm linh biết trước tiền ngôn.\nNghị điều hung kiết tâm hồn chẳng sai.\nNgười lạ ghét hôm nay,\nThường thường tánh cứng cỏi phản rầy khi ai.\nLọ toan dễ dạ trí thâm,\nTiền tài y lộc xem qua.\nThiếu niên tầm nhóm vậy mà khó gần,\nTrung niên vãng cảnh lộc tăng.\nLong Đức chiếu mạng bằng bằng hậu lai.\nCủa cha mẹ không hưởng rày,\nDầu mà đặng hưởng phí tài tiêu hoang.\nCó nghề hoặc có quyền ban,\nMới là đặng vững mong đàng lập nên.\nVợ chồng đổi dời đôi bên,\nDầu trai hay gái bền nợ duyên.\nCó lộc ăn uống an nhiên,\nMón ăn chẳng thiếu đặng yên mạng rày.\nGia đình có số đổi thay,\nĐôi lần mới đặng hôm nay lập thành.\nTa nên bố đức làm lành,\nHậu nhựt phát đạt phước sanh nhường nhờ.','Tuổi này mạng Kim Bạch Kim. Người có tánh tình thông minh, linh cảm tốt, có tài mưu lược và chí khí cứng cỏi. Số đặng Thái Dương chiếu mạng nên trí tuệ sáng suốt, nhạy bén. Thuở nhỏ hay bệnh hoạn, thiếu máu huyết. Của cha mẹ khó hưởng, dễ bị phá tán. Số tự lập, tay trắng tạo nên cơ nghiệp. Duyên nợ trắc trở buổi đầu, sau mới đặng bền vững. Hậu vận đặng giàu sang, an nhàn nhờ tu tâm dưỡng tánh.'),(10,4,'Nu','Kim Bạch Kim','Đoán xem số mạng như là,\nQuí Mẹo Kim mạng số ta như vầy.\nTuổi Mộc Kim mạng số nầy khắc rầy,\nBốn thân có bịnh chẳng may.\nHoặc thiếu máu huyết hôm nay nhức mình.\nThái Dương chiếu mạng thông minh,\nTâm linh biết trước tiền ngôn.\nNghị điều hung kiết tâm hồn chẳng sai.\nNgười lạ ghét hôm nay,\nThường thường tánh cứng cỏi phản rầy khi ai.\nLọ toan dễ dạ trí thâm,\nTiền tài y lộc xem qua.\nThiếu niên tầm nhóm vậy mà khó gần,\nTrung niên vãng cảnh lộc tăng.\nLong Đức chiếu mạng bằng bằng hậu lai.\nCủa cha mẹ không hưởng rày,\nDầu mà đặng hưởng phí tài tiêu hoang.\nCó nghề hoặc có quyền ban,\nMới là đặng vững mong đàng lập nên.\nVợ chồng đổi dời đôi bên,\nDầu trai hay gái bền nợ duyên.\nCó lộc ăn uống an nhiên,\nMón ăn chẳng thiếu đặng yên mạng rày.\nGia đình có số đổi thay,\nĐôi lần mới đặng hôm nay lập thành.\nTa nên bố đức làm lành,\nHậu nhựt phát đạt phước sanh nhường nhờ.','Nữ mạng Quý Mẹo, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo liệu gia đình chu đáo. Số này tuổi trẻ bôn ba, phải chịu nhiều phen dời đổi, hậu vận nhờ đức dày mà đặng hưởng phước an nhàn vinh hoa.'),(10,6,'Nam','Trường Lưu Thủy','Đoán xem số mạng như là,\nQuí Tỵ mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSớm sanh có bịnh chẳng may,\nTrong mình yếu đuối rày tật thân.\nGương diện vui vẻ là phần,\nTánh hiền ý dễ không phân sang hèn.\nCạnh tranh ngôn ngữ nhiều phen.\nKhông nhịn lời nói thường bèn cãi nhau.\nTánh muốn mua gấp xôn xao,\nLòng người không độc nói ào bỏ qua.\nÝ ham hát xướng đờn ca,\nÍt hay lo tính chuyện xa lâu dài.\nLuận xem duyên nợ hôm nay,\nVợ chồng cách trở đổi thay nhiều lần.\nKhổ tâm chồng vợ phân vân,\nĐến sau kết nghĩa Châu Trần bền lâu.\nCủa tiền tay tạo dãi dầu,\nHào tài khó giữ ngõ hầu vào ra.\nThông minh lanh lợi thấy xa,\nGần người sang trọng xem qua thương rày.\nCửa nhà dời đổi nhiều thay,\nGần đặng huynh đệ hôm nay phước phần.\nHào con không trọn khó phân,\nSanh đa dưỡng thiếu vắng phần về sau.\nĐệ huynh xung khắc đồng bào,\nÍt khi hạp ý nhờ nhau có phần.\nKhá nên dưỡng tánh tu tâm,\nHưởng nhờ hậu vận ấm thân thọ trường.','Tuổi này mạng Trường Lưu Thủy. Người có tính hiền hòa, gương mặt vui vẻ, không phân biệt sang hèn nhưng tánh hay nói thẳng, dễ xảy ra cạnh tranh ngôn ngữ. Thuở nhỏ khó nuôi, hay có bệnh tật. Số tự lập, tay trắng làm nên cơ nghiệp nhưng của tiền khó giữ thuở trẻ. Duyên nợ trắc trở, phải dời đổi hoặc qua hai lần đò mới đặng bền lâu. Hào con cái và anh em có phần xung khắc, ít nhờ cậy đặng. Hậu vận đặng giàu sang, trường thọ nhờ tu tâm dưỡng tánh.'),(10,6,'Nu','Trường Lưu Thủy','Đoán xem số mạng như là,\nQuí Tỵ mạng Thủy số ta như vầy.\nTuổi cùng với mạng hai đây khắc rày.\nSớm sanh có bịnh chẳng may,\nTrong mình yếu đuối rày tật thân.\nGương diện vui vẻ là phần,\nTánh hiền ý dễ không phân sang hèn.\nCạnh tranh ngôn ngữ nhiều phen.\nKhông nhịn lời nói thường bèn cãi nhau.\nTánh muốn mua gấp xôn xao,\nLòng người không độc nói ào bỏ qua.\nÝ ham hát xướng đờn ca,\nÍt hay lo tính chuyện xa lâu dài.\nLuận xem duyên nợ hôm nay,\nVợ chồng cách trở đổi thay nhiều lần.\nKhổ tâm chồng vợ phân vân,\nĐến sau kết nghĩa Châu Trần bền lâu.\nCủa tiền tay tạo dãi dầu,\nHào tài khó giữ ngõ hầu vào ra.\nThông minh lanh lợi thấy xa,\nGần người sang trọng xem qua thương rày.\nCửa nhà dời đổi nhiều thay,\nGần đặng huynh đệ hôm nay phước phần.\nHào con không trọn khó phân,\nSanh đa dưỡng thiếu vắng phần về sau.\nĐệ huynh xung khắc đồng bào,\nÍt khi hạp ý nhờ nhau có phần.\nKhá nên dưỡng tánh tu tâm,\nHưởng nhờ hậu vận ấm thân thọ trường.','Nữ mạng Quý Tỵ, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, siêng năng lo toan gia đình. Số này tuổi trẻ bôn ba gian khổ, nhiều phen thay đổi nơi ăn chốn ở, hậu vận nhờ đức dày mà đặng hưởng phước an nhàn vinh hoa.'),(10,8,'Nam','Dương Liễu Mộc','Đoán xem số mạng như là,\nQuí Mùi mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nThái Dương chiếu mạng khôn lanh,\nTrí sáng mau hiểu tài lành tâm linh.\nLong thần độ mạng kết tinh,\nCủa tiền phát đạt giữ gìn trong tay.\nKhông chịu nói dối với ai,\nNói sao có vậy việc rày đinh ninh.\nNặng lời nhiều tiếng nghĩa tình đứt xa.\nLương duyên cách trở số ta,\nNhiều nơi duyên nợ vậy mà khó song.\nĐến sau loan phụng chung phòng,\nGặp nơi hào phú phước hồng bền lâu.\nRộng lòng vui vẻ ngõ hầu,\nCứu người rồi lại đảo đầu không ơn.\nCửa nhà dời đổi nguồn cơn,\nCách xử cha mẹ dời chơn xứ người.\nMới là tạo lập tốt tươi,\nĐặng nên cơ nghiệp vui cười vinh quang.\nSố có đau ghẻ chẳng an,\nHoặc thiếu máu huyết thường mang nhức mình.\nBà con lãnh đạm nhơn tình,\nKhó nương nhờ cậy tự mình lập nên.\nViệc làm chẳng định trước bền,\nMuốn làm làm đại hư nên quản gì.\nNên làm Âm đức vậy thì,\nGia đình phát đạt mạng tuỳ đức sanh.','Tuổi này mạng Dương Liễu Mộc, đặng Thái Dương chiếu mạng nên trí tuệ sáng suốt, khéo léo. Người tánh ngay thẳng, không nói dối. Tuy nhiên duyên nợ trắc trở, phải dời đổi nhà cửa xứ sở mới đặng vinh quang. Số không có phần nhờ cậy bà con, phải tự lực cánh sinh. Có số đau ghẻ hoặc thiếu máu huyết. Hậu vận đặng giàu sang phú túc nhờ đức dày.'),(10,8,'Nu','Dương Liễu Mộc','Đoán xem số mạng như là,\nQuí Mùi mạng Mộc số ta như vầy.\nTuổi cùng với mạng đặng vầy tương sanh.\nThái Dương chiếu mạng khôn lanh,\nTrí sáng mau hiểu tài lành tâm linh.\nLong thần độ mạng kết tinh,\nCủa tiền phát đạt giữ gìn trong tay.\nKhông chịu nói dối với ai,\nNói sao có vậy việc rày đinh ninh.\nNặng lời nhiều tiếng nghĩa tình đứt xa.\nLương duyên cách trở số ta,\nNhiều nơi duyên nợ vậy mà khó song.\nĐến sau loan phụng chung phòng,\nGặp nơi hào phú phước hồng bền lâu.\nRộng lòng vui vẻ ngõ hầu,\nCứu người rồi lại đảo đầu không ơn.\nCửa nhà dời đổi nguồn cơn,\nCách xử cha mẹ dời chơn xứ người.\nMới là tạo lập tốt tươi,\nĐặng nên cơ nghiệp vui cười vinh quang.\nSố có đau ghẻ chẳng an,\nHoặc thiếu máu huyết thường mang nhức mình.\nBà con lãnh đạm nhơn tình,\nKhó nương nhờ cậy tự mình lập nên.\nViệc làm chẳng định trước bền,\nMuốn làm làm đại hư nên quản gì.\nNên làm Âm đức vậy thì,\nGia đình phát đạt mạng tuỳ đức sanh.','Nữ mạng Quý Mùi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình vui vẻ, hiền hậu, lo liệu gia đình chu đáo. Số này tuổi trẻ vất vả cực nhọc, trung vận đặng quới nhơn trợ giúp, hậu vận hưởng phước an nhàn.'),(10,10,'Nam','Kiếm Phong Kim','Đoán xem số mạng như là,\nQuí Dậu kim mạng số ta như vầy.\nTuổi cùng mạng kim khắc hiềm,\nTánh người cứng cỏi lập nghiêm bề ngoài.\nSố phần duyên nợ đổi thay,\nQuả Tú chiếu mạng đắng cay nợ tình.\nCó duyên sắc đẹp ba sinh,\nNhiều nơi tính lại chung tình khó xong.\nThiên Đức chiếu mạng phước hồng,\nSố người trường thọ tấm lòng trung cang.\nTâm tánh cứng cỏi vững vàng,\nMiệng thời hay nói chẳng màng sợ ai.\nBộ miệng không kín hôm nay,\nCó việc vui miệng nói rày lậu ra.\nTiền tài y lộc xem qua,\nCũng là đủ dụng đạo nhà ấm no.\nTánh hay vui vẻ truyện trò,\nThông minh tánh sáng số đo việc làm.\nBà con lãnh đạm đành cam,\nKhông nhờ thân tộc tay làm chắc ăn.\nVắng cảnh phát đạt vượng tăng,\nĐến khi lớn tuổi như trăng đêm rằm.\nTa nên tích đức nơi tâm,\nPhải phòng có số phạm nhằm tù lao.\nCó duyên đi đứng ra vào,\nViệc khó hóa dễ chuyện nào cũng xong.\nMạng này có số quyền công,\nCũng là tài nghệ trong lòng bàn tay.\nTa nên tích đức hậu lai,\nMong nhờ vãng cảnh hưởng rày vinh quang.','Tuổi này mạng Kiếm Phong Kim, đặng Thiên Đức chiếu mạng nên trường thọ. Người có tánh cứng cỏi, thông minh, lanh lợi nhưng miệng hay nói lậu chuyện. Số phải tự lực cánh sinh, không nhờ đặng bà con thân tộc. Tuổi trẻ trắc trở duyên nợ, hậu vận mới đặng giàu sang, vinh hiển. Cần phòng số phạm lao lý.'),(10,10,'Nu','Kiếm Phong Kim','Đoán xem số mạng như là,\nQuí Dậu kim mạng số ta như vầy.\nTuổi cùng mạng kim khắc hiềm,\nTánh người cứng cỏi lập nghiêm bề ngoài.\nSố phần duyên nợ đổi thay,\nQuả Tú chiếu mạng đắng cay nợ tình.\nCó duyên sắc đẹp ba sinh,\nNhiều nơi tính lại chung tình khó xong.\nThiên Đức chiếu mạng phước hồng,\nSố người trường thọ tấm lòng trung cang.\nTâm tánh cứng cỏi vững vàng,\nMiệng thời hay nói chẳng màng sợ ai.\nBộ miệng không kín hôm nay,\nCó việc vui miệng nói rày lậu ra.\nTiền tài y lộc xem qua,\nCũng là đủ dụng đạo nhà ấm no.\nTánh hay vui vẻ truyện trò,\nThông minh tánh sáng số đo việc làm.\nBà con lãnh đạm đành cam,\nKhông nhờ thân tộc tay làm chắc ăn.\nVắng cảnh phát đạt vượng tăng,\nĐến khi lớn tuổi như trăng đêm rằm.\nTa nên tích đức nơi tâm,\nPhải phòng có số phạm nhằm tù lao.\nCó duyên đi đứng ra vào,\nViệc khó hóa dễ chuyện nào cũng xong.\nMạng này có số quyền công,\nCũng là tài nghệ trong lòng bàn tay.\nTa nên tích đức hậu lai,\nMong nhờ vãng cảnh hưởng rày vinh quang.','Nữ mạng Quý Dậu, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình ngay thẳng, siêng năng lo liệu. Số này có tay cầm của, hậu vận đặng an nhàn sung túc, hưởng phước đức của tổ tiên.'),(10,12,'Nam','Đại Hải Thủy','Đoán xem số mạng như là,\nQuí Hợi mạng Thủy số ta như vầy.\nTuổi Thủy mạng Thủy số nầy,\nPhạm số té nặng chịu rày tổn thân.\nPhải phòng bịnh rủi chịu rày bổn thân.\nSố người đau ốm nhiều lần không an.\nChiêm bao thường thấy tự tung,\nLuân xem tiền của đến nay.\nĐủ ăn đủ mặc của rày hao ra.\nĐặng tiền sang số của ta,\nĐoán xem tiền của gia đình.\nKhắc hào chồng vợ đỗi dời đôi sau.\nKhắc hào chồng vợ đỗi dời đôi sau,\nSố người hưởng trưởng thọ nạn tai nhiều.\nSố ta tự tạo lập thân,\nĐệ huynh thân tộc khó gần cậy nương.\nGia đình đổi dời đôi độ tha hương,\nĐặng nên cơ nghiệp vững bền.\nGia đình hưng vượng tuổi niên,\nĐêm nằm giấc mộng vậy thời.\nNhẹ mình hay bổng đi chơi tung hoành.\nKhá trau tâm niệm để đành,\nHưởng điều phát đạt phước sanh thọ trường.','Tuổi này mạng Đại Hải Thủy. Người có tánh tình bao dung, nhân hậu, thông minh, mưu lược. Thuở nhỏ hay đau ốm, bịnh tật, cần phòng tai nạn sông nước hoặc té ngã. Số tự lập, tay trắng tạo nên cơ nghiệp, ly hương mới phát đạt. Duyên nợ trắc trở, vợ chồng hay ly tán hoặc phải dời đổi nhà cửa nhiều lần mới yên. Hậu vận đặng giàu sang, an nhàn, trường thọ nhờ tu tâm tích đức.'),(10,12,'Nu','Đại Hải Thủy','Đoán xem số mạng như là,\nQuí Hợi mạng Thủy số ta như vầy.\nTuổi Thủy mạng Thủy số nầy,\nPhạm số té nặng chịu rày tổn thân.\nPhải phòng bịnh rủi chịu rày bổn thân.\nSố người đau ốm nhiều lần không an.\nChiêm bao thường thấy tự tung,\nLuân xem tiền của đến nay.\nĐủ ăn đủ mặc của rày hao ra.\nĐặng tiền sang số của ta,\nĐoán xem tiền của gia đình.\nKhắc hào chồng vợ đỗi dời đôi sau.\nKhắc hào chồng vợ đỗi dời đôi sau,\nSố người hưởng trưởng thọ nạn tai nhiều.\nSố ta tự tạo lập thân,\nĐệ huynh thân tộc khó gần cậy nương.\nGia đình đổi dời đôi độ tha hương,\nĐặng nên cơ nghiệp vững bền.\nGia đình hưng vượng tuổi niên,\nĐêm nằm giấc mộng vậy thời.\nNhẹ mình hay bổng đi chơi tung hoành.\nKhá trau tâm niệm để đành,\nHưởng điều phát đạt phước sanh thọ trường.','Nữ mạng Quý Hợi, thờ Bà Cửu Thiên Huyền Nữ độ mạng. Tánh tình đoan trang, hiền hậu, lo toan gia đình chu đáo. Số này tuổi trẻ bôn ba, nhiều phen thay đổi nơi ăn chốn ở, hậu vận đặng hưởng phước an nhàn vinh hoa.');
