CREATE TABLE `so29_hanhangnam` (
  `ID` int(11) NOT NULL AUTO_INCREMENT,
  `TuoiAmLich` int(11) NOT NULL,
  `TenHan` varchar(255) DEFAULT NULL,
  `LoiGiai` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`ID`)
