/*!40000 ALTER TABLE `so29_hanhangnam` DISABLE KEYS */;
INSERT INTO `so29_hanhangnam` VALUES (1,1,'Thái Tế','Hạn Thái Tế hay sanh điều tai hại và buồn rầu, mỗi việc nên để phòng, hay xảy ra việc chẳng lành, hoặc có việc bi ai, làm ăn không yên trí.'),(2,2,'Thái Dương','Hạn Thái Dương năm nay làm ăn khá, mỗi việc đều được bình an, gia đạo an lành, lo tính việc chi cũng đặng sáng suốt, gặp hung hóa hiền.'),(3,3,'Tang Môn','Hạn Tang Môn năm nay phòng có việc bi ai, tang phục, hao tài, tốn của, hoặc có đau ốm, hay xảy ra việc rầu muộn, mỗi việc nên để phòng.'),(4,4,'Thái Âm','Hạn Thái Âm năm nay làm ăn khá, có người nhơn giúp đỡ, lo tính việc chi cũng đặng dễ.'),(5,5,'Quan Phù','Hạn Quan Phù năm nay làm ăn có điều cản trở, hao tài tốn của, không đặng yên trí, phòng việc quan, lời nói hay rủi ro, sanh việc rầy rà, nên nhẫn nại.'),(6,6,'Tử Phù','Hạn Tử Phù năm nay làm ăn không khá, phòng việc bi ai trong nhà, hoặc điều tang phục, không đặng an vui, nên cầu khẩn.'),(7,7,'Tế Phá','Hạn Tế Phá năm nay làm ăn không khá, nuôi thú vật bất lợi, mỗi việc phải để phòng, không thuận ý, hay cản trở việc làm ăn, hay hao tốn vô cớ.'),(8,8,'Long Đức','Hạn Long Đức năm nay làm ăn khá lắm, mỗi việc đều thuận ý, dễ làm ăn, đi đường cũng tốt, mua bán thuận lợi, nên mở việc làm ăn.'),(9,9,'Bạch Hổ','Hạn Bạch Hổ năm nay phòng bổn thân bất lợi, và động việc tang phục, hao tài tốn của, hoặc sanh bịnh hoạn, nhiều việc lo buồn, nên ngừa chướng đánh.'),(10,10,'Phước Đức','Hạn Phước Đức năm nay làm ăn khá lắm, mỗi việc đặng bình an, đặng vui mừng, đặng mạnh giỏi, lời nói đặng phát đạt, gặp việc may có tài.'),(11,11,'Điếu Khách','Hạn Điếu Khách năm nay đi sông, ghe, bờ, cầu, leo trèo giữ mình kẻo bị té, phòng việc rầy rà, và có động việc quan, ăn nói phải lựa điều, sanh việc lôi thôi.'),(12,12,'Bịnh Phù','Hạn Bịnh Phù năm nay hay sanh bịnh hoạn, sanh việc than buồn, mỗi việc nên cẩn thận, gia đạo không đặng an, hoặc là trong nhà có người khác đau, hoặc nuôi dưỡng tốn hao.'),(13,13,'Thái Tế','Hạn Thái Tế hay sanh điều tai hại và buồn rầu, mỗi việc nên để phòng, hay xảy ra việc chẳng lành, hoặc có việc bi ai, làm ăn không yên trí.'),(14,14,'Thái Dương','Hạn Thái Dương năm nay làm ăn khá, mỗi việc đều được bình an, gia đạo an lành, lo tính việc chi cũng đặng sáng suốt, gặp hung hóa hiền.'),(15,15,'Tang Môn','Hạn Tang Môn năm nay phòng có việc bi ai, tang phục, hao tài, tốn của, hoặc có đau ốm, hay xảy ra việc rầu muộn, mỗi việc nên để phòng.'),(16,16,'Thái Âm','Hạn Thái Âm năm nay làm ăn khá, có người nhơn giúp đỡ, lo tính việc chi cũng đặng dễ.'),(17,17,'Quan Phù','Hạn Quan Phù năm nay làm ăn có điều cản trở, hao tài tốn của, không đặng yên trí, phòng việc quan, lời nói hay rủi ro, sanh việc rầy rà, nên nhẫn nại.'),(18,18,'Tử Phù','Hạn Tử Phù năm nay làm ăn không khá, phòng việc bi ai trong nhà, hoặc điều tang phục, không đặng an vui, nên cầu khẩn.'),(19,19,'Tế Phá','Hạn Tế Phá năm nay làm ăn không khá, nuôi thú vật bất lợi, mỗi việc phải để phòng, không thuận ý, hay cản trở việc làm ăn, hay hao tốn vô cớ.'),(20,20,'Long Đức','Hạn Long Đức năm nay làm ăn khá lắm, mỗi việc đều thuận ý, dễ làm ăn, đi đường cũng tốt, mua bán thuận lợi, nên mở việc làm ăn.'),(21,21,'Bạch Hổ','Hạn Bạch Hổ năm nay phòng bổn thân bất lợi, và động việc tang phục, hao tài tốn của, hoặc sanh bịnh hoạn, nhiều việc lo buồn, nên ngừa chướng đánh.'),(22,22,'Phước Đức','Hạn Phước Đức năm nay làm ăn khá lắm, mỗi việc đặng bình an, đặng vui mừng, đặng mạnh giỏi, lời nói đặng phát đạt, gặp việc may có tài.'),(23,23,'Điếu Khách','Hạn Điếu Khách năm nay đi sông, ghe, bờ, cầu, leo trèo giữ mình kẻo bị té, phòng việc rầy rà, và có động việc quan, ăn nói phải lựa điều, sanh việc lôi thôi.'),(24,24,'Bịnh Phù','Hạn Bịnh Phù năm nay hay sanh bịnh hoạn, sanh việc than buồn, mỗi việc nên cẩn thận, gia đạo không đặng an, hoặc là trong nhà có người khác đau, hoặc nuôi dưỡng tốn hao.'),(25,25,'Thái Tế','Hạn Thái Tế hay sanh điều tai hại và buồn rầu, mỗi việc nên để phòng, hay xảy ra việc chẳng lành, hoặc có việc bi ai, làm ăn không yên trí.'),(26,26,'Thái Dương','