INSERT INTO `so30_loikhuyen` VALUES (1,'Lời khuyên','Ai có bịnh trẫm trọn uống thuốc không mạnh. Nên vọng bàn nương dăng trà quả, dọn ngoài Trời hình kiếu như trên đây, rồi cố tâm cầu nguyện, dọn ra ngoài Trời hình kiếu như trên đây, rồi cố tâm cầu nguyện, đặng giữ lấy mình. Cung thỉnh Thần Giác, sanh hài, làm duyên lành, sanh tai biến, thể giáng hạ tại nạn, cứ thể Giáng hạ tại nạn, cứ thể Giáng hạ tại nạn, cứ thể Giáng hạ tại nạn, tức là giữ mình. Lời khuyên dân chúng cõi đời, lời nói đời này, thi hành theo lời dặn dò là lời khuyên đời này, thi hành theo lời dặn dò là lời khuyên đời này, thi hành theo lời dặn dò là lời khuyên đời này, thi hành theo lời dặn dò là lời khuyên.');
