INSERT INTO `so30_ngay_cau_tien` VALUES (1,1,'ngày Tý, ngày Hợi','Tuổi Tý: ngày Tý, ngày Hợi, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(2,2,'ngày Tý, ngày Ngọ','Tuổi Sửu: ngày Tý, ngày Ngọ, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(3,3,'ngày Sửu, ngày Mùi','Tuổi Dần: ngày Sửu, ngày Mùi, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(4,4,'ngày Dần, ngày Thân','Tuổi Mão: ngày Dần, ngày Thân, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(5,5,'ngày Thìn, ngày Dậu','Tuổi Thìn: ngày Thìn, ngày Dậu, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(6,6,'ngày Tỵ, ngày Tuất','Tuổi Tỵ: ngày Tỵ, ngày Tuất, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(7,7,'ngày Tý, ngày Hợi','Tuổi Ngọ: ngày Tý, ngày Hợi, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(8,8,'ngày Tý, ngày Ngọ','Tuổi Mùi: ngày Tý, ngày Ngọ, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(9,9,'ngày Sửu, ngày Mùi','Tuổi Thân: ngày Sửu, ngày Mùi, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(10,10,'ngày Dần, ngày Thân','Tuổi Dậu: ngày Dần, ngày Thân, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(11,11,'ngày Thìn, ngày Dậu','Tuổi Tuất: ngày Thìn, ngày Dậu, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.'),(12,12,'ngày Tỵ, ngày Tuất','Tuổi Hợi: ngày Tỵ, ngày Tuất, nên cầu.\n\nMấy ngày ở trên đây là ngày của Tiên Bà ở nơi cung trăng giáng hạ độ tuổi nào theo ngày ấy. Khi cúng độ tối có trăng thì tốt, nếu bịnh gấp rút lắm thì viết bài vị cúng việc khẩn cầu, khi mạnh cúng cũng tốt. Dầu bịnh chi trong lòng thành tâm cầu nguyện thì bịnh ấy cũng được giải trừ được.');
