INSERT INTO `so32_co_hom_khong` VALUES (1,'Mạng Kim',1,1,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có dạng 3 người con lo việc, có hòm, có người thân nhơn và luận lý đến nhiều, và có thầy chùa đưa linh.'),(2,'Mạng Mộc',2,1,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có dạng 3 người con lo việc, có hòm, có người thân nhơn và luận lý đến nhiều, và có thầy chùa đưa linh.'),(3,'Mạng Thủy',3,1,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có dạng 3 người con lo việc, có hòm, có người thân nhơn và luận lý đến nhiều, và có thầy chùa đưa linh.'),(4,'Mạng Hỏa',4,1,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có dạng 3 người con lo việc, có hòm, có người thân nhơn và luận lý đến nhiều, và có thầy chùa đưa linh.'),(5,'Mạng Thổ',5,1,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có dạng 3 người con lo việc, có hòm, có người thân nhơn và luận lý đến nhiều, và có thầy chùa đưa linh.'),(6,'Mạng Kim',2,2,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 2 người con trai, 1 người con gái, bà con thân nhơn đến nhiều, hòm rương sẵn, có thầy chùa đưa linh.'),(7,'Mạng Mộc',3,2,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 2 người con trai, 1 người con gái, bà con thân nhơn đến nhiều, hòm rương sẵn, có thầy chùa đưa linh.'),(8,'Mạng Thủy',4,2,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 2 người con trai, 1 người con gái, bà con thân nhơn đến nhiều, hòm rương sẵn, có thầy chùa đưa linh.'),(9,'Mạng Hỏa',5,2,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 2 người con trai, 1 người con gái, bà con thân nhơn đến nhiều, hòm rương sẵn, có thầy chùa đưa linh.'),(10,'Mạng Thổ',6,2,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 2 người con trai, 1 người con gái, bà con thân nhơn đến nhiều, hòm rương sẵn, có thầy chùa đưa linh.'),(11,'Mạng Kim',3,3,'Theo mạng này mà sanh nhằm tháng này, đến khi mãn có 3 người con trai, hai người con gái, có hòm sơn đen, đầu sơn mai đến chiều mãn, có thầy chùa đưa linh.'),(12,'Mạng Mộc',4,3,'Theo mạng 