/*!40000 ALTER TABLE `so32_coi_khi_chet` DISABLE KEYS */;
INSERT INTO `so32_coi_khi_chet` VALUES (1,1,4,'Trường Sanh','Số này đến khi chung sự đau hai ngày thì mãn số, ngày ấy trời nóng, hòm rương sẵn, con trai hai người, con gái hai người, có hạn 45-46 tuổi nhờ đặng qua thì hưởng thọ đến 67 tuổi thì đủ số, có thầy chùa đưa linh.'),(2,1,5,'Mộc Dục','Số này đến khi đau bịnh mà mãn số, lúc ấy trời lặm, hạn 17, 18, 19 tuổi khắc kỳ lắm, qua đặng thì hưởng thọ đến 72 tuổi, mới mãn số, thầy mặt một đứa con trai, hai đứa con gái đưa linh, số không có thầy chùa.'),(3,1,6,'Quan Đái','Số này đến khi đau bịnh mà mãn số, hạn 33, 34 tuổi khắc kỳ, như qua đặng thì hưởng thọ đến 64 tuổi, mãn lúc mùa đông tuyết trời lạnh có hòm sẵn, có người con trai, hai người con gái đặng thấy mặt, có thầy chùa đưa linh.'),(4,1,7,'Lâm Quan','Số này thọ bịnh 2, 3 ngày mãn số, lúc chiều tối, có hòm rương sẵn, có người con trai, một người con gái đặng thấy mặt, có thầy chùa đưa linh.'),(5,1,8,'Đế Vượng','Số này thọ bịnh ngủ mê 5 ngày rồi mãn, có con trai và con gái 5 người đặng thấy mặt, có hòm rương sẵn, có thầy chùa đưa linh.'),(6,1,9,'Suy','Số này khi mãn trong mùa trời mưa, khi chờn chơi trong, có hòm rương đủ, có hòm tủ, con trai hai người, gái ba người đặng thấy mặt, có thầy chùa đưa linh.'),(7,1,10,'Bịnh','Số này đến khi chết đau bịnh mà mãn số, chết đi sống lại 1, 2 ngày mãn luôn, khi mãn nhằm trời Đông nhằm trời lạnh, có hòm tủ nứt không liền, có con trai 1 người, con gái 2 người đặng thấy mặt, có thầy chùa đưa linh.'),(8,1,11,'Tử','Số này đến khi bịnh mà mãn số, nhằm mùa Hạ, ngày mãn có trời mưa, số có một người con gái, và một người rể đặng thấy mặt, có hòm rương sẵn, bà con ít, không có thầy chùa đưa linh.'),(9,1,12,'Mộ','Số này khi mãn trong mùa Thu có hòm rương sẵn, có một người con trai, một người con gái kêu rê về lo an táng, có nhạc lễ, có bà con đồng, có thầy chùa đưa linh.'),(10,1,1,'Tuyệt','Số này đến khi chết đau bịnh mà mãn số, có hai người con trai, một người con gái thấy mặt, nhưng nhằm lúc con nghèo lắm, phải mượn hòm đem về chôn, không có thầy chùa đưa linh.'),(11,1,2,'Thai','Số này đến khi chết, sớm còn đi chơi chở đồng người lo nói chuyện bàn cãi, rồi về nhà tối mãn, nhằm mùa Đông, ngày chờn có trời mưa, có hai người con trai, một người con gái đặng thấy mặt, có hòm rương sẵn, có nhạc lễ, có thầy chùa đưa linh, bà con tới đồng đưa rất đông.'),(12,1,3,'Dưỡng','Số này đến khi chết, sớm còn đi chơi chở đồng người lo nói chuyện bàn cãi, rồi về nhà tối mãn, nhằm mùa Đông, ngày chờn có trời mưa, có hai người con trai, một người con gái đặng thấy mặt, có hòm rương sẵn, có nhạc lễ, có thầy chùa đưa linh, bà con tới đồng đưa rất đông.'),(13,2,10,'Trường Sanh','Số này đến khi chung sự đau hai ngày thì mãn số, ngày ấy trời nóng, hòm rương sẵn, con trai hai người, con gái hai người, có hạn 45-46 tuổi nhờ đặng qua thì hưởng thọ đến 67 tuổi thì đủ số, có thầy chùa đưa linh.'),(14,2,11,'Mộc Dục','Số này đến khi đau bịnh mà mãn số, lúc ấy trời lặm, hạn 17, 18, 19 tuổi khắc kỳ lắm, qua đặng thì hưởng thọ đến 72 tuổi, mới mãn số, thầy mặt một đứa con trai, hai đứa con gái đưa linh, số không có thầy chùa.'),(15,2,12,'Quan Đái','Số này đến khi đau bịnh mà mãn số, hạn 33, 34 tuổi khắc kỳ, như qua đặng thì hưởng thọ đến 64 tuổi, mãn lúc mùa đông tuyết trời lạnh có hòm sẵn, có người con trai, hai người con gái đặng thấy mặt, có thầy chùa đưa linh.'),(16,2,1,'Lâm Quan','Số này thọ bịnh 2, 3 ngày mãn số, lúc chiều tối, có hòm rương sẵn, có người con trai, một người con gái đặng thấy mặt, có thầy chùa đưa linh.'),(17,2,2,'Đế Vượng','Số này thọ bịnh ngủ mê 5 ngày rồi mãn, có con trai và con gái 5 người đặng thấy mặt, có hòm rương sẵn, có thầy chùa đưa linh.'),(18,2,3,'Suy','Số này khi mãn trong mùa trời mưa, khi chờn chơi trong, có hòm rương đủ, có hòm tủ, con trai hai người, gái ba người đặng thấy mặt, có thầy chùa đưa linh.'),(19,2,4,'Bịnh','Số này đến khi chết đau bịnh mà mãn số, chết đi sống lại 1, 2 ngày mãn luôn, khi mãn nhằm trời Đông nhằm trời lạnh, có hòm tủ nứt không liền, có con trai 1 người, con gái 2 ng