/*!40000 ALTER TABLE `so33_loigiai_chiet` DISABLE KEYS */;
INSERT INTO `so33_loigiai_chiet` VALUES ('Bạc Hổ','Số này đặng Phước Lộc, tài lợi, số người hay đi xa xứ, có công danh, còn vợ chồng là số không được bền lâu.'),('Châu Ung','Số này gặp nhiều tai nạn, phải phòng ngừa kẻ tiểu nhân phản, vợ chồng có việc buồn giận, vợ chồng xung khắc với nhau, có sự khổ tâm.'),('Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi hay chết lắm, nếu không chết thì không sanh đẻ và nuôi không lớn nên rất bất lợi.'),('Hiệp','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn, lại thêm sanh đẻ nhiều, cái huê lợi ấy sanh lợi thêm và thêm thu trữ đặng nhiều.'),('Hướng','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn lại thêm sanh đẻ đặng nhiều, có huê lời, cái huê lợi ấy nó sanh thêm thạnh vượng.'),('Không','Số này không có nuôi trâu heo và các loài thú, nếu nuôi thì hay sanh ra nhiều điều trắc trở lắm, lại thêm không lớn không sanh đẻ, bất lợi.'),('Kiên','Số này có số nuôi trâu heo và các loài thú nó sanh đẻ nhiều, nuôi mau lớn, đặng thạnh vượng, cái huê lợi lớn ấy, còn lập nên sự nghiệp vững bền đặng.'),('Ngoại Sát','Số này phạm số Ngoại Sát, có việc đi đường, hoặc đổi dời chỗ ở, phòng có việc quan làng, ngừa kẻ tiểu nhơn phản.'),('Niên Sát','Số này gặp nhiều tai nạn, phải phòng ngừa kẻ tiểu nhơn phản, vợ chồng có việc buồn giận với nhau.'),('Phá','Số này có số nuôi trâu, nuôi heo và các loài thú, nhưng mà khi nuôi 2, 3 lứa đầu, có hao tổn lôi thôi, rồi sau nuôi đặng trở nên thạnh vượng lắm.'),('Vong Thân','Số này có việc đi đường nhiều, hoặc đổi dời chỗ ở, phòng có việc quan làng, vợ chồng có việc buồn giận chút ít, sanh việc xung buồn.'),('Vượng','Số này có việc đi đường nhiều, hoặc đổi dời chỗ ở, phòng có việc quan làng, vợ chồng có việc buồn giận, vợ chồng có việc vui gian với nhau.');
