INSERT INTO `so34_trietly` VALUES (1,'Giải Giác hồng trần','Lúc tâm thần bình tĩnh biện bạch đôi lời \"cổ ngữ\" lưu truyền. Có lời của Đức Phật tổ từ tôn nói rằng, tiên giác nhi hậu giác tha.\nNghĩa: Biết trước cho người khác biết sau,\nĐời nhà Hớn: có ông Hán Công nói rằng:\nBiết mà không nói, thì đại bất nhơn.\nNói không đủ lời là đại bất nghĩa.\nVì vậy mà xét phận hổ thầm nên tôi gắng công tìm soạn trích lục đạo trong chốn hồng trần, xin kết luận dưới đây.'),(2,'Cuộc Tam Hoàng Xuất Thế','Trên mới có đức Thiên Hoàng Thượng Đế.\nDưới mới có đức Thiên Hoàng Trung Đế.\nDưới nữa có Đức nhơn Hoàng Hạ Đế.\nTrời có Nhựt, nguyệt Tinh.\nĐất có Thủy Hỏa Phong.\nngười có Tinh Khí thần.'),(3,'Lời Kết Luận','Trời có Dương Khí, đất có Âm Khí,\nÂm dương tương hiệp mới được hóa sanh.\nChừng ấy mới hóa tượng thành khí ngũ thái.\nNhứt, khí thái duyệt sanh thủy,\nNhì, khí thái sơ sanh hỏa,\nTam, khí thái thủy sanh mộc,\nTứ, khí thái tố sanh kim,\nNgũ, khí thái cực sanh thổ,\nChừng ấy phù tam ngươn kỳ cực.\nKết thành tam bửu, ngũ hành thiên can, địa chi, cửu tinh, nhị thập bát tú. Đồng thọ mạng lịnh của Đức Thiên Hoàng ta trấn bốn phương tám hướng.');
/*!40000 ALTER TABLE `so34_trietly` ENABLE KEYS */;
UNLOCK TABLES;

