INSERT INTO `so35_nhan_qua` VALUES (1,'Khẩu','Kinh Thiên, Thị Địa','Bá họa giáng ương'),(2,'Khẩu','Mắng gió chửi mưa','Ngày cuồng đền tội'),(3,'Khẩu','Hỗn ẩu anh em','Cô độc một mình'),(4,'Khẩu','Chê người rách lạnh','Chuyển kiếp cơ hàn'),(5,'Khẩu','Sanh con không dạy','Hoạn họa trùng lai'),(6,'Khẩu','Dùng linh cầm hoặc','Mắc mưu liên lụy'),(7,'Khẩu','Gạt gái bỏ gái','Vợ bỏ thình lình'),(8,'Khẩu','Đặng thờ chê thất thế','Suy sụp nan cầu'),(9,'Khẩu','Xúi con hiếp người','Chịu đời thất thế'),(10,'Khẩu','Xúi vợ chồng tan rã','Gia đạo linh đinh'),(11,'Tâm','Bỏ mồ ly loạn','Ba đời lưu lạc'),(12,'Tâm','Hủy hoại lúa gạo','Thiếu ăn thiếu mặc'),(13,'Tâm','Em côi anh bỏ','Gián cảnh thất thời'),(14,'Tâm','Thấy của tiền tham','Gián cảnh bần hàn'),(15,'Tâm','Sát sanh cầu thọ','Ác lai quả báo'),(16,'Tâm','Giết mẹ bắt con','Chuyển kiếp mồ côi'),(17,'Tâm','Hại dân khuấy chúng','Câm đuôi điếc cùi'),(18,'Tâm','Làm ăn bất lương','Ngục hình đày đọa'),(19,'Tâm','Pha cầu đào lộ','Oan gia nghiệp chướng'),(20,'Can','Tánh giận quá độ','Hư gan sanh bịnh'),(21,'Tỳ','Ăn vật phong độc','Tỳ vị sanh trùng'),(22,'Phế','Khinh thị kim ngân','Bị suy lá phổi'),(23,'Thận','Dâm dục quá độ','Thận kém sanh lao'),(24,'Nhĩ','Chẳng nghe lời lành','Con cháu hung ác'),(25,'Nhãn','Thấy nền lòng ghét','Vận thanh phi tiêu'),(26,'Nhãn','Thấy sắc cổ dâm','Vợ con tâm lạng');
/*!40000 ALTER TABLE `so35_nhan_qua` ENABLE KEYS */;
UNLOCK TABLES;

