INSERT INTO `so36_ngu_tang` VALUES ('Bộ Can','Mộc','Thuộc mộc, chủ về sơ tiết, tàng huyết, quản lý sự vận động.'),('Bộ Phế','Kim','Thuộc kim, chủ về khí, quản lý việc hô hấp và bảo vệ cơ thể.'),('Bộ Tâm','Hỏa','Thuộc hỏa, chủ về thần minh, nơi tàng trữ cái thần của con người.'),('Bộ Thận','Thủy','Thuộc thủy, chủ về tàng tinh, quản lý xương cốt và sự phát dục.'),('Bộ Tỳ','Thổ','Thuộc thổ, chủ về vận hóa đồ ăn thức uống, nuôi dưỡng cơ thể.');
