LOCK TABLES `so37_loi_ket` WRITE;
/*!40000 ALTER TABLE `so37_loi_ket` DISABLE KEYS */;
INSERT INTO `so37_loi_ket` VALUES (1,'Hội Tam Giáo đồng nhận rằng','Trong nhơn quả phải có quả báo, lại thêm đạo Thiên Chúa Giáo có nhân cuộc báo quả. Nếu người có lưu tâm huệ cổ trong thế sự, thì hiện thấy cuộc báo quả nhãn tiền tại thế. Còn cuộc luân hồi, nhờ có kinh sách có ghi chép sự tích truyền lại cho hậu thế, chuyện có rõ ràng.'),(2,'Phân Giải Hạn Kỳ Báo Quả','Vì lẽ gì người đần làm lành? Tại sao có hoạn nạn không an? Đó là cái oan khiên nghiệp chướng của ông bà, hoặc của cha mẹ, hoặc trước mình tạo ác, chưa kịp đến, hoặc đến chưa rồi, kiếp này đang còn trả quả tiền khiên. Hãy làm lành lánh dữ để phước đức lại cho con cháu.'),(3,'Bài An Thần Tự Tỉnh','Cái bản tâm mình biết sử dụng nó thành tâm thần. Nếu không biết sử dụng nó thành tà tâm. Dầu thân hay là tà, cũng tự mình giáo dưỡng nó hiện hình. Nên làm lành để đặng hưởng phước lộc.'),(4,'Đôi hàng kính tặng','Kính trình Liệt vị khán quan, dày công điển nghĩa vẹn toàn quyển ni. Hiệu sách Tam Thế vậy thì, coi là thường sự để chi hiểu rành... (Ghi toàn bộ bài thơ ở trang 359)'),(5,'Thi','DƯƠNG danh chép gởi để truyền đời,\nCỘNG sắp nên bày rạng khắp nơi.\nHẦU tặng khán quan chư độc giả,\nHIỆU nghiệm tương lai rõ vận thời.\nKHƯƠNG ninh suy bỉ đều biết trước,\nĐỨC thắng tài sơ chẳng vẹn lời,\nSOẠN thấy sót thưa mong sửa đổi,\nGIẢ ơn đồng chủng nghĩa vơi vơi.');
/*!40000 ALTER TABLE `so37_loi_ket` ENABLE KEYS */;
UNLOCK TABLES;

