LOCK TABLES `tudien_loigiai_chung` WRITE;
/*!40000 ALTER TABLE `tudien_loigiai_chung` DISABLE KEYS */;
INSERT INTO `tudien_loigiai_chung` VALUES (13,'Ám Lộc','Số này phạm Ám Lộc, ăn mặc có ít, không nhờ anh em, gần người sang trọng, sự nghiệp không ở xứ cũ, tuổi lớn ăn ở đặng yên, làm ăn mới khá.'),(13,'Âm Nhạc','Số này: Có tánh thông minh, có nghề đờn kìm thông, có danh tiếng và vui vẻ, đến xứ nào cũng được người trọng hậu, quí thể.'),(13,'Bạch Hạt','Số này đặng Bạch Hạt, số này đi mua bán tứ phương, có tiền lúa nhiều, tuổi lớn làm ăn thạnh vượng, đặng thong thả.'),(13,'Bát Bại','Số phạm Bát Bại thì gia đình sự nghiệp lập không thành, trai đi đông tây, gái đi Nam Bắc, số lưu lạc phong trần.'),(13,'Bịnh Lộc','Số này phạm Bịnh Lộc hay có bịnh hoạn lắm, không ở xứ cũ tu hành không đặng, giữ tiết kiệm đời cực khổ mà cũng nghèo.'),(13,'Bối Lộc','Số này phạm Bối Lộc, anh em ở xa cách, đi biệt xứ không trở về, đi có nhiều xứ, đồ lao cực khổ, mà không khá.'),(13,'Bột Cưu','Số này đặng Bột Cưu, ở đời hay có tánh làm lành, y lộc không thiếu, tuổi nhỏ chưa khá, đến lớn đặng vui vẻ, thạnh vượng.'),(13,'Chánh Lộc','Số này đặng Chánh Lộc, tánh cần kiệm, đi lưu lạc xứ khác khi tuổi lớn làm ăn trở nên sự nghiệp, vợ chồng con cháu vui vẻ.'),(13,'Châu Tước','Số này đặng Châu Tước tánh hạnh đặng cao cường, ăn mặc không thiếu, tiền tài thạnh vượng, ra đường nhiều người kính trọng.'),(13,'Cô Thần','Số phạm Cô Thần, số khắc vợ chồng, khắc con, lại thêm phận bạc, lại có anh em không hòa, mỗi việc gì tự liệu.'),(13,'Dương Vận','Số này Dương Vận thì anh em cốt nhục không hòa, có số làm thợ khéo, anh em ở xa cách không nhờ.'),(13,'Giác Ưng','Số này đặng Giác Ưng, tâm tánh cao thượng có quyền hành tuổi lớn có tài lộc nhiều, tánh ưa diện tiệc, vui vẻ đời.'),(13,'Hao Lộc','Số này phạm Hao Lộc, tánh hay ăn diện tiệc, hay kết nhơn tình, chơi gần người sang trọng, sự nghiệp phá tan, đến xứ khác mới lập an.'),(13,'Hề Sắt','Số này đặng Hề Sắt, có tài bằng người, nghề nghiệp rất tinh thông làm quan cũng tốt, làm dân cũng có tài.'),(13,'Hiệp Lộc','Số này đặng Hiệp Lộc, thì đặng giàu sang kinh dinh có tánh thông minh, thân mạng không tai họa, hưởng vinh hoa.'),(13,'Hoa Cái','Số này đặng Hoa Cái, thì đặng có duyên nhiều người thương có phát 3 tài giỏi, có lộc thực nhiều, người ta hay kính trọng.'),(13,'Hoàng Quý','Số này: Không có số ở theo làng xóm làm ăn, chỉ có cái số ở theo chốn công môn, làm nghề văn chương thì tốt.'),(13,'Hồng Cao','Số này đặng Hồng Cao, số này hay lui tới chốn quan trường, cái mạng đặng hưng vượng, lộc thực tự nhiên có, một đời đặng vui vẻ.'),(13,'Hướng Lộc','Số này có tài lộc thạnh vượng, có ruộng vườn, có tánh tốt, việc ăn mặc đủ, gặp hung hóa hiền, cầu quan có quới nhơn kính trọng.'),(13,'Khổn Lộc','Số này phạm Khổn Lộc, anh em bà con không đặng gần, ăn mặc thiếu hẹp, tánh can cường, nhiều người ghét, tuổi nhỏ nghèo, tuổi lớn làm khá.'),(13,'Khổng Tước','Số này đặng Khổng Tước, thì có danh tiếng, gần người sang trọng, làm ăn có chí lo liệu, biết tự lập lấy thân.'),(13,'Kiếp Sát','Số này phạm Kiếp Sát, khắc cha mẹ, khắc vợ con, có phước thì qua, bằng không thì đi ăn xin, số gái thay đổi ba đời chồng.'),(13,'Kim Kê','Số này đặng Kim Kê, tánh hạnh can đảm, văn chương giỏi, có nghề khéo, có danh tiếng lộc thực nhiều.'),(13,'Kim Ô','Số này đặng Kim Ô, tánh thông minh hiểu việc, đi xứ nào cũng có tài lợi thạnh vượng, sự nghiệp đặng an cư.'),(13,'Lang Phạm','Số này có lập sự nghiệp ở xứ khác thì tốt, và có ruộng đất bằng như ở xứ cha mẹ sanh thì thất bại.'),(13,'Lục Hại','Số này phạm Lục Hại, khắc cha mẹ, anh em, thân tộc, bề vợ chồng con cái cũng xung khắc, có số đi tu thì đắc quả.'),(13,'Lục Hạp','Số này đặng Lục Hạp thì cha mẹ, anh em, gia đình, bà con, làm ăn cũng đều thuận hạp tất cả, việc ăn mặc rộng rãi.'),(13,'Ngoại Sát','Số này phạm Ngoại Sát, không ở xứ cha mẹ, đi nơi khác xứ làm ăn khá, khắc vợ chồng, khắc con, tay trắng lập nên sự nghiệp.'),(13,'Nhựt Mã','Số này đặng Nhựt Mã, tánh hay đi nhiều, làm ăn khá, có điền địa, thâu tài lợi nhiều, gia trụ ít lo, ra đường nhiều trọng hậu.'),(13,'Niên Sát','Số này phạm Niên Sát, không ở chỗ cha mẹ lập, đi chỗ khác làm ăn khá, tự lập nên sự nghiệp, không nhờ anh em.'),(13,'Phá Gia Sát','Số này ở xứ cha mẹ sanh, làm ăn lập nghiệp không thành, có số đi xứ khác, làm ăn lập nghiệp đặng thịnh vượng.'),(13,'Phụng Hoàng','Số này đặng Phụng Hoàng, tánh hiền lành, có chức phận lớn, bằng không thì cũng phát tài thạnh vượng rất vinh hoa.'),(13,'Phước Tinh','Số này đặng Phước Tinh; số đặng sang trọng, số sống lâu có học thi dễ lấy khoa, còn làm ăn thì đặng sản nghiệp lớn.'),(13,'Quả Tú','Số phạm Quả Tú, số khắc vợ chồng, khắc con, số phận bạc, gái gặp số này không có chồng con chi cả.'),(13,'Quan Nhơn','Số này: Số có mạng làm giàu, hay ăn của bốn phương, học tập văn chương dễ lấy khoa, số có tiền và lúa gạo.'),(13,'Quan Sát','Số này đặng Quan Sát, thuở nhỏ khó nuôi, lớn lên hay có tai nạn, và hay có bệnh, bằng không thì phải chịu tật.'),(13,'Sanh Quan','Số này: Tánh hạnh có mưu kế nhiều, và có số làm thợ mộc, số có ăn mặc đầy đủ, khéo ý, khéo tay làm.'),(13,'Sát Lộc','Số này phạm Sát Lộc, số bôn ba lội lạc, mưu sanh kế mị thường, để sanh nhai, đến tuổi gần già làm ăn mới khá.'),(13,'Sơn Lộc','Số này đặng Sơn Lộc, thuở nhỏ cách xa cha mẹ lo làm ăn, mỗi việc chi cũng chẳng đủ, tuổi lớn đặng thạnh vượng, vàng bạc đầy rương.'),(13,'Sư Thuật','Số này: Có số làm thầy, như có phước nhiều đặng làm quan, trong đời ăn mặc đầy đủ, người có tài và gần người sang trọng.'),(13,'Sư Tử','Số này đặng Sư Tử thì mạng đặng chức phận lớn, có tánh ôn hòa với đời, có nghề nghiệp lớn, làm ăn thạnh vượng.'),(13,'Tài Lộc','Số này đặng Tài Lộc, làm ăn khá, sự nghiệp lập nên, có trâu ruộng, tôi tớ đủ dùng, trở nên danh tiếng phú gia.'),(13,'Tài Phùng','Số này: Có số làm thợ may, tay cầm kéo kim chỉ, nếu không làm thợ may thì tay phải có tật, phải nên làm nghề.'),(13,'Tai Sát','Số này phạm Tai Sát nhơn thân hay có tật bịnh, không lìa và hay có tai nạn thường, hay khắc vợ chồng và con.'),(13,'Tam Hình Sát','Số phạm Tam Hình Sát thì trong đời ngừa kẻo bị bắt giam cầm, như có phước thì qua đặng bằng không, thì có bị phạm án.'),(13,'Tăng Đạo','Số này: Có tu niệm đặng đắc quả, nếu lập gia đình sau rồi cũng bỏ, dù làm nghề gì thì cũng đủ sanh nhai đó thôi.'),(13,'Thiên An','Số này đặng Thiên An, tánh can cường, tâm thông minh, có số tu niệm đắc quả, có học thi dễ lấy khoa.'),(13,'Thiên Ất','Số này gặp Thiên Ất, số người đặng sang trọng, và đặng rảnh rang, làm ruộng, nuôi thú vật đều thạnh vượng.'),(13,'Thiên Lộc','Số này đặng Thiên Lộc, có số làm quan, lại có số làm giàu tôi tớ nhiều, vợ chồng hòa thuận, hưởng phước lộc nhiều.'),(13,'Thiên Quan','Số này đặng Thiên Quan thì có chức phận, chốn triều đình đặng sống lâu thêm sang trọng.'),(13,'Thiên Sát','Số này phạm Thiên Sát, số trai khắc cha mẹ vợ, số gái khắc cha mẹ chồng, vợ chồng khắc, ít con, hay có bịnh ngặt, bằng không thì lưu lạc, một mình tìm cách sanh nhai.'),(13,'Thủ Tác','Số này: Có cái số trồng răng, nhổ răng giỏi lắm, làm nghề răng đặng khá lại có người sang trọng yêu chuộng.'),(13,'Tiệm Dược','Số này: Có số làm thầy thuốc và lập tiệm thuốc và làm thầy bói, có cái phần làm thầy, thuận số thì khá.'),(13,'Tiểu Lang Phạm','Số phạm Tiểu Lang Phạm, trai thì làm con nuôi người ta, bằng không thì cũng làm bộ hạ, gái kỵ cha mẹ, anh em, bà con.'),(13,'Toại Lộc','Số này phạm Toại Lộc, tánh hạnh nhiều mưu kế, có tánh tham, xảo trá, anh em, chồng vợ, con cháu có nhưng không hòa hiệp.'),(13,'Trủng Tề','Số này: Người có tánh can cường, có số làm con nuôi người ta, khá nên thảo luyện nghề nghiệp, để hộ thân ngày sau.'),(13,'Tú Tài','Số này: Có số về văn chương, đặng cậy nhờ về sau, công đường rất thạnh vượng, nam nữ cũng vậy.'),(13,'Tướng Tinh','Số này đặng Tướng Tinh, số có quyền hành, bỉnh cán, tuổi trẻ phát tài, lộc sớm, bề vợ chồng con cháu sung túc, rất vinh hoa.'),(13,'Văn Tinh','Số này đặng Văn Tinh có số văn chương tấn phát, làm ăn thạnh vượng, phòng còn ngày sau đi ăn xin.'),(13,'Vong Thần','Số này phạm Vong Thần, số khắc anh em, bà con, đổi chỗ ở ba lần, kỳ ba lập nên sự nghiệp, điền viên tốt.'),(13,'Vượng Lộc','Số này đặng Vượng Lộc, tiền tài hưng vượng, sản nghiệp lập thành, tánh hay chơi anh em bạn, trai có vợ, gái có chồng gặp đặng chỗ sang trọng.'),(13,'Yến Tử','Số này đặng Yến Tử tâm tánh khéo, thân hình đi đứng nhẹ nhàng, siêng năng nói chuyện, ít buồn rầu, đặng mạnh khoẻ trong mình.'),(13,'Đã Thiết','Số này: Có số làm thợ rèn, hoặc làm thợ thiết, bằng không thì cũng có nghề cầm gươm giáo, nếu không thì anh em ở cách xứ.'),(13,'Đại Bại','Số phạm Đại Bại, thì lập gia đình không thành như có chỗ khác tốt thì đỡ nhẹ bớt, bằng không sự nghiệp phiêu lưu.'),(13,'Đại Hao','Số phạm Đại Hao trong đời phải ngừa sự làm ăn thất bại, và tiền tài cẩn thận kẻo hao bớt thình lình, rán nên dè dặt.'),(13,'Đản Mạng Sát','Số phạm Đản Mạng Sát, lúc cha mẹ mới sanh khó nuôi, hạng 3 năm và hạng 6 tuổi và hạng 12 tuổi, như qua đặng thì đến 21 và 31 tuổi nên ngừa số phận ai bi.'),(13,'Địa Sát','Số này phạm Địa Sát, thường gặp tai nạn, kỵ con, khắc vợ chồng, nhưng có nghề giỏi, làm ăn no đủ.'),(14,'Giai','Số này không có số nuôi heo và các loài thú, nếu nuôi hay chết lắm, nếu không chết thì không sanh đẻ và nuôi không lớn nên rất bất lợi.'),(14,'Hiệp','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn, lại thêm sanh đẻ nhiều, cái huê lợi ấy sanh lợi thêm và thêm thu trữ đặng nhiều.'),(14,'Hướng','Số này có số nuôi trâu, nuôi heo và các loài thú, đặng mau lớn lại thêm sanh đẻ đặng nhiều, có huê lợi, cái huê lợi ấy nó sanh thêm thạnh vượng.'),(14,'Không','Số này không có nuôi trâu heo và các loài thú, nếu nuôi thì hay sanh ra nhiều điều trắc trở lắm, lại thêm không lớn không sanh đẻ, bất lợi.'),(14,'Kiên','Số này có số nuôi trâu heo và các loài thú nó sanh đẻ nhiều, nuôi mau lớn, đặng thạnh vượng, cái huê lợi lớn ấy, còn lập nên sự nghiệp vững bền đặng.'),(14,'Phá','Số này có số nuôi trâu, nuôi heo và các loài thú, nhưng mà khi nuôi 2, 3 lứa đầu, có hao tổn lôi thôi, rồi sau nuôi đặng trở nên thạnh vượng lắm.'),(15,'Bại','Số này nhằm chữ Bại, ruộng đất cha mẹ cho hay là mình tạo, ở tại chốn quan sanh thì bị thất bại, nếu có ý chí lớn, đi xứ khác lập điền viên, thì có đặng chút ít.'),(15,'Giai','Số này nhằm chữ Giai, cha mẹ cho ruộng đất giữ không được lâu dài, tự nhiên tay trắng tạo thành ruộng đất điền viên, rất nên thạnh vượng về lúc tuổi già.'),(15,'Hiệp','Số này nhằm chữ Hiệp, cha mẹ cho ruộng đất gìn giữ đặng, lại còn mua tạo thêm, cũng đều đặng tốt, số này điền địa rất thạnh vượng đặng vững bền.'),(15,'Hướng','Số này nhằm chữ Hướng, dầu ruộng đất cha mẹ cho cũng không cần gìn giữ đi đến đâu thấy ruộng đất cũng không ham bởi thế cho nên, không giữ và không tạo đặng, lo ăn mặc chơi bời đó thôi.'),(15,'Không','Số này nhằm chữ Không, dầu có ruộng cha mẹ cho, giữ cũng không còn, đến khi nghèo còn hai bàn tay trắng, rồi có ý lo tạo, hay là mua đặng ít nhiều rồi mới mở đặng nên.'),(15,'Kiên','Số này nhằm chữ Kiên, cha mẹ cho ruộng đất giữ đặng hay là tự tay tạo cũng đặng thành, và đặng thạnh vượng. Làm ăn nghề ruộng thường gặp đặng mùa, bền vững.'),(15,'Phá','Số này ngằm chữ Phá, dù cha cho ruộng đất cũng hết, rồi sau khi đến xứ khác lập lại cũng không thành, tại số khắc điền địa, số không có ruộng.'),(16,'Trực Giai','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít, cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(16,'Trực Hiệp','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì Vi Quan, dầu có thối cũng Vi Sư, nghĩa là: tới thì làm quan, còn lui thì làm thầy.'),(16,'Trực Hướng','Sanh nhằm Trực Hướng, Trực Hiệp thì sự học đặng thông minh, học ít biết nhiều, khi đi thi lấy khoa đặng bậc trung mà thôi, số này hễ tấn thì Vi Quan, dầu có thối cũng Vi Sư, nghĩa là: tới thì làm quan, còn lui thì làm thầy.'),(16,'Trực Không','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít, cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(16,'Trực Kiên','Sanh nhằm Trực Kiên thì học rất thông minh, học ít biết nhiều, sự học rất phát đạt, dầu học văn hay học võ, cũng đều lấy khoa đặng dễ dàng, khi lấy khoa thì đặng khoa cao, không có khoa nhỏ.'),(16,'Trực Phá','Sanh nhằm Trực Phá, Trực Giai, Trực Không: cái sự học nhiều, việc thông hiểu có ít, cho nên cái sự học ngày sau ít sở cậy về sự học. Bất dĩ là học cho biết chữ để nói chuyện với đời đó thôi khó lấy khoa cho đặng.'),(17,'Can Tú','Số này hội thi gặp nhằm tháng bảy, tháng tám thì lấy đặng khoa kể chắc, còn thi nhằm năm khác thì nhờ phước đức đặng chăng?'),(17,'Cung Kim','Số này có số thi kỳ nhì lấy đặng khoa cao rất vinh hiển tôn trọng đặng danh thơm.'),(17,'Di Hỏa','Số này có số thi đậu kỳ nhì, lấy đặng cao khoa, Văn Danh Huê Hạ rực rỡ tiếng khen.'),(17,'Giác Thủy','Số này có số thi đậu kỳ nhì, lấy đặng cao khoa, rất vinh hiển quyền cao chức trọng.'),(17,'Hỏa Di','Số này có số thi đậu kỳ nhì, lấy đặng tiểu khoa, cũng đặng sang trọng quý thể.'),(17,'Hư Tú','Số này hội thi gặp nhằm năm Tý, thì lấy đặng khoa là phần kể chắc, còn nhằm năm Thìn thì cũng lấy đặng khoa kể chắc, còn nhằm năm khác thì phước đức đặng chăng?'),(17,'Kim Cung','Số này có số thi đậu kỳ nhì, lấy đặng đại cao khoa, oai quyền văn và võ, đặng lâu dài.'),(17,'Lâu Tú','Số này học siêng năng, đến khi thi dễ lấy khoa, tuy học cực khổ quá mặc dầu, nên cần năng thì bảng đề chói rạng, danh thơm.'),(17,'Mão Tú','Số này hội thi gặp nhằm năm Mùi thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(17,'Mộc Thương','Số này có số thi đậu kỳ nhì, lấy đặng cao khoa, rồi sang làm quan võ có oai võ không sai.'),(17,'Ngưu Tú','Số này tuy học dở mặc dầu nhưng mà phải ráng cần học đến sau cũng lấy khoa, ngày sau cũng công danh đặng.'),(17,'Quỷ Tú','Số này thi không kỵ năm, tháng chi cả, như học giỏi siêng năng, đến khi thi dễ lấy khoa, đặng hai chữ công danh và hiển đạt.'),(17,'Tâm Tú','Số này hội thi gặp nhằm năm Dần, năm Mẹo thì lấy đặng khoa kể chắc, còn năm khác thì nhờ phước đức đặng chăng?'),(17,'Thổ Vỏ','Số này có số thi đậu kỳ nhì, lấy đặng trung khoa, rồi sau lên chức đặng bền lâu.'),(17,'Thương Mộc','Số này có số thi đậu kỳ nhì, lấy đặng trung khoa, đặng hiển vinh tôn trọng nhưng không truyền đặng cho con cháu.'),(17,'Thuỷ Giác','Số này có số thi đậu kỳ nhì, lấy đặng tiểu khoa, nhưng mà làm việc với thượng phẩm quan.'),(17,'Tinh Tú','Số này hội thi gặp nhằm năm Ngọ, thì lấy đặng khoa kể chắc, còn nhằm năm khác thì nhờ phước đức đặng chăng?'),(17,'Vỏ Thổ','Số này có số thi đặng kỳ nhì, lấy đặng đại cao khoa, lãnh quyền hành rất oai nghi vinh hiển.'),(26,'Bại Gia','Phạm nhằm số Phá Gia và Bại Gia không ở nhà của cha mẹ đặng, phải đổi dời chỗ khác, mới lập đặng thành nghiệp, nếu ở nhà của cha mẹ thì bôn ba cực khổ lắm.'),(26,'Hiệp Gia','Số này đặng số Hiệp Gia: nhà cửa lập đặng nguy nga tốt đẹp, người ăn nói đặng thông minh, mở mang, tuổi lớn 50 sắp lên thì thấy gia nghiệp tốt, của tiền lúa gạo nhiều.'),(26,'Hướng Gia','May đặng gặp số Hướng Gia: ở nhà cha mẹ đặng, để mở rộng việc làm ăn, và có số tạo lập nghiệp khác, cũng đặng thạnh vượng, làm ăn phát đạt.'),(26,'Không Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(26,'Kiên Gia','Gặp nhằm số Kiên Gia: số này lập gia nghiệp mau thì làm ăn khá lắm, còn ở nhà cũ cha mẹ, hay mua nhà cũ sửa lại thì phải chịu đau ốm hoài.'),(26,'Phá Gia','Phạm nhằm số Phá Gia và Bại Gia không ở nhà của cha mẹ đặng, phải đổi dời chỗ khác, mới lập đặng thành nghiệp, nếu ở nhà của cha mẹ thì bôn ba cực khổ lắm.'),(26,'Vong Gia','Phạm nhằm số Không Gia và Vong Gia, khi cất nhà, ở trong nhà, người đàn bà hay đau bệnh máu huyết thường, người đàn ông hay đau tốn của tiền thường, nhưng ở đặng lâu dài.'),(26,'Đại Gia','Phạm nhằm số Đại Gia: số ở nhà của cha mẹ không đặng hay sanh đều hao tốn, tai nạn, có số đi ở làng khác, tạo gia nghiệp đặng tốt, dễ làm ăn hơn chỗ cũ. Phạm số người ở chỗ quê hương lập đặng, nếu đi xứ khác tạo không thành, còn số người có lưu lạc xứ khác lập nên gia nghiệp; nếu ở lại quê hương thì lập không thành.');
/*!40000 ALTER TABLE `tudien_loigiai_chung` ENABLE KEYS */;
UNLOCK TABLES;

