INSERT INTO `vongtruongsanh` VALUES (1,'Trường Sanh','sanh con nuôi đặng phân nửa','May thay số phận Trường sanh,\nMến thương cốt nhục nương cậy nhờ đồng.\nAnh em khó đặng một dòng,\nHoặc khác cha mẹ ở trong số này.\nAnh em cách trở đông tây,\nMột nhà chung ở sanh rầy với nhau.\nThương thì giúp đỡ trước sau,\nPhải đều riêng ở mới mau nên nhà.'),(2,'Mộc Dục','sanh con nuôi đặng 2 đứa','Đoán xem Mộc Dục số này,\nGiúp lo huynh đệ lòng này thêm thương.\nViệc ta tự liệu lo lường,\nNghĩ thầm toan tính khó nương cậy nhờ.\nCầm thương lên ngựa buồn cương,\nĐông xông tây đục tứ phương lo lường.\nĐoán thương số phận vấn vương,\nMột mình tự lập gia đình trở nên.'),(3,'Quan Đái','sanh con nuôi đặng 3 đứa','Nên xem Quan Đái số ta,\nAnh em cốt nhục một nhà hoan vui.\nDầu cho xa cách buổi đầu,\nRồi sau quy hiệp có đâu xa đường.\nĐệ huynh hòa hiệp vẹn toàn,\nGia đàn tạo lập bình an vui vầy.\nNội ai nấy nấu đủ đầy,\nĐáng mừng trong họ sum vầy đệ huynh.'),(4,'Lâm Quan','sanh con nuôi đặng 3 đứa','Số ta sanh gặp lâm quan,\nAnh em sung túc hiển vang như là.\nMột gốc sanh đặng đôi ba,\nMỗi người mỗi ý vò ra lo lường.\nCó tính chiếu mạng thảm thương,\nPhải chịu cô quạnh một đường riêng lo.\nĐời sanh gặp nổi gay go,\nHai ba bốn nhánh toan lo nhiều bề.'),(5,'Đế Vượng','sanh con nuôi đặng 5 đứa','Xem hào huynh đệ tương sanh,\nMay nhằm Đế Vượng phước lành trời ban.\nBàn tính khôn khéo lo toan,\nĐấu tài thua trí là đành lập nên.\nSố này huynh đệ đôi bên,\nHoặc khác cha mẹ dưới trên thuận hòa.\nSố ta dù cách xứ xa,\nĐến khi gián cảnh một nhà đoàn viên.'),(6,'Suy','sanh con nuôi đặng 3 đứa','Than ôi gặp chữ Suy,\nKhông còn cốt nhục chia ly đôi đàng.\nHào huynh đệ không vẹn toàn,\nTai ách tật bệnh phần nàn thân sơ.\nNếu mà có phước hưởng nhờ,\nMột người chịu tật chịu khờ cho ta.\nĐến khi trong lúc tuổi già,\nHai người thấy mặt lòng mà mến thương.'),(7,'Bịnh','sanh con nuôi đặng 1 đứa','Vương mang chữ Bịnh số ta,\nĐệ huynh bất hạp sanh ra tỵ hiềm.\nAnh thời chẳng đặng trang nghiêm,\nEm thời vô lễ lỗi niềm đệ huynh.\nChẳng còn huynh đệ chi tình,\nThà không cốt nhục một mình dễ hơn.\nCảm phiền suy nghĩ xưa ơn,\nTại vì căn số dạ hờn làm chi.'),(8,'Tử','sanh con nuôi đặng 1 đứa con gái hoặc lo nuôi con nuôi','Luận xem chữ Tử số này,\nKhát hào huynh đệ đổi xây nghĩa tình.\nAnh không đạo nghĩa phân minh,\nEm chẳng nhơn tình chịu nhịn cho an.\nOai hùm làm dữ ngang tàng,\nNgoại nhơn thân thích nghịch hàng đệ huynh.\nSố này không trọn nghĩa tình,\nĐến khi buồn giận chống kình hại nhau.'),(9,'Mộ','sanh con nuôi đặng 1 đứa','Số phần gặp Mộ linh đinh,\nBơ vơ lợt lạt nghĩa tình là đây.\nCha mẹ sanh dưỡng ngõ hầu,\nĐôi ba cốt nhục một bầu hóa sanh.\nMỗi người tánh cũng khôn lành,\nĐều riêng tâm ý cạnh tranh bất hòa.\nMột mình lo tính gần xa,\nĐến xa nên đặng thất gia hưởng nhờ.'),(10,'Tuyệt','sanh con nuôi đặng 1 đứa','Sanh nhằm chữ Tuyệt chẳng may,\nHao huynh tốn đệ khó nài đủ đông.\nDầu mà còn đủ khó trông,\nAnh em tứ xứ khỏi mong phục hồi.\nNằm ngồi dạ nhớ bâng long,\nĐến khi giàn cảnh chớ hòng cậy ai.\nĐến nay mới biết tỏ bày,\nThiên thai số định ngày mai cảm phiền.'),(11,'Thai','sanh con nuôi đặng 1 đứa','Chẳng may gặp vị Thai tinh,\nTrong mình sanh bệnh thân mình đa đoan.\nXiết than huynh đệ không tàn,\nBàn lui tính tới chẳng an một bề.\nChớ hề bàn luận đề huề,\nNói năng tử tế bị chê thêm phiền.\nKiếp trước làm chuyện vô duyên,\nKiếp này trả quả tiền khiên của mình.'),(12,'Dưỡng','sanh con nuôi đặng 3 đứa','Sanh nhằm chữ Dưỡng số này,\nNhững điều hung kiết xem đây tỏ tường.\nTrong nhà anh chị ít thương,\nRa đường trên dưới kính nhường rước đưa.\nBốn phương danh tiếng người ưa,\nCốt nhục không nghĩ bỏ chừa uổng thay.\nMột mình xa các nào hay,\nCác ư kỳ phận ngày nay rõ ràng.');
/*!40000 ALTER TABLE `vongtruongsanh` ENABLE KEYS */;
UNLOCK TABLES;

